-- Poems batch 352
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('da07fb7c-c291-4c6e-b868-5021c009236d','陳丈挽詩','李新','宋','宋诗','song-poetry','','[]','七十飄生世所稀，初休利鎖便忘機。',64,'全唐诗/poet.song.70000.json','["七十飄生世所稀，初休利鎖便忘機。", "清朝有子方干禄，白屋無塵自掩扉。", "高論競推猗頓富，夢魂翻逐楚莊飛。", "素車白馬春郊道，鸞鳯相呼舊穴歸。"]'),
('b5479802-0149-4c14-bce1-077d9bf17997','挽崇寧王雅橋楊公善宣教詞','李新','宋','宋诗','song-poetry','','[]','何必他楊重蜀苖，關西華胄固遙遙。',64,'全唐诗/poet.song.70000.json','["何必他楊重蜀苖，關西華胄固遙遙。", "大成殿老身先倡，貝葉書成血未消。", "金馬祥光開舊地，玉虹寒影臥新橋。", "偉翁有子全忠孝，行看珪璋薦盛朝。"]'),
('05819c42-c563-4692-a846-38909f9ffc25','挽江源張寛儒承事詞','李新','宋','宋诗','song-poetry','','[]','善頌堂下幾生芻，䍧牱墓西千輛車。',64,'全唐诗/poet.song.70000.json','["善頌堂下幾生芻，䍧牱墓西千輛車。", "邑人清淚墮不已，食客行歌悲有餘。", "家法新增小戴禮，生涯半用計然書。", "平生陰德知多少，勢等岷峨報亦徐。"]'),
('220cf98e-20e4-4058-9444-3c936f2c6a6d','挽張承事詞','李新','宋','宋诗','song-poetry','','[]','長吟清嘯蜀江干，一尺霜根向物寒。',64,'全唐诗/poet.song.70000.json','["長吟清嘯蜀江干，一尺霜根向物寒。", "吾道祗知尊孔子，奇書何用學劉安。", "玄談客去虛方丈，碧落雛歸迅羽翰。", "曉月流星無處覓，斷雲空著子陵灘。"]'),
('fb159eb5-805e-4f77-9ac3-2b06963dbe1f','東平縣君挽詞','李新','宋','宋诗','song-poetry','','[]','玉翰飛過碧江東，露泣三荆向曉風。',64,'全唐诗/poet.song.70000.json','["玉翰飛過碧江東，露泣三荆向曉風。", "貝葉塵生昏舊綠，蘋花煙老墮疏紅。", "鳥沉孤影桓山外，蟲返青冥壁水空。", "德範豈惟墳上土，傳家清訓是無窮。"]'),
('514e2d8d-3fdd-4c85-b9c6-9e653bb2ed59','挽史太君詞','李新','宋','宋诗','song-poetry','','[]','吳楚雲帆萬里風，元歌來哭舊江東。',64,'全唐诗/poet.song.70000.json','["吳楚雲帆萬里風，元歌來哭舊江東。", "梁城皓鶴千年恨，蜀壟青松一夢空。", "滏水波聲天地遠，灞陵山色古今同。", "碑陰且刻東坡語，勳烈將收國史中。"]'),
('74ea2798-8333-4c9a-86bd-5b19d9a23e1f','壽安夫人挽詞','李新','宋','宋诗','song-poetry','','[]','閨門秀色擢冰清，行佩蘭苕八十春。',64,'全唐诗/poet.song.70000.json','["閨門秀色擢冰清，行佩蘭苕八十春。", "傳道先生爲擇配，起家著作不憂貧。", "金花貼子分雙軸，子舍登瀛有幾人。", "千仞龍華松竹域，婦姑雖死亦相親。"]'),
('4b2abb56-9b24-47ec-9753-3f2125934c48','榮德夫人挽詞','李新','宋','宋诗','song-poetry','','[]','舊池龜去必巢蓮，龍隧愁看錦水邊。',64,'全唐诗/poet.song.70000.json','["舊池龜去必巢蓮，龍隧愁看錦水邊。", "肯與玉人俱遠宦，自憐王母已高年。", "松窗弦誦親曹叔，秋月家風起鄭玄。", "仙客立朝何所恨，自緣退有可耕田。"]'),
('18b430a3-7cc5-4379-9e16-f0ae6bf1a106','陰伯庸悼詞','李新','宋','宋诗','song-poetry','','[]','妙年詞墨一何工，漢苑家聲戚里雄。',64,'全唐诗/poet.song.70000.json','["妙年詞墨一何工，漢苑家聲戚里雄。", "居避飛塵門似水，客投漫刺袂生風。", "香消絳帳魚難蠧，月照銀杯酒不空。", "陽報豈須窮寶篋，鳯雛行看赤霞中。"]'),
('c23dda8a-069b-483c-8302-8a0b3fa836c8','病中二首  其一','李新','宋','宋诗','song-poetry','','[]','虛名畢竟耳邊風，夢入巢由事一空。',64,'全唐诗/poet.song.70000.json','["虛名畢竟耳邊風，夢入巢由事一空。", "貧窶未能防鬼笑，悲哀端更遇途窮。", "胡沙十月驚弦鴈，水國三年食蓼蟲。", "得似此身無好味，病餘明日即衰翁。"]'),
('7afa4ee6-6c2a-436c-a347-afa4f41b42ad','病中二首  其二','李新','宋','宋诗','song-poetry','','[]','林間風氣杳無蹤，欲遣誰人慰病慵。',64,'全唐诗/poet.song.70000.json','["林間風氣杳無蹤，欲遣誰人慰病慵。", "丐友何顔堪著論，祭拏無泪可沾胸。", "不知心逐搖搖旆，反爲官憐楚楚松。", "最是少眠多念處，暝鴉殘月五更鐘。"]'),
('8664f4b9-b276-489b-81b8-6048425fce03','月下','李新','宋','宋诗','song-poetry','','[]','俗意未能免，高情誰與論。',24,'全唐诗/poet.song.70000.json','["俗意未能免，高情誰與論。", "惟憐今夜月，依舊照衡門。"]'),
('87a4b53e-f9a8-4317-a875-def481f7a4a3','和許表民湔江驛四題  其一','李新','宋','宋诗','song-poetry','','[]','花盡蜂腰痩，風低燕脇涼。',24,'全唐诗/poet.song.70000.json','["花盡蜂腰痩，風低燕脇涼。", "雲衣迷遠岫，烟幕蔽柔桑。"]'),
('21cc70fd-e8cb-454c-8e13-81986831280d','和許表民湔江驛四題  其二','李新','宋','宋诗','song-poetry','','[]','吹來槐莢細，過去杜鵑悲。',24,'全唐诗/poet.song.70000.json','["吹來槐莢細，過去杜鵑悲。", "慣客久無念，送春閒有詩。"]'),
('efb09d40-1641-4dbf-af00-a3d248a026fb','和許表民湔江驛四題  其三','李新','宋','宋诗','song-poetry','','[]','筍成森碧玉，麥熟歛黄雲。',24,'全唐诗/poet.song.70000.json','["筍成森碧玉，麥熟歛黄雲。", "村酒不堪酌，一盃能易醺。"]'),
('bfc8968b-9f63-421e-826a-cd109090834e','和許表民湔江驛四題  其四','李新','宋','宋诗','song-poetry','','[]','柳橋通窈窕，客轡按玲瓏。',24,'全唐诗/poet.song.70000.json','["柳橋通窈窕，客轡按玲瓏。", "蒲劍一谿綠，酒花雙頰紅。"]'),
('53aa86d9-18b5-4f64-b3b6-de24a1d6e771','遊南水陸院  其一','李新','宋','宋诗','song-poetry','','[]','蜀國山河在，梁原草樹深。',24,'全唐诗/poet.song.70000.json','["蜀國山河在，梁原草樹深。", "暮雲千里色，無處不傷心。"]'),
('6d6726a0-9b38-4498-a5d7-23235d95bf74','遊南水陸院  其二','李新','宋','宋诗','song-poetry','','[]','鳴蛙千鼓吹，脩竹萬琅玕。',24,'全唐诗/poet.song.70000.json','["鳴蛙千鼓吹，脩竹萬琅玕。", "日下欲歸去，谿光生晚寒。"]'),
('dee5871d-db62-44ee-a8ff-19b33abbce38','宿西谷院六首  其一','李新','宋','宋诗','song-poetry','','[]','線繞參差路，雲封咫尺山。',24,'全唐诗/poet.song.70000.json','["線繞參差路，雲封咫尺山。", "寺僧初怪客，三日竊優閒。"]'),
('99ceb0ca-b308-4f9c-9970-e5ceb5c6bcb2','宿西谷院六首  其二','李新','宋','宋诗','song-poetry','','[]','野水無窮意，幽花不斷香。',24,'全唐诗/poet.song.70000.json','["野水無窮意，幽花不斷香。", "殘春孤客恨，惟與漢天長。"]'),
('cba063f8-d13d-4091-8ee2-42f06a0e27cf','宿西谷院六首  其三','李新','宋','宋诗','song-poetry','','[]','山翠圍裘領，谿聲響佩環。',24,'全唐诗/poet.song.70000.json','["山翠圍裘領，谿聲響佩環。", "終年無俗客，不用掩松關。"]'),
('a8b5de34-ab70-4327-8b3c-62995eeae080','宿西谷院六首  其四','李新','宋','宋诗','song-poetry','','[]','野鳥休驚起，浮雲莫厭看。',24,'全唐诗/poet.song.70000.json','["野鳥休驚起，浮雲莫厭看。", "松蘿秋後碧，巖谷暑中寒。"]'),
('a7463ebf-c072-4d0b-aacf-f238bc03d343','宿西谷院六首  其五','李新','宋','宋诗','song-poetry','','[]','石髓門前水，松風谷外鐘。',24,'全唐诗/poet.song.70000.json','["石髓門前水，松風谷外鐘。", "遲遲半輪月，未忍出雙峰。"]'),
('0badb223-9146-42d3-922d-1c9203bb6fc2','宿西谷院六首  其六','李新','宋','宋诗','song-poetry','','[]','稍治尋山屐，初裁半隱衣。',24,'全唐诗/poet.song.70000.json','["稍治尋山屐，初裁半隱衣。", "聲聲杜鵑語，猶勸不如歸。"]'),
('8bba2cd0-beff-4081-95a5-ab6cd8fc610c','送菜徐秀才  其一','李新','宋','宋诗','song-poetry','','[]','吏部虀鹽滿腹，先生苜蓿盈盤。',28,'全唐诗/poet.song.70000.json','["吏部虀鹽滿腹，先生苜蓿盈盤。", "珍重尋常癡客，不作膏粱眼看。"]'),
('ac71cb85-39fc-4d89-8d60-ab9473ca667c','送菜徐秀才  其二','李新','宋','宋诗','song-poetry','','[]','食薺已甘予口，送荼聊苦君腸。',28,'全唐诗/poet.song.70000.json','["食薺已甘予口，送荼聊苦君腸。", "見說舐碪無分，借令轑釡何妨。"]'),
('ef962123-aa20-47eb-a91c-b5da4438b8af','送菜徐秀才  其三','李新','宋','宋诗','song-poetry','','[]','黄精末有積雪，晚菘猶帯寒烟。',28,'全唐诗/poet.song.70000.json','["黄精末有積雪，晚菘猶帯寒烟。", "雖辜主父九鼎，不減何郎萬錢。"]'),
('b3972788-6f40-4a28-8156-a8403b043b39','送菜徐秀才  其四','李新','宋','宋诗','song-poetry','','[]','增添庾郎方丈，掇拾儀休棄遺。',28,'全唐诗/poet.song.71000.json','["增添庾郎方丈，掇拾儀休棄遺。", "但令門人學圃，不妨夫子下帷。"]'),
('40dd1e86-861e-4c8c-b792-6c6026cf7bed','秋日登樓  其一','李新','宋','宋诗','song-poetry','','[]','濃掃清陰一壑秋，眼光新困仲宣樓。',32,'全唐诗/poet.song.71000.json','["濃掃清陰一壑秋，眼光新困仲宣樓。", "等閒欲作東山醉，却爲蒼生不破愁。"]'),
('18e7d721-acde-4f84-9ea6-16dd267adec3','秋日登樓  其二','李新','宋','宋诗','song-poetry','','[]','洗遍山光暮雨收，落霞孤鶩點清秋。',32,'全唐诗/poet.song.71000.json','["洗遍山光暮雨收，落霞孤鶩點清秋。", "蜀天地暖知無雁，不怕愁聲稳上樓。"]'),
('c01abc21-3be2-47a6-8182-1e77038190d4','送呂興元  其一','李新','宋','宋诗','song-poetry','','[]','身離梁苑初蠶月，脚蹈秦雲已麥秋。',32,'全唐诗/poet.song.71000.json','["身離梁苑初蠶月，脚蹈秦雲已麥秋。", "要見使君恩惠久，滔滔長伴漢江流。"]'),
('e8f4f06c-9a4c-41c9-9389-9389602b4770','送呂興元  其二','李新','宋','宋诗','song-poetry','','[]','梯天懸閣馬行空，旌旆悠悠照谷紅。',32,'全唐诗/poet.song.71000.json','["梯天懸閣馬行空，旌旆悠悠照谷紅。", "靈鳯陰寒春過晚，萬山猶有牡丹風。"]'),
('78d02d19-9928-4e2c-b4b9-649232fbc4ac','送呂興元  其三','李新','宋','宋诗','song-poetry','','[]','冰壺舊映藍溪玉，璧乘曾依白帝城。',32,'全唐诗/poet.song.71000.json','["冰壺舊映藍溪玉，璧乘曾依白帝城。", "明日武林山下路，過橋唯有杜鵑聲。"]'),
('8a0b48df-aaba-4cde-a4f2-8b657e52299f','送呂興元  其四','李新','宋','宋诗','song-poetry','','[]','太平天子事東封，洛苑回鑾訪侍中。',32,'全唐诗/poet.song.71000.json','["太平天子事東封，洛苑回鑾訪侍中。", "自古相門終出相，試持圭璧近重瞳。"]'),
('eca3f882-4521-4df5-a5e6-f6b32307d48b','送呂興元  其五','李新','宋','宋诗','song-poetry','','[]','霧豹平時豈一班，定將清對領威顔。',32,'全唐诗/poet.song.71000.json','["霧豹平時豈一班，定將清對領威顔。", "東南民病知多少，莫把皇華誤出關。"]'),
('34c2f9d9-74a3-469e-ab9d-e6417d39bace','送呂興元  其六','李新','宋','宋诗','song-poetry','','[]','行入雲衢路未通，主人明日復觀風。',32,'全唐诗/poet.song.71000.json','["行入雲衢路未通，主人明日復觀風。", "幾聲寒鵲江村暮，煙雨瀟瀟失去鴻。"]'),
('9d2017b0-8b11-4136-955f-74ac98bae59f','目擊','李新','宋','宋诗','song-poetry','','[]','懸知九折自成醫，痩骨綿綿尚勝肥。',32,'全唐诗/poet.song.71000.json','["懸知九折自成醫，痩骨綿綿尚勝肥。", "引睡文書滿床榻，病兒猶枕樂天詩。"]'),
('7d5e4203-6e62-4b6e-8ab8-cae50828e070','送程公明  其一','李新','宋','宋诗','song-poetry','','[]','莫倚行臺怯酒醺，一盃父老送慇懃。',32,'全唐诗/poet.song.71000.json','["莫倚行臺怯酒醺，一盃父老送慇懃。", "白雲嶺上雖無數，未敢持來玷使君。"]'),
('0f2bae25-627d-4f72-997b-33fd494d9fce','送程公明  其二','李新','宋','宋诗','song-poetry','','[]','漸横碧落快秋風，回首雲山幾萬重。',32,'全唐诗/poet.song.71000.json','["漸横碧落快秋風，回首雲山幾萬重。", "明夕長亭新夢破，亂鴉殘月五更鐘。"]'),
('516d4166-e1a2-47ee-b926-8a96307e6fa2','送程公明  其三','李新','宋','宋诗','song-poetry','','[]','解頤詩訓憶趨庭，四十專城髮尚青。',32,'全唐诗/poet.song.71000.json','["解頤詩訓憶趨庭，四十專城髮尚青。", "屈指世間無此樂，路行争看老人星。"]'),
('8d9ad47a-ab33-4ac0-8a2d-0af11fe3b439','送程公明  其四','李新','宋','宋诗','song-poetry','','[]','不羈風韻有蕭郎，白傅新詩已滿筐。',32,'全唐诗/poet.song.71000.json','["不羈風韻有蕭郎，白傅新詩已滿筐。", "煙薄露寒雖寫痩，自應清節也凌霜。"]'),
('3b392ca8-6fe7-440a-bd3e-24a6964669ac','送程公明  其五','李新','宋','宋诗','song-poetry','','[]','金闔銅樞喚仗開，越班侍從薦高才。',32,'全唐诗/poet.song.71000.json','["金闔銅樞喚仗開，越班侍從薦高才。", "一鞭野色身何處，芸閣清風待客來。"]'),
('98a70b60-6ea3-4603-801b-0f00530141b7','送程公明  其六','李新','宋','宋诗','song-poetry','','[]','玉鐙驚驦趁早朝，天香成陣暗蟬貂。',32,'全唐诗/poet.song.71000.json','["玉鐙驚驦趁早朝，天香成陣暗蟬貂。", "平雲無復偷閒到，溪闊煙深鎻市橋。"]'),
('c048041e-bd11-46b9-9e56-e83e6cbb825f','送程公明  其七','李新','宋','宋诗','song-poetry','','[]','無限秋容入跨鼇，使君山色兩相高。',32,'全唐诗/poet.song.71000.json','["無限秋容入跨鼇，使君山色兩相高。", "半生笑盡迎逢輩，俯仰隨人效桔橰。"]'),
('580c11ba-ada5-49d6-8834-db1922c2c510','送程公明  其八','李新','宋','宋诗','song-poetry','','[]','自憐痩骨飲冰寒，惆悵相逢下眼看。',32,'全唐诗/poet.song.71000.json','["自憐痩骨飲冰寒，惆悵相逢下眼看。", "閒想顯人應笑我，道傍初試折腰官。"]'),
