('c3a6d755-0614-4a48-b610-7871098f17fa','和李少卿','李新','宋','宋诗','song-poetry','','[]','疏雨輕煙憶故林，一生難愜子由心。',32,'全唐诗/poet.song.71000.json','["疏雨輕煙憶故林，一生難愜子由心。", "未須逕化陂龍去，留作甘棠異日陰。"]'),
('a0bcae14-f333-46ce-895d-5eddfd723d38','程公明駕部墨竹','李新','宋','宋诗','song-poetry','','[]','淺梢疏節任蕭郎，正向祁寒敵曉霜。',32,'全唐诗/poet.song.71000.json','["淺梢疏節任蕭郎，正向祁寒敵曉霜。", "清興未窮僧已老，自遺山色與溪光。"]'),
('9a5f9d4c-d1ed-4e8d-b256-116f625ec73f','自西縣趨南鄭道中雜詠三首  其一','李新','宋','宋诗','song-poetry','','[]','矮陌穹廬青匝地，垂楊步幛綠藏橋。',32,'全唐诗/poet.song.71000.json','["矮陌穹廬青匝地，垂楊步幛綠藏橋。", "無端驚耳西江漲，十里雄聲學海潮。"]'),
('1b59f6e5-ccf0-4507-a7d6-750ae81151c5','自西縣趨南鄭道中雜詠三首  其二','李新','宋','宋诗','song-poetry','','[]','愛山不道妨行色，礙眼仍須徹帽裙。',32,'全唐诗/poet.song.71000.json','["愛山不道妨行色，礙眼仍須徹帽裙。", "願借仙人白鷴尾，自家親掃北山雲。"]'),
('81ee95fa-bf2a-41ae-b765-dccdccc62927','自西縣趨南鄭道中雜詠三首  其三','李新','宋','宋诗','song-poetry','','[]','茂林修竹平夷地，牧馬藏兵戰鬬塲。',32,'全唐诗/poet.song.71000.json','["茂林修竹平夷地，牧馬藏兵戰鬬塲。", "死節不知師李固，溺冠惟解法高皇。"]'),
('ed162b24-313b-49e9-b227-6586320235af','禪房','李新','宋','宋诗','song-poetry','','[]','石竇涓涓函丈冷，海雲疊疊暮山低。',32,'全唐诗/poet.song.71000.json','["石竇涓涓函丈冷，海雲疊疊暮山低。", "秋風早晚驚禪定，肯爲陶潛一過溪。"]'),
('8c1c73ca-3ebe-478a-bd34-4cdac2156be4','題韓溪','李新','宋','宋诗','song-poetry','','[]','雲夢擒王終獵狗，芒碭龍子詎蟠泥。',32,'全唐诗/poet.song.71000.json','["雲夢擒王終獵狗，芒碭龍子詎蟠泥。", "前知婦女磨英氣，亦率蕭公早過溪。"]'),
('6d9ef823-c55d-4d87-b876-eb64a0fb7677','墨竹','李新','宋','宋诗','song-poetry','','[]','葉葉飛秋聲自來，蕭郎國有不羈才。',32,'全唐诗/poet.song.71000.json','["葉葉飛秋聲自來，蕭郎國有不羈才。", "西山昨夜虎風惡，大折一枝無處栽。"]'),
('0e873874-4905-4323-92fb-6df7bf94cac8','題賴盤市法雲院二首  其一','李新','宋','宋诗','song-poetry','','[]','亂石崖邊花蹙錦，鬬雞峰下麥翻雲。',32,'全唐诗/poet.song.71000.json','["亂石崖邊花蹙錦，鬬雞峰下麥翻雲。", "青螺着地山渾翠，丹餅乘天日半曛。"]'),
('66d58a22-70d9-413b-87d6-2850a4e9b742','題賴盤市法雲院二首  其二','李新','宋','宋诗','song-poetry','','[]','石壁冷磨閒日月，松櫺平覺遠山川。',32,'全唐诗/poet.song.71000.json','["石壁冷磨閒日月，松櫺平覺遠山川。", "便將小紐雙龜印，試換禪床一覺眠。"]'),
('917e493c-c9da-4bc2-8756-6642656590a5','用劉子默韻題瘼亭','李新','宋','宋诗','song-poetry','','[]','醉頭兀兀接籬斜，客宦歸來賦白華。',32,'全唐诗/poet.song.71000.json','["醉頭兀兀接籬斜，客宦歸來賦白華。", "小洞方池初着意，坐看梅雨數殘花。"]'),
('a0acd4f9-af68-4608-95a3-7dbbb82fd560','芝溪院','李新','宋','宋诗','song-poetry','','[]','青蓋行春踏雁沙，連山舊燒起新芽。',32,'全唐诗/poet.song.71000.json','["青蓋行春踏雁沙，連山舊燒起新芽。", "馬蹄何處窮餘興，猶有谿山一樹花。"]'),
('ad0cf751-2600-4bab-967f-8dd9a8bd1210','次韻崔同年馬上口占二首  其一','李新','宋','宋诗','song-poetry','','[]','底事安仁易白頭，一鞭行色伴清鷗。',32,'全唐诗/poet.song.71000.json','["底事安仁易白頭，一鞭行色伴清鷗。", "抽身簿領窮清興，唯有江天倒射眸。"]'),
('8cb584fd-fe44-4d1b-b38f-904310698e8c','次韻崔同年馬上口占二首  其二','李新','宋','宋诗','song-poetry','','[]','柳花榆莢半飛空，燕子銜來盡落紅。',32,'全唐诗/poet.song.71000.json','["柳花榆莢半飛空，燕子銜來盡落紅。", "日與長安俱未遠，可能提榼問東風。"]'),
('ea51fb5b-d97b-4b63-b419-7c54c8a16014','白塔院','李新','宋','宋诗','song-poetry','','[]','西風晴野快揚鞭，臨水驦駒惜錦韀。',32,'全唐诗/poet.song.71000.json','["西風晴野快揚鞭，臨水驦駒惜錦韀。", "蕭寺凄涼幾不到，巨楠蒼檜碧參天。"]'),
('f2476e2c-6ef2-4820-816c-cdbf76a78836','龍笛','李新','宋','宋诗','song-poetry','','[]','長天雲掃碧龍鱗，黄鶴樓前白玉輪。',32,'全唐诗/poet.song.71000.json','["長天雲掃碧龍鱗，黄鶴樓前白玉輪。", "秋意正隨羌笛怨，夜深愁殺倚欄人。"]'),
('86c3cd34-8d3e-46c6-9203-dd7a71eca12a','天王院','李新','宋','宋诗','song-poetry','','[]','溪邊竹瘦暮雲昏，愛客頭陀未掩門。',32,'全唐诗/poet.song.71000.json','["溪邊竹瘦暮雲昏，愛客頭陀未掩門。", "問我年來何所事，袖邊朱墨幾多痕。"]'),
('30c5a7b8-5f98-4c88-9776-9d98c143a7d8','戲子常攜妓見訪','李新','宋','宋诗','song-poetry','','[]','紅英渾似識劉郎，迎笑干株夾路傍。',32,'全唐诗/poet.song.71000.json','["紅英渾似識劉郎，迎笑干株夾路傍。", "曙色松窗留不得，斷雲無處覓殘香。"]'),
('d1054f3b-57c2-4d9e-b0ff-2c4aa8c995a7','次韻子温早梅','李新','宋','宋诗','song-poetry','','[]','霜多未葉大孤寒，欲向春前倒樹開。',32,'全唐诗/poet.song.71000.json','["霜多未葉大孤寒，欲向春前倒樹開。", "莫道東風無意在，餘香看即度牆來。"]'),
('9e3ddc99-4824-4f14-84d5-c6f15b85fe02','新春道中口占  其一','李新','宋','宋诗','song-poetry','','[]','幛地翠煙猶惜曉，乳花小雨却翻晴。',32,'全唐诗/poet.song.71000.json','["幛地翠煙猶惜曉，乳花小雨却翻晴。", "去年春恨依前到，先得東風捲入城。"]'),
('97befd2d-5b1e-48f4-8a0c-70f09dfc739b','新春道中口占  其二','李新','宋','宋诗','song-poetry','','[]','挑人柳目空依路，喚客鶯聲又隔林。',32,'全唐诗/poet.song.71000.json','["挑人柳目空依路，喚客鶯聲又隔林。", "病渴相如今已老，悔將春事入琴心。"]'),
('92fc8506-cbfe-4036-bbd8-edc29feb0a91','新春道中口占  其三','李新','宋','宋诗','song-poetry','','[]','老去難禁數别離，一樽春酒爲誰悲。',32,'全唐诗/poet.song.71000.json','["老去難禁數别離，一樽春酒爲誰悲。", "綠楊深院花飛處，秪有東風獨自知。"]'),
('acf2989f-9fae-4997-b8b3-551065fa8a07','新春道中口占  其四','李新','宋','宋诗','song-poetry','','[]','千本春桃行石顔，暖風扶袖入雲端。',32,'全唐诗/poet.song.71000.json','["千本春桃行石顔，暖風扶袖入雲端。", "庾郎食菜今多少，但看行厨白璧盤。"]'),
('128da729-1f19-40dd-b114-548a1a6de101','新春道中口占  其五','李新','宋','宋诗','song-poetry','','[]','白馬蹄輕氣亦驕，嘶風嘶日上山椒。',32,'全唐诗/poet.song.71000.json','["白馬蹄輕氣亦驕，嘶風嘶日上山椒。", "迺翁不似楊光禄，與汝披霜趁早朝。"]'),
('7bb386e6-b139-4d84-8003-31ebed5bf637','新春道中口占  其六','李新','宋','宋诗','song-poetry','','[]','榆莢已吹鵝眼去，柳綿不帯繭香來。',32,'全唐诗/poet.song.71000.json','["榆莢已吹鵝眼去，柳綿不帯繭香來。", "輕霜未度劉郎鬢，更看春桃幾度開。"]'),
('4523ed5c-dc46-467f-a510-8d566bcbdbd6','春閒戲書三首  其一','李新','宋','宋诗','song-poetry','','[]','幾家桃李高低樹，一望江山表裏春。',32,'全唐诗/poet.song.71000.json','["幾家桃李高低樹，一望江山表裏春。", "寂寞無心看花去，懸知自有看花人。"]'),
('f4d8e5fb-e385-4dd6-bdd4-3dfefbb4b390','春閒戲書三首  其二','李新','宋','宋诗','song-poetry','','[]','春天行樂若爲傷，青鬢吹蓬半染霜。',32,'全唐诗/poet.song.71000.json','["春天行樂若爲傷，青鬢吹蓬半染霜。", "莫道一生甘淡薄，十年前亦爲春狂。"]'),
('c3c8ebb8-20c8-4e9f-8837-a8dc25fbb156','春閒戲書三首  其三','李新','宋','宋诗','song-poetry','','[]','老病空懷雲水鄉，涪江春浪接天長。',32,'全唐诗/poet.song.71000.json','["老病空懷雲水鄉，涪江春浪接天長。", "扁舟擬下巫陽去，不聽巴猿已斷腸。"]'),
('ec5bdf42-7fd3-4e48-b337-075820e2859e','高祖試劍石','李新','宋','宋诗','song-poetry','','[]','拔山蓋世何爲者，三尺青龍不切泥。',32,'全唐诗/poet.song.71000.json','["拔山蓋世何爲者，三尺青龍不切泥。", "且向斷崖聊一試，如聞鬼母夜悲啼。"]'),
('7316e528-80a5-4568-9ee1-1a657faafbce','普州鐵山福濟廟祀神曲 迎神','李新','宋','宋诗','song-poetry','','[]','夜郎北兮雲蒼蒼，辛夷落兮木葉黄。',82,'全唐诗/poet.song.71000.json','["夜郎北兮雲蒼蒼，辛夷落兮木葉黄。", "兵佖路兮凱歌闋，渡瀘歸兮馬汗血。", "宅靈安所兮嶺之西，鼓角殷地兮烏夜啼。", "倐而來兮鼓舞迎將，苾芬蘭羞兮泠泠桂漿。", "羅拜兮堂皇，神之樂兮未央。"]'),
('5f3394b8-142b-4412-8901-d8d43cd6bb7c','普州鐵山福濟廟祀神曲 送神','李新','宋','宋诗','song-poetry','','[]','伐鼓兮隆隆，風雨時兮歲豐。',79,'全唐诗/poet.song.71000.json','["伐鼓兮隆隆，風雨時兮歲豐。", "刲羊炰羔兮旨酒清潔，相與答神兮繼日以月。", "肉掩豆兮中禮，盞斝酢兮告終。", "神之福汝兮百室攸同，神歡以留兮塵囂而蒙，靈旂雲馬兮或時返乎離宮。"]'),
('d5a94022-9da7-426c-82e9-71cf118f161f','折楊柳','李新','宋','宋诗','song-poetry','','[]','東風來何時，百花已飄零。',72,'全唐诗/poet.song.71000.json','["東風來何時，百花已飄零。", "獨餘堤上柳，慘淡含春榮。", "扁舟復何適，延客江上亭。", "顧無青玉案，何以送子行。", "攀條欲相贈，上有雙流鶯。", "流鶯正求友，奈此別離情。"]'),
('9eb8ae45-8bd1-4636-8553-331f45e3df6c','登西樓呈桑彥周','李新','宋','宋诗','song-poetry','','[]','獨自行藏莫倚欄，市廛野色不相干。',64,'全唐诗/poet.song.71000.json','["獨自行藏莫倚欄，市廛野色不相干。", "是中門戶也羅雀，何處身心更夢棺。", "錦水背人朝暮去，雪山隨我久長寒。", "一生著作驚磨滅，欲借君家鐵硯看。"]'),
('b842e9aa-552b-4249-b120-a4001526b501','立春前密雪應祈呈范內翰','李新','宋','宋诗','song-poetry','','[]','六出飛霙歲或愆，喜觀瓊礫曉滂然。',64,'全唐诗/poet.song.71000.json','["六出飛霙歲或愆，喜觀瓊礫曉滂然。", "水官休隸一時慘，木帝已誇羣物妍。", "斗換石田皆沃壞，暗催雲稼入豐年。", "吾君誠禱通旻昊，願聽氓謠被管絃。"]'),
('705ddc91-ad94-4c11-b5d6-21a5292ebcea','九日無菊','李新','宋','宋诗','song-poetry','','[]','芳物及時難，良辰曠野歡。',48,'全唐诗/poet.song.71000.json','["芳物及時難，良辰曠野歡。", "古園荒草莽，秋雨禿闌干。", "香桂風流減，紅萸氣味單。", "書紳懲淡飲，活取宿根寒。"]'),
('6face638-0691-441b-8e55-aa5acf830ff2','重陽後有作','李新','宋','宋诗','song-poetry','','[]','白酒賢人趣，黄花道貌粧。',48,'全唐诗/poet.song.71000.json','["白酒賢人趣，黄花道貌粧。", "物情殊未厭，時節不加長。", "自是良辰往，何妨後會張。", "試看人化鬼，不異露爲霜。"]'),
('6c5ed356-598e-4002-b725-907cbf356b7c','重陽已後折菊泛酒','李新','宋','宋诗','song-poetry','','[]','芳樽畢獻酬，世態等閑休。',48,'全唐诗/poet.song.71000.json','["芳樽畢獻酬，世態等閑休。", "金蕊香猶在，騷人意重留。", "泛觴詩老座，作古飲家流。", "從此重陽後，殷勤送暮秋。"]'),
('4a6c0683-7761-4abc-a19c-7bc3d950f0cf','閨重陽','李新','宋','宋诗','song-poetry','','[]','鳳曆推移二十霜，一回重見閏重陽。',64,'全唐诗/poet.song.71000.json','["鳳曆推移二十霜，一回重見閏重陽。", "糯田收早醪將熟，朔氣來時菊整香。", "綠鬢不堪禁晚景，醉盃聊可浣愁腸。", "幽人百萬揚州鶴，鼎足成歡未易當。"]'),
('4aa9050e-0837-4a77-8b3c-153f261d47f1','次韻重陽二首  其一','李新','宋','宋诗','song-poetry','','[]','蜂愁節去已焉哉，賓友追稱上宴臺。',64,'全唐诗/poet.song.71000.json','["蜂愁節去已焉哉，賓友追稱上宴臺。", "詩韻此時傳我和，酒樽當日爲誰開。", "光陰碌碌駒奔過，氣候新新轂轉來。", "身赴令辰如舞袖，急忙須趁管絃催。"]'),
('136537a3-7f0d-4e4b-82f4-f7d347968817','次韻重陽二首  其二','李新','宋','宋诗','song-poetry','','[]','故事登高會，流風落帽文。',48,'全唐诗/poet.song.71000.json','["故事登高會，流風落帽文。", "客樽常滿滿，籬菊任紛紛。", "馬埒攄豪氣，萸囊想舊聞。", "不須蘭作佩，騷客恨如雲。"]'),
('a8176850-e25e-4fc5-96e9-5cce7c66fd71','又三絕戲老友  其一','李新','宋','宋诗','song-poetry','','[]','二十年中一度逢，百年能見幾回重。',32,'全唐诗/poet.song.71000.json','["二十年中一度逢，百年能見幾回重。", "幽人樂事無由併，且醉良辰瑪瑙鍾。"]'),
('650c4260-da16-43ac-b8be-a64bdce6937c','又三絕戲老友  其二','李新','宋','宋诗','song-poetry','','[]','西風學得不風流，每怪衰逢末伏秋。',32,'全唐诗/poet.song.71000.json','["西風學得不風流，每怪衰逢末伏秋。", "一陣清風吹醉帽，故教人見老人頭。"]'),
('aac1f40f-1f5e-4cde-87ac-e3762c8c41c6','又三絕戲老友  其三','李新','宋','宋诗','song-poetry','','[]','摘盡霜髭禿蝟髯，年來地閣不任尖。',32,'全唐诗/poet.song.71000.json','["摘盡霜髭禿蝟髯，年來地閣不任尖。", "芙蓉爲惜斑斑鬢，着力風前壓帽簷。"]'),
('c581aed5-0eb3-4fe6-8ff6-df50ba6cc00c','重陽醖未熟無菊絕句','李新','宋','宋诗','song-poetry','','[]','露寒黄菊怯芬芳，入甕新醅未可嘗。',32,'全唐诗/poet.song.71000.json','["露寒黄菊怯芬芳，入甕新醅未可嘗。", "痛飲不須撞令節，花開酒熟是重陽。"]'),
('823bb52c-1dd4-4e8f-ad60-607675b188e5','重陽舟次高郵','李新','宋','宋诗','song-poetry','','[]','途遠舟程未到家，此身誰念客天涯。',64,'全唐诗/poet.song.71000.json','["途遠舟程未到家，此身誰念客天涯。", "東籬乍破黄金蕊，舊鬢新添白雲牙。", "蓴美不須添醤豉，蟹肥無復羨魚蝦。", "白衣送酒知何在，疏放終難學孟嘉。"]'),
('ed6a4b38-c59f-4034-95b9-6ac3a2a784b8','重陽','李新','宋','宋诗','song-poetry','','[]','簟篷辭勞始乞身，夾衣溫麗燕私辰。',64,'全唐诗/poet.song.71000.json','["簟篷辭勞始乞身，夾衣溫麗燕私辰。", "秋客刮黛披天姣，秫米長腰潄螘囷。", "黄菊明朝爲長菊，江山今日笑醒人。", "不煩孫盛貽嘲弄，預對西風脫醉巾。"]'),
('d448970e-54a5-4c1f-bcb2-8b2f3bdda71f','九日羅江旅情呈文孺','李新','宋','宋诗','song-poetry','','[]','山程十驛策駑來，中路幾成興盡回。',64,'全唐诗/poet.song.71000.json','["山程十驛策駑來，中路幾成興盡回。", "旅次白醪饒客醉，故園黄菊爲誰開。", "漏長更箭遲翻鼓，生久燈花細落煤。", "不是學無經濟術，道書教我壯心灰。"]'),
('0e4b7c5d-2151-4b73-b5aa-473f0bfcf32b','重陽近有作','李新','宋','宋诗','song-poetry','','[]','短晷西風冷，殘秋令節頻。',48,'全唐诗/poet.song.71000.json','["短晷西風冷，殘秋令節頻。", "菊花無幾日，竹葉勸何人。", "飽稻黄雞矮，拋房紫栗新。", "時來持此備，未覺野夫貧。"]'),
('9b41ffd7-d33e-4d20-b649-3fa8229e6503','冬至夜宿顒口市','李新','宋','宋诗','song-poetry','','[]','寧辭舉棹頻，不覺又黄昏。',48,'全唐诗/poet.song.71000.json','["寧辭舉棹頻，不覺又黄昏。", "有感逢冬節，無窮宿水村。", "客心愁待旦，盃酒強開樽。", "共祝同歡慶，亨途莫我論。"]'),
('1e619706-bcb3-4e27-883e-52a85c429810','半方壺詩','李新','宋','宋诗','song-poetry','','[]','讘人未得老三山，半作方壺憶夜壇。',64,'全唐诗/poet.song.71000.json','["讘人未得老三山，半作方壺憶夜壇。", "鶴本令威來漢表，鳳翔蕭史下瓊欄。", "到門佳客雙鳬落，入座清風六月寒。", "破竈黄金已無數，定知雲翼說燒丹。"]'),
('039529de-d487-4c66-b658-13014e6c8317','和李少卿游北湖六首  其一','李新','宋','宋诗','song-poetry','','[]','真有鬼謠藏古錦，曷須塵閥眩鳥衣。',32,'全唐诗/poet.song.71000.json','["真有鬼謠藏古錦，曷須塵閥眩鳥衣。", "但看湖上波光裏，不欠當年小院歸。"]'),
('24e21961-a0fc-4c03-adef-dfd14d458337','和李少卿游北湖六首  其二','李新','宋','宋诗','song-poetry','','[]','碧搖虹影橋橫水，翠漏林光日薄山。',32,'全唐诗/poet.song.71000.json','["碧搖虹影橋橫水，翠漏林光日薄山。", "本絕機心成野步，卻驚鷗鷺不知還。"]'),
('c6533369-aaf1-4a99-a8f1-ea214038189e','和李少卿游北湖六首  其三','李新','宋','宋诗','song-poetry','','[]','東山歌扇圓荷動，北海瓊酥竹葉開。',32,'全唐诗/poet.song.71000.json','["東山歌扇圓荷動，北海瓊酥竹葉開。", "笑擘輕紅堆玉碗，衝塵亦有荔枝來。"]'),
('af31c826-d039-4aaf-839d-91bddccd8dd2','和李少卿游北湖六首  其四','李新','宋','宋诗','song-poetry','','[]','芙蕖照水晚粧明，綵鷁無風自在行。',32,'全唐诗/poet.song.71000.json','["芙蕖照水晚粧明，綵鷁無風自在行。", "爭席要人相爾汝，新來翻爲玉漿驚。"]'),
('43bbda6f-592c-4b44-9d61-733ba6a7a51a','和李少卿游北湖六首  其五','李新','宋','宋诗','song-poetry','','[]','紋楸圓玉鬬清堅，陣馬雲屯絕復連。',32,'全唐诗/poet.song.71000.json','["紋楸圓玉鬬清堅，陣馬雲屯絕復連。", "坐據胡床消永日，此身今逐地行仙。"]'),
('dbbb032a-88e2-498d-997b-f142c9a0a5a4','和李少卿游北湖六首  其六','李新','宋','宋诗','song-poetry','','[]','麤疏犢鼻卻閑身，莫道吾家北院貧。',32,'全唐诗/poet.song.71000.json','["麤疏犢鼻卻閑身，莫道吾家北院貧。", "自是江湖釣竿手，不妨煙水卻知人。"]'),
('113594df-11ea-4f7c-b23d-addb88ef8a89','漢源館','李新','宋','宋诗','song-poetry','','[]','消熱層冰遠，投涼嘉樹稀。',48,'全唐诗/poet.song.71000.json','["消熱層冰遠，投涼嘉樹稀。", "雨晴瀟灑去，夢與泬寥歸。", "禽靜谷無語，雲生山有衣。", "路行知水好，終不療長饑。"]'),
('38226d1e-73a9-457c-9a64-d503f6fbb318','一曉發射洪循江而行書二詩州堆館  其一','李新','宋','宋诗','song-poetry','','[]','少健有力入雲耕，耕雲不怕山重重。',64,'全唐诗/poet.song.71000.json','["少健有力入雲耕，耕雲不怕山重重。", "歲時伏臘追社集，照水自愛雙頰紅。", "三十餘年廢田舍，芋魁豆飯忘迺翁。", "誓歸復講舊生計，無謂我不如老農。"]'),
('605685b8-348d-4bb6-9064-19dfaae1a391','一曉發射洪循江而行書二詩州堆館  其二','李新','宋','宋诗','song-poetry','','[]','翠麥鋪茸不罅土，白白紅紅花日許。',64,'全唐诗/poet.song.71000.json','["翠麥鋪茸不罅土，白白紅紅花日許。", "我行未盡天之涯，馬足輿肩已辛苦。", "時名入手無一掬，昔年虎章今化鼠。", "疾歸灌畦蔬換肉，無謂我不如老圃。"]'),
('269cd81c-f488-410c-af6c-7eccf0752494','句  其一','李新','宋','宋诗','song-poetry','','[]','在昔岷峨神，龍文而馬首。',12,'全唐诗/poet.song.71000.json','["在昔岷峨神，龍文而馬首。"]'),
('3e9ef519-a6aa-4db4-808e-b5e295bdbc88','句  其二','李新','宋','宋诗','song-poetry','','[]','雲迷夏禹從前宅，雪壓姜維最後城。',16,'全唐诗/poet.song.71000.json','["雲迷夏禹從前宅，雪壓姜維最後城。"]'),
('f2b5c2f6-618c-4af2-8d52-997b2df6e664','句  其三','李新','宋','宋诗','song-poetry','','[]','山外浮雲雲外城，江邊羌角水中聲。',16,'全唐诗/poet.song.71000.json','["山外浮雲雲外城，江邊羌角水中聲。"]'),
('0a92f66f-f5f8-4f82-9685-98c300d92b0c','句  其四','李新','宋','宋诗','song-poetry','','[]','誰道圖書府，不通氈罽鄉。',12,'全唐诗/poet.song.71000.json','["誰道圖書府，不通氈罽鄉。"]'),
('35878df5-4eca-48ed-a60f-08fbc0e27353','句','張覺民','宋','宋诗','song-poetry','','[]','風威带雪連秦樹，山勢將寒入蜀門。',16,'全唐诗/poet.song.71000.json','["風威带雪連秦樹，山勢將寒入蜀門。"]'),
('42f64835-9463-4b9b-ac28-8d16702c1e10','挽張叔夜二首  其一','張孝純','宋','宋诗','song-poetry','','[]','疇昔中朝士，簪紳仰令名。',48,'全唐诗/poet.song.71000.json','["疇昔中朝士，簪紳仰令名。", "恩威彰輔郡，忠孝衛都城。", "許國志何壯，爲山功莫成。", "西風故林道，蕭瑟感秋聲。"]'),
('85c75364-b354-4fb5-a52a-1847f9d76c79','挽張叔夜二首  其二','張孝純','宋','宋诗','song-poetry','','[]','季世遭奇禍，煩冤痛可論。',48,'全唐诗/poet.song.71000.json','["季世遭奇禍，煩冤痛可論。", "交情傷死別，親屬慟遺言。", "空想還家夢，難招去國魂。", "一朝成萬古，斜日下平原。"]'),
('49a99f0c-5b52-4a5b-923b-383582f0a37b','中運使寄酒清明日到以詩謝之','張孝純','宋','宋诗','song-poetry','','[]','芳樽到日恰清明，似與嘉辰默計程。',64,'全唐诗/poet.song.71000.json','["芳樽到日恰清明，似與嘉辰默計程。", "擬助林園延勝賞，肯容桃李落繁英。", "老來官爵渾無味，閑裏杯盤卻有情。", "見說使車臨岱麓，倘能相過共飛觥。"]'),
('5c2d6ea8-713d-4ddd-8660-e250aa1c3320','詩一首','高荷','宋','宋诗','song-poetry','','[]','妄作非吾事，罷官饑爾曹。',48,'全唐诗/poet.song.71000.json','["妄作非吾事，罷官饑爾曹。", "此心常去住，何日遂孤高。", "雁伴烏瘡脫，蠅營狗跛勞。", "不如張仲蔚，門外長蓬蒿。"]'),
('4f494cfd-9ce7-4775-8d38-5e156d9b8664','上黄太史','高荷','宋','宋诗','song-poetry','','[]','萬里南溪郡，黄香得賜環。',288,'全唐诗/poet.song.71000.json','["萬里南溪郡，黄香得賜環。", "盛名喧海內，摧翮返雲間。", "太史資誠峻，郎官選亦慳。", "朝廷才特起，堂奧援誰扳。", "一夢追前事，羣公厄後艱。", "中傷皆死禍，放逐罕生還。", "別駕之戎僰，僑居傍草菅。", "想知諳鳥道，聞說異人寰。", "楊子家元窘，王維室久鰥。", "鵩來心破碎，猨叫淚湲潺。", "達觀終難得，羈愁必易刪。", "衆情相惻憫，靈物自恬憪。", "迥閣澄秋晚，幽窗聳夜跧。", "蜀天何處盡，巴月幾回彎。", "墜履魂空斷，遺弓涕忽潸。", "石門凄殿楯，銅雀慘宮鬟。", "帝統聯仁聖，皇恩感艷頑。", "網羅疏黨禁，誅蔓掃朋姦。", "點檢金閨彥，凋零玉筍班。", "尚令宗廟器，遙隔鬼門關。", "拊髀咨詢及，含香誥命頒。", "笑談趨赤縣，吟詠落烏蠻。", "奏記懷東觀，移文頷北山。", "應將九遷待，未補七年閑。"]'),
('ccf56d2f-17e9-472e-9af7-27df639f6469','國香','高荷','宋','宋诗','song-poetry','','[]','南溪太史還朝晚，息駕江陵頗從款。',256,'全唐诗/poet.song.71000.json','["南溪太史還朝晚，息駕江陵頗從款。", "綵毫曾詠水仙花，可惜國香天不管。", "將花託意爲羅敷，十七未有十五餘。", "宋玉門牆紆貴從，藍橋庭戶怪貧居。", "十年目色遙成處，公更不來天上去。", "已嫁鄰姬窈窕姿，空傳墨客殷勤句。", "聞道離鸞別鶴悲，藁碪無賴鬻蛾眉。", "桃花結子風吹後，巫峽行雲夢足時。", "田郎好事知渠久，酬贈明珠同石友。", "憔悴猶疑洛浦妃，風流固可章臺柳。", "寶髻犀梳金鳳翹，尊前初識董嬌饒。", "來遲杜牧應須恨，愁殺蘇州也合銷。", "卻把水仙花說似，猛省西家黄學士。", "乃能知妾妾當時，悔不書空作黄字。", "王子初聞話此祥，索詩裁與漫凄涼。", "只今驅豆無方法，徒使田郎號國香。"]'),
('8af9e730-0f76-4526-a4b2-17a138bea1c4','和山谷題李亮功家周昉畫美人琴阮圖','高荷','宋','宋诗','song-poetry','','[]','丹青有神藝，周郎獨能兼。',48,'全唐诗/poet.song.71000.json','["丹青有神藝，周郎獨能兼。", "圖畫絕世人，真態不可添。", "卻憐如畫者，相與落誰手。", "想像猶可言，雨重煙籠柳。"]'),
('2b8599f2-e53f-4e47-968a-90447cb745fa','詩一首','高荷','宋','宋诗','song-poetry','','[]','浪頭送過皇天蕩，夕陽引到烏衣巷。',64,'全唐诗/poet.song.71000.json','["浪頭送過皇天蕩，夕陽引到烏衣巷。", "惡風退作六鷁飛，清秋不成一鶚上。", "故人情親在千里，萬金不如一番紙。", "望斷雲邊鴻影稀，似聽枝間鵲聲喜。"]'),
('21bfcc62-b4fc-40ba-8b82-a4e55a999df5','答山谷先生','高荷','宋','宋诗','song-poetry','','[]','四篇詩得褭蹄金，妙旨初臨法語尋。',64,'全唐诗/poet.song.71000.json','["四篇詩得褭蹄金，妙旨初臨法語尋。", "要我盡除兒子氣，知公全用老婆心。", "平章許事真難可，付囑斯文豈易任。", "感激面東垂涕泗，高山從此少知音。"]'),
('65fdb54d-c9d7-4916-8865-357182684098','蠟梅','高荷','宋','宋诗','song-poetry','','[]','少鎔蠟淚裝應似，多爇龍涎臭不如。',32,'全唐诗/poet.song.71000.json','["少鎔蠟淚裝應似，多爇龍涎臭不如。", "只恐春風有機事，夜來開破幾丸書。"]'),
('ab8eea73-f108-448a-bf94-e4c9108bf008','句  其一','高荷','宋','宋诗','song-poetry','','[]','所喜江陵得真處，沮漳依舊兩川橫。',16,'全唐诗/poet.song.71000.json','["所喜江陵得真處，沮漳依舊兩川橫。"]'),
('c176f7a1-f663-4856-a842-8b4ad4482504','句  其二','高荷','宋','宋诗','song-poetry','','[]','親祠堂主鸞曾駐，善夢先生蝶不歸。',16,'全唐诗/poet.song.71000.json','["親祠堂主鸞曾駐，善夢先生蝶不歸。"]'),
('f16dec85-5d70-45ae-a8c6-a5984fdaf1b2','句  其三','高荷','宋','宋诗','song-poetry','','[]','沙軟綠頭相並鴨，水深紅尾自跳魚。',16,'全唐诗/poet.song.71000.json','["沙軟綠頭相並鴨，水深紅尾自跳魚。"]'),
('dddb8f06-a209-4f16-9756-88566f0aa19d','句  其四','高荷','宋','宋诗','song-poetry','','[]','威強九鼎懼，喪亂一臺成。',12,'全唐诗/poet.song.71000.json','["威強九鼎懼，喪亂一臺成。"]'),
('0e8f063c-d9d3-4740-960e-c887b2f832ef','句  其五','高荷','宋','宋诗','song-poetry','','[]','勃興連穀雨，閏位次花王。',12,'全唐诗/poet.song.71000.json','["勃興連穀雨，閏位次花王。"]'),
('5ecc410d-46c3-4242-b69e-32ee32615221','句  其六','高荷','宋','宋诗','song-poetry','','[]','佳人鬬草百，稚子擊毬雙。',12,'全唐诗/poet.song.71000.json','["佳人鬬草百，稚子擊毬雙。"]'),
('5cb87208-30fe-4745-90c2-6b36f8a02f8b','句  其七','高荷','宋','宋诗','song-poetry','','[]','辨雖豪白馬，讒亦困青蠅。',12,'全唐诗/poet.song.71000.json','["辨雖豪白馬，讒亦困青蠅。"]'),
('52559533-5cf9-45e3-94b3-cfd3209d991d','初行山','晁詠之','宋','宋诗','song-poetry','','[]','靄靄初蒸雲，落落欲墜石。',132,'全唐诗/poet.song.71000.json','["靄靄初蒸雲，落落欲墜石。", "山深多晚花，照水自紅碧。", "漁艇入煙小，松竹凌煙直。", "西風漾碧波，扁舟恣崎側。", "客從北方來，苦遭世俗迫。", "登臨雖夙願，山川多未識。", "浩蕩涉寒流，躋攀並蒼壁。", "捫蘿窺發道，踏逕窮人迹。", "清泉洗塵心，山鳥慣幽客。", "逸興良未已，日下千崖赤。", "十載孫承公，好具登山屐。"]'),
('5e265887-e2c0-4e01-9188-e4f6cca032e2','見降羌感事','晁詠之','宋','宋诗','song-poetry','','[]','沙場尺箠致羌渾，玉陛朝趨雨露恩。',32,'全唐诗/poet.song.71000.json','["沙場尺箠致羌渾，玉陛朝趨雨露恩。", "自笑百年家鳳闕，一生腸斷國西門。"]'),
('06288a5d-22e2-418e-a6e6-7fb93b902aa6','壽星寺','晁詠之','宋','宋诗','song-poetry','','[]','石磴插青雲，禪宮入渺冥。',48,'全唐诗/poet.song.71000.json','["石磴插青雲，禪宮入渺冥。", "歸雲侵客座，流水亂松聲。", "天近月逾白，竹多山更青。", "從來丘壑志，不獨付孫登。"]'),
('681eeea9-b20b-4b6a-aae8-2007d2c1deeb','杭州思歸','晁詠之','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','丘壑情無盡，田園興有餘。',48,'全唐诗/poet.song.71000.json','["丘壑情無盡，田園興有餘。", "何當厭澤國，不奈憶君廬。", "庭戶草應長，江山木已疏。", "何時整歸棹，八月洞庭湖。"]'),
('ad6c73b4-f33e-4813-b792-381a9bde17e4','木香花','晁詠之','宋','宋诗','song-poetry','','[]','朱簾高檻俯幽芳，露浥煙霏玉褪粧。',64,'全唐诗/poet.song.71000.json','["朱簾高檻俯幽芳，露浥煙霏玉褪粧。", "月冷素娥偏有態，夜寒青女不禁香。", "從教春事年年晚，要使詩人日日狂。", "替取秋蘭紉佩好，忍隨風雨受凄涼。"]'),
('cd5e141b-f4bd-4287-98ac-f865bb064bb7','戲葛試官','晁詠之','宋','宋诗','song-poetry','','[]','沒興主司逢葛八，賢弟被黜兄薦發。',32,'全唐诗/poet.song.71000.json','["沒興主司逢葛八，賢弟被黜兄薦發。", "細思堪惜又堪嫌，一壁有眼半壁瞎。"]'),
('0dd57bb3-6680-4469-b41f-24f0afb718c5','題韋偃雙松老僧圖','晁詠之','宋','宋诗','song-poetry','','[]','兩松鬰蒼蒼，夭矯發奇峭。',60,'全唐诗/poet.song.71000.json','["兩松鬰蒼蒼，夭矯發奇峭。", "翛然龍蛇姿，勢欲排巖嶠。", "老禪猶會心，默坐觀萬竅。", "我亦發深省，倚檻一長嘯。", "此興含千古，孰謂韋偃少。"]'),
('ddce6e21-13ec-474c-9967-ff69acfc69f6','句  其一','晁詠之','宋','宋诗','song-poetry','','[]','當時雞犬皆霄漢，自是劉郎不得仙。',16,'全唐诗/poet.song.71000.json','["當時雞犬皆霄漢，自是劉郎不得仙。"]'),
('b42efde4-31e0-4b2e-9cba-d33e669fb04a','句  其二','晁詠之','宋','宋诗','song-poetry','','[]','傷心有恨關存歿，袖手無人問姓名。',16,'全唐诗/poet.song.71000.json','["傷心有恨關存歿，袖手無人問姓名。"]'),
('b2f14650-cc4a-4ca9-85a3-518963ed7aab','句  其三','晁詠之','宋','宋诗','song-poetry','','[]','旌旗太一三山外，車馬長楊五柞中。',32,'全唐诗/poet.song.71000.json','["旌旗太一三山外，車馬長楊五柞中。", "柳外雕鞍公子醉，水邊紈扇麗人行。"]'),
('8bd7945d-ddc2-4fe7-a768-54e902fcc38b','句  其四','晁詠之','宋','宋诗','song-poetry','','[]','喚得梅蕊要同韻，羞殺梨花不解香。',16,'全唐诗/poet.song.71000.json','["喚得梅蕊要同韻，羞殺梨花不解香。"]'),
('aef6044e-e521-48c2-85dc-40452cf64244','德清宰俞居安自畫淵明圖','王當','宋','宋诗','song-poetry','','[]','門無車馬喧，逕有松菊陰。',168,'全唐诗/poet.song.71000.json','["門無車馬喧，逕有松菊陰。", "前窗面清泚，後戶依嶔岑。", "就使世俗工，猶足寫幽深。", "況今令尹賢，洞照先哲心。", "出處異軌轍，丘壑同胸襟。", "予知淡筆墨，良似無弦琴。", "先生如明月，瑩潔照古今。", "形模或能寫，光彩詎可臨。", "寥寥千古意，當向筆下尋。", "人心去典午，朝柄歸卯金。", "豈無康濟心，且賦歸來吟。", "天生卓犖姿，豈是甘山林。", "當今急英賢，四海待商霖。", "勉哉就功名，枯槁不足欽。"]'),
('69cdd402-531a-4e78-8568-c93cc5f00a3b','表兄丁行之俾予作山水一軸','王當','宋','宋诗','song-poetry','','[]','禿髪管城書不中，麝煤滿硯隨輕濃。',155,'全唐诗/poet.song.71000.json','["禿髪管城書不中，麝煤滿硯隨輕濃。", "煙雲變怪本無定，丹青故匪能形容。", "解衣盤礴無人久，妙迹於今復何有。", "揮毫要使真宰泣，嘆息初非癡絕手。", "遼東有人丁令威，去家得仙人暫歸。", "上界繁做異丘壑，安得長林大麓長追隨。", "聯翩大軸要予寫，敲冰不在鵝溪下。", "吾既不能爲喬松直幹摩蒼天，又不能爲小童一線飛紙鳶。", "萬里江山入平遠，喚取畫師閻立本。"]'),
('fb47c7c5-a3d3-4fb0-b164-de7ca342d8ef','江侯邀予作山水書以贈之','王當','宋','宋诗','song-poetry','','[]','江侯樂山水，誓卜山水居。',180,'全唐诗/poet.song.71000.json','["江侯樂山水，誓卜山水居。", "遊戲天目道，箬帽跨蹇驢。", "村童習識之，拍手笑且呼。", "行行不知顧，心與山水俱。", "于茲且幾年，所得應有餘。", "云胡不知厭，要予寫諸圖。", "昔者少壯日，戲墨謾妻奴。", "今衰眼目暗，筆硯久已疏。", "書來不得謝，督迫疇敢徐。", "圖成不自識，濃談恣所如。", "雲深霧莫測，中恐藏於菟。", "人生孰非幻，作觀隨有無。", "江侯樂山水，何考其真歟。", "作詩調江侯，江侯其曉諸。", "觀畢勿遽棄，醤瓿尚可糊。"]'),
('c0a26e54-549d-4886-96be-5308b6633aec','何源秀才爲予畫山水圖覓詩','王當','宋','宋诗','song-poetry','','[]','孤峰特立何巉巉，勢與霄漢高兩參。',224,'全唐诗/poet.song.71000.json','["孤峰特立何巉巉，勢與霄漢高兩參。", "左蟠右列分嶺岫，儼若至尊朝子男。", "怪予蝸室不盈丈，欲有異境超塵凡。", "素縑掛壁故妥帖，平地作此千嵌巖。", "雲蒸霧結深莫測，長林大麓亂不芟。", "想當變怪蟄龍虎，中有窟穴誰能探。", "將崩未崩江動石，欲去不去風滿帆。", "山坳林闕見天際，隱約萬里橫煙嵐。", "嗟予質性素山野，視此丘壑心益耽。", "斗升之粟真秣莝，野馬垂耳就轡銜。", "西山爽氣日在望，吏卒侍側嚴若監。", "青鞋布襪棄不著，誰令自苦披青衫。", "頗羞漁父駐短櫂，似笑大夫新被讒。", "寄言鳥獸倘可侶，吾將從汝棲林巒。"]'),
('6fa4c154-f242-45f0-9612-cc303da52580','戲畫古松真清齋前','王當','宋','宋诗','song-poetry','','[]','輪囷復離奇，不柏亦不栗。',216,'全唐诗/poet.song.71000.json','["輪囷復離奇，不柏亦不栗。", "吾廬非夏社，嘉樹伊誰植。", "刳心謝吹噓，強骨餘霹靂。", "崢嶸歷風霜，偃蹇豈朝夕。", "客從何方來，一睹心眼惑。", "怪此蒼蛟龍，落莫依屋壁。", "不知造物工，輸寫入筆力。", "輕明絕纖埃，冥晦滴濃黑。", "皮堅皵鱗甲，葉老攢予戟。", "古工予不師，揮掃恣淋瀝。", "盤礴醉且狂，詎識韋與畢。", "雖云不造極，要自出胸臆。", "當知後凋操，不在翰墨跡。", "地瘠山骨出，天低雲氣逼。", "俯仰輒有礙，巨幹那能直。", "翻令棟梁姿，鬰屈自跼蹐。", "安得少陵絹，一掃二千尺。", "會看十八公，高壓三品石。"]'),
('3cc66050-bf77-489d-857d-d426191272f2','戲畫松柏壁','王當','宋','宋诗','song-poetry','','[]','窮山數家聚，官況羈若旅。',169,'全唐诗/poet.song.71000.json','["窮山數家聚，官況羈若旅。", "冰廳晝日永，眇眇誰與語。", "眷彼蒼髯生，結友得新甫。", "奮筆寫瑰姿，雙虬見牆堵。", "飽霜柯葉老，積日皮骨枯。", "上有雲垂天，慘淡閣寒雨。", "下有溪潄石，牽牛確絕埃土。", "材奇生長艱，根瘦卓立苦。", "交柯寒相依，雷陳共然許。", "分幹或相避，廉藺馴兩虎。", "信非同根生，要是歲寒侶。", "衆木猥連林，噲等何足伍。", "君看桃與李，穠麗相媚嫵。", "情態能幾時，紛紛可堪數。"]'),
('cabcd031-c436-47c1-8d7d-059c762a4b27','贈田端彥','歐陽獻','宋','宋诗','song-poetry','','[]','守節固窮匪易事，鐵中誰許鬬錚錚。',64,'全唐诗/poet.song.71000.json','["守節固窮匪易事，鐵中誰許鬬錚錚。", "聞道新除右僕射，難留高臥老先生。", "能令餘黨留殘息，必有昌言佐盛明。", "我欲效顰嗟老矣，西風回首涕縱橫。"]'),
('03b9d96f-418b-4df8-a81e-3c22bc6cab1f','答田端彥','歐陽獻','宋','宋诗','song-poetry','','[]','莫嗟騏驥老，不識雲臺仗。',24,'全唐诗/poet.song.71000.json','["莫嗟騏驥老，不識雲臺仗。", "此驥天所月，未易論得喪。"]'),
('e10635c0-77c7-4160-b17a-dd86a6045895','題釣臺','徐大正','宋','宋诗','song-poetry','','[]','光武初從血戰回，故人長短尚論材。',32,'全唐诗/poet.song.71000.json','["光武初從血戰回，故人長短尚論材。", "中霄若起唐虞興，未必先生戀釣臺。"]'),
('ce92db01-f536-4460-a8f4-ca9d263dc465','和林東喬東禪院','李存賢','宋','宋诗','song-poetry','','[]','野雲閑带雨，林木靜無風。',24,'全唐诗/poet.song.71000.json','["野雲閑带雨，林木靜無風。", "村落一溪外，民田四望中。"]'),
('4a40ab76-a72d-40bb-9425-c59e7d44bb86','留題靈巖古詩十韻','冤亭卞','宋','宋诗','song-poetry','','[]','屈指數四絕，四絕中最優。',120,'全唐诗/poet.song.71000.json','["屈指數四絕，四絕中最優。", "此景冠天下，不獨奇東州。", "夜月透巖白，亂雲和雨收。", "甘泉瀉山腹，聖日穿崖頭。", "大暑不知夏，爽氣常如秋。", "風高松子落，天外鐘聲浮。", "祖師生朗石，古殿名般舟。", "人巧不可至，天意何所留。", "老僧笑相語，此事常窮求。", "移出蓬萊島，侍吾仙子遊。"]'),
('108ff8cf-d24d-4696-92f8-2308cc6c538b','和陶弼思柳亭韻','韋旻','宋','宋诗','song-poetry','','[]','白雲靉靉結相緣，半夜鏌鋣舞醉仙。',32,'全唐诗/poet.song.71000.json','["白雲靉靉結相緣，半夜鏌鋣舞醉仙。", "五百年來得書記，羅洪溪畔浴沂年。"]'),
('28721507-09ed-4162-8564-ac510c86d2e7','閑居','陳俌','宋','宋诗','song-poetry','','[]','大不手持卿相印，小無人擁使君符。',32,'全唐诗/poet.song.71000.json','["大不手持卿相印，小無人擁使君符。", "門前溪水綠如許，好把一竿秋釣鱸。"]'),
('e65ac9d3-63eb-42f9-990c-35490269b249','留宿靈巖','高景山','宋','宋诗','song-poetry','','[]','雪霽寒威峻，山空晚色新。',48,'全唐诗/poet.song.71000.json','["雪霽寒威峻，山空晚色新。", "我來何所羨，一夕暫閑身。", "法鼓震虛空，靈巖紹祖風。", "老僧禪定後，龍虎自相逢。"]'),
('6917e7fd-1efb-415a-916a-6974557fe195','題清風樓','郭景祥','宋','宋诗','song-poetry','','[]','久持使節別堯天，故起朱樓北斗邊。',32,'全唐诗/poet.song.71000.json','["久持使節別堯天，故起朱樓北斗邊。", "勢壓江淮盤厚地，影分吳楚與雲連。"]'),
('de151c80-1101-4804-91c3-543e55aa8f12','子規','劉蕭仲','宋','宋诗','song-poetry','','[]','深藏密葉人難見，斷送春光夢一空。',32,'全唐诗/poet.song.71000.json','["深藏密葉人難見，斷送春光夢一空。", "啼後血流成底事，只應都作映山紅。"]'),
('02a777ed-eac1-4efa-bf4d-1428cb5596e2','句','劉蕭仲','宋','宋诗','song-poetry','','[]','招客飲治聾，聊復盡余盃。',12,'全唐诗/poet.song.71000.json','["招客飲治聾，聊復盡余盃。"]'),
('126fd308-7a11-446d-bcc7-3932cd6bef04','和朱利賓題妙智院','元勛','宋','宋诗','song-poetry','','[]','放懷對客初尋笑，滿目開花未放愁。',32,'全唐诗/poet.song.71000.json','["放懷對客初尋笑，滿目開花未放愁。", "望遠此情天不盡，名山何得逐窮幽。"]'),
('e2caef13-2856-46b4-8e73-69814ff480ff','題靈巖各景 紫雲巖','元勛','宋','宋诗','song-poetry','','[]','歷翠捫蒼堅，不犯塵衣涴。',36,'全唐诗/poet.song.71000.json','["歷翠捫蒼堅，不犯塵衣涴。", "暗香何處花，松下微風過。", "當有道人來，霏煙承寶坐。"]'),
('5e5e5587-ed46-4cf3-9e78-31541df61ce4','題靈巖各景 夕陽洞','元勛','宋','宋诗','song-poetry','','[]','東風送花歸，曳杖雲可倚。',36,'全唐诗/poet.song.71000.json','["東風送花歸，曳杖雲可倚。", "泉石符宿緣，相見作歡喜。", "西瞻少遲留，天末霞成綺。"]'),
('50668ea4-faec-476b-a306-ac9722e935b1','題靈巖各景 朝陽巖','元勛','宋','宋诗','song-poetry','','[]','煙磴入風路，欹危轉深冥。',36,'全唐诗/poet.song.71000.json','["煙磴入風路，欹危轉深冥。", "通明忽到眼，石自太古青。", "仙人故臺在，何處乘雲駢。"]'),
('daa9261b-0e9a-4c1b-9c37-cce82f9748d5','題靈巖各景 明心洞','元勛','宋','宋诗','song-poetry','','[]','僧房尚聞聲，雲扃已通步。',36,'全唐诗/poet.song.71000.json','["僧房尚聞聲，雲扃已通步。", "觀身空翠間，宿靄避巾屨。", "不須躡回蹤，徑自通仙路。"]'),
('6ae8d38f-d99f-417f-a7b4-64ae4461add2','題靈巖各景 漣漪洞','元勛','宋','宋诗','song-poetry','','[]','畏心恐靈居，空渺不可際。',36,'全唐诗/poet.song.71000.json','["畏心恐靈居，空渺不可際。", "奇石墜驚雲，涼坐得少憩。", "何曾落花流，自隔人間世。"]'),
('77e9f068-186c-44cf-bdca-685c238beeb6','題靈巖各景 碧雲洞','元勛','宋','宋诗','song-poetry','','[]','踏流遡風寒，危徑僅可傴。',36,'全唐诗/poet.song.71000.json','["踏流遡風寒，危徑僅可傴。", "中空遂閎深，翠潤欲垂雨。", "人間知何時，石乳觀萬古。"]'),
('3270b386-00a1-4926-891d-64ec5ea10b5a','靈巖','元勛','宋','宋诗','song-poetry','','[]','諸仙深窟宅，石門限塵寰。',120,'全唐诗/poet.song.71000.json','["諸仙深窟宅，石門限塵寰。", "空洞初不礙，風扉敞雲關。", "高廣幾何許，百夫可回環。", "誰託遺蹟在，溟濛煙霧間。", "羽駕此來往，朝貢想清班。", "西風翠屏近，藤蘿莫容攀。", "因循再閱歲，建見亦以艱。", "舊聞劍門好，形勢摧夷蠻。", "今茲固殊特，獨冠江南山。", "少陵惜未到，我語憑誰刪。"]'),
('5a170de2-61f8-4895-8261-f2c70fb0f7c1','題白帝廟詩並序','元勛','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','楚山中到三峽開，長江浩浩從西來。',337,'全唐诗/poet.song.71000.json','["楚山中到三峽開，長江浩浩從西來。", "奫淪巨浸吞萬派，淫預傑立高崔嵬。", "鯨波回薄山羊角，征鼙摻疊鳴春雷。", "蹴石巖壁勢益狠，怒濤駭浪爭鳴豗。", "舟師絕叫不容瞬，風滿孰敢施檣桅。", "龍驤蒙衝量萬斛，梢濆撇漩如枯荄。", "昔聞有神司正直，江潭祠宇留山隈。", "羞牢釃斝薦誠懇，幽鑒冀蒙神所哀。", "跋柁鼓檝駛東騖，忽忽已過巫陽臺。", "巴徼炎瘴晝如霧，湯燖赫日昏風霾。", "欻然晴皎射峭壁，翠光冶灧無纖埃。", "聯娟嵐光落衣袂，飛雲容與風䬐䬐。", "祝融之祥古亦有，神之報與良豐哉。", "嗟余陷阱豈無謂，九死寧知禍有胎。", "觸機直前靡顧後，壬人資從或嫌猜。", "燎原之勢既炎烈，垂涎膏血如狼豺。", "盻刀陰顧肆舞勇，脅肩諂笑如詼俳。", "違道奸徑躐禁橐，盡網異議爲梯媒。", "旋踵已爲鬼矙室，俄驚白骨到蒼苔。", "人勝有時天亦宜定，肸蠁疏網常恢恢。", "險夷百折堅一節，君恩浩蕩天昭回。"]'),
('c7cbb3f8-fa49-449f-9b5a-c19a34f662f5','題妙覺寺','朱利賓','宋','宋诗','song-poetry','','[]','有官增吏役，無事愛僧家。',48,'全唐诗/poet.song.71000.json','["有官增吏役，無事愛僧家。", "不憚山頭路，來煎飯後茶。", "鐘魚雖闃寂，松竹自交加。", "掃榻須盤薄，吾生會有涯。"]'),
('58b1bd15-d85f-4a7a-b199-7c0114533c54','題妙智院','朱利賓','宋','宋诗','song-poetry','','[]','江南景物可人意，夢裏家山喚客愁。',32,'全唐诗/poet.song.71000.json','["江南景物可人意，夢裏家山喚客愁。", "歲月幾何春欲暮，水雲深處寺偏幽。"]'),
('cef59c08-b629-4904-8448-287154437423','句','王公亮','宋','宋诗','song-poetry','','[]','足穀醫還驗，占桑夢已靈。',12,'全唐诗/poet.song.71000.json','["足穀醫還驗，占桑夢已靈。"]'),
('53767d04-b159-4d2b-95f6-1a312ef3aa3f','醴泉歌','張元孝','宋','宋诗','song-poetry','','[]','君不見齊城城西范公泉，曾照當年范公影。',262,'全唐诗/poet.song.71000.json','["君不見齊城城西范公泉，曾照當年范公影。", "范公一去不復返，異時此地成佳景。", "先賢口澤氣尚存，甘棠遺愛誰能並。", "貌公遺像龕公泉，千年恒對佗山嶺。", "惟有此山見此公，後樂不廢林泉景。", "古來豪傑宦轍經，山川草木皆引領。", "不獨照耀翰墨光，抑且品題丹青炳。", "顧予昔忝宗伯省，諧世無術傷骨鯁。", "一年謫官此羈棲，數向寒泉挽修綆。", "冰壺日日潄瓊液，涓滴解使心常醒。", "平生頗味海內水，此與金山可並鶚。", "膏澤定有鬼神護，清流自與乾坤永。", "忽復飄然當去茲，泉聲引韻若爲哽。", "坎漥詎測源流深，鳥鵲空噪梧桐冷。", "君不見古人飲水必廉泉，臨流洗耳須清潁。", "嗟哉此水可洗心，往來祠下宜深省。"]'),
('e43b7a7b-8e87-49c0-8379-0d721b6bed3d','題碧落洞','高衛','宋','宋诗','song-poetry','','[]','翠竇連空跂可攀，飛仙時下五雲端。',32,'全唐诗/poet.song.71000.json','["翠竇連空跂可攀，飛仙時下五雲端。", "公車不暇頻遊此，今日纔來可謂難。"]'),
('515a6d1e-2cda-4093-b139-0afba2ff02e3','題碧落洞','高衡','宋','宋诗','song-poetry','','[]','仙府沈沈日開，霓旌鶴駕幾徘徊。',31,'全唐诗/poet.song.71000.json','["仙府沈沈日開，霓旌鶴駕幾徘徊。", "青雲有路容人到，煮茗浮觴不忍迴。"]'),
('80201a83-b8db-40a0-aeb8-d01b3d1241e3','題碧落洞','張熙','宋','宋诗','song-poetry','','[]','大豁□幽徹洞天，分明平地有蓬山。',32,'全唐诗/poet.song.71000.json','["大豁□幽徹洞天，分明平地有蓬山。", "朝元□□歸何晚，故敞瑤扃白日閑。"]'),
('ce43bf58-ae4d-4930-9816-52fd36454199','景福寺','何彥國','宋','宋诗','song-poetry','','[]','山留灌木冬長茂，巖抱陰雲凍不開。',32,'全唐诗/poet.song.71000.json','["山留灌木冬長茂，巖抱陰雲凍不開。", "滄海未乾徐福死，更於何處覓蓬萊。"]'),
('9f76d9ca-9d70-4e9d-9ce5-10c7d95d67b0','大蓬山天寶碑','何彥國','宋','宋诗','song-poetry','','[]','誰向山陰謾刻鎸，雨淋日炙隸文全。',32,'全唐诗/poet.song.71000.json','["誰向山陰謾刻鎸，雨淋日炙隸文全。", "依稀記得升平事，天寶猶題十二年。"]'),
('e3534e7d-fd1a-455d-a6b3-a5a963f45829','句','何彥國','宋','宋诗','song-poetry','','[]','暗量無限人間事，難概不平天下心。',16,'全唐诗/poet.song.71000.json','["暗量無限人間事，難概不平天下心。"]'),
('1f688953-f313-44b3-bc30-10806b72692f','留題太山','倪適','宋','宋诗','song-poetry','','[]','下列羣山谷萬道，霞瑞重重絕頂高。',32,'全唐诗/poet.song.71000.json','["下列羣山谷萬道，霞瑞重重絕頂高。", "獨判天涯第一□，洞天深影無人□。"]'),
('cea7a075-7ef2-4228-8625-62a28ef9a1f3','題萬年妙蓮閣','宋景年','宋','宋诗','song-poetry','','[]','上方危閣化無蹤，平顧摩空萬桂叢。',64,'全唐诗/poet.song.71000.json','["上方危閣化無蹤，平顧摩空萬桂叢。", "自有蓮華發泥下，何須芝草遍山中。", "石橋暮隔霏霏雨，翠壁寒供凜凜風。", "彈指憑誰開戶牖，向來禪觀仰羣公。"]'),
('55e534e8-d78c-4a4c-ab35-b5f8c53d1dcb','錫杖泉','祁彭年','宋','宋诗','song-poetry','','[]','昔有高人示化權，曾隨杖錫湧甘泉。',32,'全唐诗/poet.song.71000.json','["昔有高人示化權，曾隨杖錫湧甘泉。", "巖穿細孔成池沼，香積僧庖待滌蠲。"]'),
('cf4434e2-68e7-4bbe-bc07-e44b59fc054a','不執寶大師房','祁彭年','宋','宋诗','song-poetry','','[]','枯槁形容七十餘，見人無力出禪居。',32,'全唐诗/poet.song.71000.json','["枯槁形容七十餘，見人無力出禪居。", "蕭然丈室常扃戶，一炷清香萬慮除。"]'),
('ca3bdcf5-7a49-4489-bba4-36a2817c232a','答蘇後湖','榮倪','宋','宋诗','song-poetry','','[]','草廬卜築小如巢，翠竹離離檻外交。',64,'全唐诗/poet.song.71000.json','["草廬卜築小如巢，翠竹離離檻外交。", "鄰米乞來分鶴飽，醫書編就借僧鈔。", "經年閉戶窮幽討，晴日攜筇出近郊。", "爲問練湖高隱地，可容杯水泛堂坳。"]'),
('4016cf05-ec11-4702-bb33-d5f989f00f1d','句','榮倪','宋','宋诗','song-poetry','','[]','多謝喧喧雀，時來破寂寥。',12,'全唐诗/poet.song.71000.json','["多謝喧喧雀，時來破寂寥。"]'),
('df77ca9d-6ad3-49b5-84cd-07891fb5b09a','句','陳二叔','宋','宋诗','song-poetry','','[]','金刀劈破紫穰瓢，撒下丹砂數白粒。',16,'全唐诗/poet.song.71000.json','["金刀劈破紫穰瓢，撒下丹砂數白粒。"]'),
('e8b97799-afbf-4a49-9ad4-a1da57fe161a','送客','王莊','宋','宋诗','song-poetry','','[]','楊花撩亂繞煙村，感觸離人更斷魂。',32,'全唐诗/poet.song.71000.json','["楊花撩亂繞煙村，感觸離人更斷魂。", "江上歸來無好思，滿庭風雨易黄昏。"]'),
('766e1d51-b005-431c-89a2-7774453ddeb2','句','王松','宋','宋诗','song-poetry','','[]','舊菊籬邊又開了，故人天際未歸來。',16,'全唐诗/poet.song.71000.json','["舊菊籬邊又開了，故人天際未歸來。"]'),
('2ad7c24a-c8b7-4abe-9141-0252d6bd069d','產難','釋妙總','宋','宋诗','song-poetry','','[]','不遲一步，不疾一刻。',36,'全唐诗/poet.song.71000.json','["不遲一步，不疾一刻。", "明眼衲僧，如何會得。", "粉骨碎身未足酬，一句了然超百億。"]'),
('40ba2dde-a10d-49e0-992d-59ba9f558846','狗子無佛性','釋妙總','宋','宋诗','song-poetry','','[]','鐵壁銀山，一箭穿過。',20,'全唐诗/poet.song.71000.json','["鐵壁銀山，一箭穿過。", "潦倒趙州，口能招禍。"]'),
('b689c0fa-939e-445d-9f0e-bb02ff90cea3','杲禪師以巖頭婆子話相問作偈以答','釋妙總','宋','宋诗','song-poetry','','[]','一葉扁舟泛渺落，呈橈舞棹別宮商。',32,'全唐诗/poet.song.71000.json','["一葉扁舟泛渺落，呈橈舞棹別宮商。", "雲山海月都拋卻，嬴得莊周蝶夢長。"]'),
('a01f20ab-6f64-4007-8cd5-472f1c0e40dc','偈','釋妙總','宋','宋诗','song-poetry','','[]','日日是好日，佛法世法盡周畢。',30,'全唐诗/poet.song.71000.json','["日日是好日，佛法世法盡周畢。", "不須特地覓幽玄，祇管鉢盂兩度濕。"]'),
('18180476-6cdf-41d5-8ca4-bbb87325ec1b','連珠池','嚴希孟','宋','宋诗','song-poetry','','[]','小橋通南浦，夾道桑榆綠。',24,'全唐诗/poet.song.71000.json','["小橋通南浦，夾道桑榆綠。", "水繞若連珠，風傳芰荷馥。"]'),
('3e927666-4c4c-488d-be2d-b43e1b86c1d4','寄題隱仙坡','王璹','宋','宋诗','song-poetry','','[]','有一仙翁號隱仙，要知□□又生賢。',32,'全唐诗/poet.song.71000.json','["有一仙翁號隱仙，要知□□又生賢。", "好將隱德無家意，賀□仙坡萬古傳。"]'),
('5140637a-eeb1-420c-8a01-fc1ceb39befa','賀州作','毛衷','宋','宋诗','song-poetry','','[]','幾年宦跡浪江湖，到此功名心已無。',32,'全唐诗/poet.song.71000.json','["幾年宦跡浪江湖，到此功名心已無。", "獨上高樓翹首望，江郎山下白雲孤。"]'),
('7257d30e-51cd-4a67-a668-3dce2689d3de','獄中寄酒友','顔幾','宋','宋诗','song-poetry','','[]','龜不靈兮禍有胎，刀從林甫笑中來。',65,'全唐诗/poet.song.71000.json','["龜不靈兮禍有胎，刀從林甫笑中來。", "憂惶囚繫二十日，辜負醺酣三百杯。", "病鶴雖甘低羽翼，罪龍尤很多望風雷。", "諸豪俱是知心友，誰遣尊罍向北開。"]'),
('dc4f8682-0f0e-4a97-8ba6-76d7d67bbe2c','句','顔幾','宋','宋诗','song-poetry','','[]','白日尊中短，青山枕上高。',12,'全唐诗/poet.song.71000.json','["白日尊中短，青山枕上高。"]'),
('22b6f586-f3c8-45a7-8947-9afba5f96520','老叟奉和枝孫仲潛佳作','劉衍','宋','宋诗','song-poetry','','[]','重興古廟一新成，推福昭然□□誠。',64,'全唐诗/poet.song.71000.json','["重興古廟一新成，推福昭然□□誠。", "和氣繕調□歲稔，嘉祥通化國風清。", "共誇□□明時盛，未算堯蓂按月榮。", "不獨詩人讚功德，奏□朝治賀昇平。"]'),
('3deb2157-78fa-4cd8-83d9-0f4f7f11819c','勉子','鄭氏','宋','宋诗','song-poetry','','[]','夏日林間風，汝父心樊籠。',192,'全唐诗/poet.song.71000.json','["夏日林間風，汝父心樊籠。", "冬寒一爐火，嚴凝我獨坐。", "汝父爲官逋，四海鎮區區。", "別汝始經年，汝父鬢皤然。", "歲寒霜雪落，此景誰能覺。", "近聞汝知音，兩補未入學。", "親戚無常心，以此加輕薄。", "兄姊暗攢眉，父母非驚愕。", "知汝負天才，誤失不爲錯。", "遠遠報汝知，旅懷保安樂。", "經史多貫串，德業加磨琢。", "交友用慎擇，出處當執卓。", "京國繁華地，人心險丘壑。", "切切遵予言，勿爲外物鑠。", "文行天所祐，仙桂在掌握。", "衣錦歸故鄉，雙親乃歡躍。"]'),
('e373d693-9c32-4e70-8177-0b21d268d37f','句','上官仲恭','宋','宋诗','song-poetry','','[]','君不見喬木參天獨樂園，至今猶是溫公宅。',19,'全唐诗/poet.song.71000.json','["君不見喬木參天獨樂園，至今猶是溫公宅。"]'),
('8d848791-f787-44b6-8213-6595d10912ad','十二時頌  其一','釋文準','宋','宋诗','song-poetry','','[]','雞鳴丑，念佛起來懶開口。',28,'全唐诗/poet.song.71000.json','["雞鳴丑，念佛起來懶開口。", "上樓敲磬兩三聲，驚散飛禽方丈後。"]'),
('c77b4afc-d87c-4ec5-8dec-e95d701ff3f6','十二時頌  其二','釋文準','宋','宋诗','song-poetry','','[]','平旦寅，當人有道事須親。',28,'全唐诗/poet.song.71000.json','["平旦寅，當人有道事須親。", "不聞先聖有慈訓，莫認狂癡作近鄰。"]'),
('c6c7c1e4-75ce-4783-9252-86bf3ff20256','十二時頌  其三','釋文準','宋','宋诗','song-poetry','','[]','日出卯，大道分明莫外討。',28,'全唐诗/poet.song.71000.json','["日出卯，大道分明莫外討。", "日月縱橫在目前，逢原左右拈來草。"]'),
('bac80fd2-376d-4a19-bffa-b2895b92bfdf','十二時頌  其四','釋文準','宋','宋诗','song-poetry','','[]','食時辰，更無一法可當情。',28,'全唐诗/poet.song.71000.json','["食時辰，更無一法可當情。", "千里出山雲有色，一源投澗水無聲。"]'),
('7880f28c-e0d4-4180-b529-745ff3b27047','十二時頌  其五','釋文準','宋','宋诗','song-poetry','','[]','禺中巳，龍象須觀第一義。',28,'全唐诗/poet.song.71000.json','["禺中巳，龍象須觀第一義。", "若向其中覓是非，見解何曾有李二。"]'),
('fe4937aa-9e1e-44c9-b0a5-29e1cf7a0795','十二時頌  其六','釋文準','宋','宋诗','song-poetry','','[]','日南午，理事相諳更相互。',28,'全唐诗/poet.song.71000.json','["日南午，理事相諳更相互。", "三門拈向燈籠頭，休問他家覓歸路。"]'),
('884c5be4-a914-4dec-8fe7-4a5c46611259','十二時頌  其七','釋文準','宋','宋诗','song-poetry','','[]','日昳未，法身清浄絕方比。',28,'全唐诗/poet.song.71000.json','["日昳未，法身清浄絕方比。", "乾坤遐邇盡東西，千山萬山翠相倚。"]'),
('4a30e80b-8a80-4753-ae1f-cd70dc128a57','十二時頌  其八','釋文準','宋','宋诗','song-poetry','','[]','晡時申，由來大道絕疏親。',28,'全唐诗/poet.song.71000.json','["晡時申，由來大道絕疏親。", "陽和九月百花發，須信壺中別有春。"]'),
('1910aaa6-2fe2-406c-a626-b9295494fb9e','十二時頌  其九','釋文準','宋','宋诗','song-poetry','','[]','日入酉，凈室焚香孤坐久。',28,'全唐诗/poet.song.71000.json','["日入酉，凈室焚香孤坐久。", "忽然月上滿東窗，照我牀頭瑞香斗。"]'),
('7938c0a0-700b-4a11-a7a6-d7e286e541b2','十二時頌  其一○','釋文準','宋','宋诗','song-poetry','','[]','黄昏戌，樓上鳴鐘已落日。',28,'全唐诗/poet.song.71000.json','["黄昏戌，樓上鳴鐘已落日。", "行人旅店宿長途，花上游蜂罷采蜜。"]'),
('7a12d1c8-264f-4f04-a8f0-2cfbf1f03577','十二時頌  其一一','釋文準','宋','宋诗','song-poetry','','[]','人定亥，老鼠此時正無礙。',28,'全唐诗/poet.song.71000.json','["人定亥，老鼠此時正無礙。", "忽然燈滅寢堂前，牀前咬我靸鞋袋。"]'),
('a30552d1-ff03-4217-b932-589043dcda14','十二時頌  其一二','釋文準','宋','宋诗','song-poetry','','[]','半夜子，夢裏分明被人使。',28,'全唐诗/poet.song.71000.json','["半夜子，夢裏分明被人使。", "連宵合藥到天光，起來何處有白芷。"]'),
('674d6770-7602-4609-93f4-b086f0c9a6ff','偈十二首  其一','釋文準','宋','宋诗','song-poetry','','[]','寒來暑往古今同，萬別十差不礙空。',32,'全唐诗/poet.song.71000.json','["寒來暑往古今同，萬別十差不礙空。", "昨夜鐵牛頭角露，滿庭松栢撼秋風。"]'),
('72fe94eb-ff37-4db6-86db-f05674f9e7d3','偈十二首  其二','釋文準','宋','宋诗','song-poetry','','[]','八月九月天，白露寒露節。',24,'全唐诗/poet.song.71000.json','["八月九月天，白露寒露節。", "門外在處山，秋風落黄葉。"]'),
('dcc91385-6a37-4fef-8f94-22ea3fe305cd','偈十二首  其三','釋文準','宋','宋诗','song-poetry','','[]','夜雨斂重雲，曉鴻鳴寥沈。',24,'全唐诗/poet.song.71000.json','["夜雨斂重雲，曉鴻鳴寥沈。", "可憐祖師意，頭頭都漏泄。"]'),
('f8be3eac-28d3-4cca-9f48-f45b6f7daa87','偈十二首  其四','釋文準','宋','宋诗','song-poetry','','[]','祖師關棙子，幽隱罕人知。',24,'全唐诗/poet.song.71000.json','["祖師關棙子，幽隱罕人知。", "不是悟心者，如何舉向伊。"]'),
('abb295e7-8840-48c0-a88b-c2562caf33ac','偈十二首  其五','釋文準','宋','宋诗','song-poetry','','[]','高吟大笑意猖狂，潘閬騎驢出故鄉。',68,'全唐诗/poet.song.71000.json','["高吟大笑意猖狂，潘閬騎驢出故鄉。", "驚起暮天沙上雁，海門斜去兩三行。", "古人道，不看經，不念佛，看經念佛是何物。", "自從識得轉經人，龍藏聖賢都一拂。"]'),
('9c03e6e7-aea1-4043-83c7-833643a8b196','偈十二首  其六','釋文準','宋','宋诗','song-poetry','','[]','四月人家麥正收，連綿陰雨不能休。',32,'全唐诗/poet.song.71000.json','["四月人家麥正收，連綿陰雨不能休。", "沿溪處處生深草，飽殺南泉水牯牛。"]'),
('5b58fccc-0fbc-4bce-8481-b64fb885fa68','偈十二首  其七','釋文準','宋','宋诗','song-poetry','','[]','雞鳴丑，三四五六七八九。',60,'全唐诗/poet.song.71000.json','["雞鳴丑，三四五六七八九。", "象骨峰頭木馬嘶，新豐洞口石牛吼。", "山之前，水之後，吳道僧繇畫不就。", "斷頭船子下南康，彷彿天明到湖口。"]'),
('99807d90-4d0d-4c3c-8a3d-76f13df3c671','偈十二首  其八','釋文準','宋','宋诗','song-poetry','','[]','大道縱橫，觸事現成。',20,'全唐诗/poet.song.71000.json','["大道縱橫，觸事現成。", "雲開日發，水綠山青。"]'),
('451ad7d9-0031-4236-a3d0-dc1ad53c83dc','偈十二首  其九','釋文準','宋','宋诗','song-poetry','','[]','鑽真珠解玉板即易，看窟籠著楔卻難。',29,'全唐诗/poet.song.71000.json','["鑽真珠解玉板即易，看窟籠著楔卻難。", "月色和雲白，松聲带露寒。"]'),
('99b880a3-4dfc-49b5-b529-6d653cb8c628','偈十二首  其一○','釋文準','宋','宋诗','song-poetry','','[]','八月中秋天涼，芙蓉花發題目禪房。',102,'全唐诗/poet.song.71000.json','["八月中秋天涼，芙蓉花發題目禪房。", "老胡大道分明在，不必諸方問短長。", "短不是短，長不是長。", "短長不是處，是道非思量。", "思量不及，文彩愈彰。", "秋山兮秋雲片片，秋江兮秋水洋洋。", "風悲蘭社，天澹滄浪。", "欲言言不及，林下好商量。"]'),
('d8421f4c-6465-48ae-85f5-db1e3193c967','偈十二首  其一一','釋文準','宋','宋诗','song-poetry','','[]','今朝臘月十五，切忌葛藤露布。',59,'全唐诗/poet.song.71000.json','["今朝臘月十五，切忌葛藤露布。", "者事直下分明，當處超佛越祖。", "便與麽去，苦苦。", "寒山子能莽齒，十年歸不得，忘卻來時路。", "呵呵呵。"]'),
('0ac4e8db-a012-434e-b247-9770a8148755','偈十二首  其一二','釋文準','宋','宋诗','song-poetry','','[]','天道運行，節氣頻更。',50,'全唐诗/poet.song.71000.json','["天道運行，節氣頻更。", "五日爲候，十日爲旬。", "三十日爲月，十二月爲年。", "一日一日，因循因循。", "五九盡，又逢春。"]'),
('6e693874-5628-464e-ba44-71bbdf732995','頌古五首  其一','釋文準','宋','宋诗','song-poetry','','[]','老胡徹底老婆心，爲阿難陀意轉深。',32,'全唐诗/poet.song.71000.json','["老胡徹底老婆心，爲阿難陀意轉深。", "韓幹馬嘶青草渡，戴嵩牛臥綠楊陰。"]'),
('89c10604-39c9-46d3-aa18-c8a51399e450','頌古五首  其二','釋文準','宋','宋诗','song-poetry','','[]','我手佛手，十八十九。',20,'全唐诗/poet.song.71000.json','["我手佛手，十八十九。", "雲散月明，癡人夜走。"]'),
('c882e142-a954-4113-b318-1af2cf5d8215','頌古五首  其三','釋文準','宋','宋诗','song-poetry','','[]','我脚驢脚，放過一著。',20,'全唐诗/poet.song.71000.json','["我脚驢脚，放過一著。", "龐公笊籬，清平木杓。"]'),
('78fcd696-c16e-41a9-b001-da61a218d4f1','頌古五首  其四','釋文準','宋','宋诗','song-poetry','','[]','人人生緣，北律南禪。',20,'全唐诗/poet.song.71000.json','["人人生緣，北律南禪。", "道吾打鼓，華亭撐船。"]'),
('64c36bbb-4ad2-4f73-ac74-c62f955fb4b4','頌古五首  其五','釋文準','宋','宋诗','song-poetry','','[]','之乎者也，衲僧鼻孔，大頭向下。',28,'全唐诗/poet.song.71000.json','["之乎者也，衲僧鼻孔，大頭向下。", "若也不會，問取東林王大姐。"]'),
('a616f12d-06b1-4fdf-9dfd-3e8f3fc674ea','頌古五首  其六','釋文準','宋','宋诗','song-poetry','','[]','行路難，行路難，最難難是過臺山。',32,'全唐诗/poet.song.71000.json','["行路難，行路難，最難難是過臺山。", "唯有趙州公驗正，昂頭掉臂總閑閑。"]'),
('4cd8e5c7-fbdb-4047-9c0e-97662b312096','頌古五首  其七','釋文準','宋','宋诗','song-poetry','','[]','好笑提婆達多，入捺落十小劫波。',30,'全唐诗/poet.song.71000.json','["好笑提婆達多，入捺落十小劫波。", "然得三禪妙樂，吹布毛須還鳥窼。"]'),
('dbe7d168-7b1a-4b2f-a9bd-dd6dd4f5cda8','送雲侍者','釋文準','宋','宋诗','song-poetry','','[]','鳥窼吹布毛，老婆爲侍者。',96,'全唐诗/poet.song.71000.json','["鳥窼吹布毛，老婆爲侍者。", "今古道雖同，賓峰不然也。", "二月三月時，和風滿天下。", "是處百華開，遠近山如畫。", "歧路春禽喧，高巖春水瀉。", "頭頭三昧門，虛明周大野。", "好箇真消息，書送汝歸舍。", "衲僧末後句，噓是何言歟。"]'),
('cf4d97f5-d561-42a2-9fb5-35c359402977','送利監收','釋文準','宋','宋诗','song-poetry','','[]','開眼合眼，道契寰中。',121,'全唐诗/poet.song.71000.json','["開眼合眼，道契寰中。", "東行西行，禪非物外。", "大仰插鍬叉手，靴裏動指頭。", "南泉把鎌刈茅，誰人知此意。", "今也道不及古，僧僧解數滿肚。", "但尋雪月風華，失卻昔年活路。", "不能返照回光，法界毗盧全露。", "阿呵阿，笑倒利頭陀，風前月下囉哩囉。", "深夜處分諸火客，你看甚麽火色。"]'),
('a2890d13-058f-444a-892c-a9b3ecd1db51','自贊  其一','釋文準','宋','宋诗','song-poetry','','[]','我若自贊，雲居羅漢。',40,'全唐诗/poet.song.71000.json','["我若自贊，雲居羅漢。", "我若自毀，無主餓鬼。", "贊之不欣，毀之不嗔。", "毀譽不動，東魯西秦。"]'),
('3ffc3da9-a17b-4bc1-8e37-9936ec19739e','自贊  其二','釋文準','宋','宋诗','song-poetry','','[]','爾圖我真，又求我贊。',43,'全唐诗/poet.song.71000.json','["爾圖我真，又求我贊。", "我真我贊，兩重公案。", "家醜不外揚，己德不自談。", "寄之以數，六九五十三。"]'),
('835ead7a-5934-453b-806a-798606b8bc5f','自贊  其三','釋文準','宋','宋诗','song-poetry','','[]','我已是妄，爾更妄寫。',40,'全唐诗/poet.song.71000.json','["我已是妄，爾更妄寫。", "妄我妄寫，兩重虛假。", "欲傳吾真，須泯見聞。", "聲色不礙，相似十分。"]'),
('7caed506-22a6-4336-bbe8-0c54987d60b6','贈奇松頭歌','釋文準','宋','宋诗','song-poetry','','[]','種松道者道情孤，往箇茅庵事事無。',86,'全唐诗/poet.song.71000.json','["種松道者道情孤，往箇茅庵事事無。", "屋內鋤頭三兩柄，煙熏一隻醋葫蘆。", "問渠禪，回首指山前。", "問渠道，戴箇篛笠去鋤艸。", "再三再四再問渠，拍手呵呵笑欲倒。", "卻言昔日老雲門，參見睦州陳長老。"]'),
('082bcc38-4122-4e0f-8549-ecf1beba49ec','偈二首  其一','釋文準','宋','宋诗','song-poetry','','[]','五九四十五，聖人作而萬物睹。',30,'全唐诗/poet.song.71000.json','["五九四十五，聖人作而萬物睹。", "秦時𨍏轢鑽頭尖，漢祖殿前攀噲怒。"]'),
('74ec67ba-ffb0-43ab-8268-b364e69907a1','偈二首  其二','釋文準','宋','宋诗','song-poetry','','[]','今朝臘月十，夜來天落雪。',90,'全唐诗/poet.song.71000.json','["今朝臘月十，夜來天落雪。", "羣峰極目高低白，綠竹青松難辨別。", "必是來年蠶麥熟，張公李公皆忻悅。", "皆忻悅，鼓腹謳歌笑不徹。", "把得雲簫繚亂吹，依稀有如楊柳枝。", "又不覺手之舞之，足之蹈之，左之右之。"]'),
('bcc7d830-3abb-45f0-a485-be72624e92c8','以偈問文準禪師','僧某','宋','宋诗','song-poetry','','["\u5bd2\u98df\u8282", "\u4eba\u751f", "\u611f\u53f9"]','寒食因悲郭外春，墅田無處不傷神。',32,'全唐诗/poet.song.71000.json','["寒食因悲郭外春，墅田無處不傷神。", "林間壘壘添新塚，半是去年來哭人。"]'),
('69c68114-8da8-4113-81a8-aaa8fa564469','偈三首  其一','釋梵言','宋','宋诗','song-poetry','','[]','吾心似秋月，碧潭清浩潔。',24,'全唐诗/poet.song.71000.json','["吾心似秋月，碧潭清浩潔。", "無物堪比倫，教我如何說。"]'),
('a4db18c9-f2a8-45a6-9d00-cd7c56b63ea7','偈三首  其二','釋梵言','宋','宋诗','song-poetry','','[]','一生二，二生三，遏捺不住，廓周沙界。',65,'全唐诗/poet.song.71000.json','["一生二，二生三，遏捺不住，廓周沙界。", "德靈直上妙峰，善財卻入樓閣。", "新婦騎驢阿家牽，山青水綠。", "桃華紅，李華白，一塵一佛土，一葉一釋迦。"]'),
('44bd5671-2104-4ce1-8d04-f071cab7810d','偈三首  其三','釋梵言','宋','宋诗','song-poetry','','[]','臘月二十日，一年將欲盡，萬里未歸人。',34,'全唐诗/poet.song.71000.json','["臘月二十日，一年將欲盡，萬里未歸人。", "門前殘雪日輪消，室內紅塵遣誰掃。"]'),
('80cb184f-7d80-4d1d-a5f1-16df8c17281c','頌古九首  其一','釋梵言','宋','宋诗','song-poetry','','[]','趙州老，對面人難曉。',30,'全唐诗/poet.song.71000.json','["趙州老，對面人難曉。", "一歸何處，青州布襖。", "金銀琉璃，硨磲瑪瑙。"]'),
('dede2861-a31b-4f00-9b41-5a7f3419651d','頌古九首  其二','釋梵言','宋','宋诗','song-poetry','','[]','春風二月半，桃華紅爛熳。',38,'全唐诗/poet.song.71000.json','["春風二月半，桃華紅爛熳。", "靈雲到處逢，衲僧著眼看。", "看，看，短棹孤舟，誰居彼岸。"]'),
('9043c5db-c767-414d-8ca3-759b4fda7d5e','頌古九首  其三','釋梵言','宋','宋诗','song-poetry','','[]','田中插鍬，床上推枕。',20,'全唐诗/poet.song.71000.json','["田中插鍬，床上推枕。", "千手千眼，不審不審。"]'),
('dae2dbc3-a1dc-45ab-8b9b-0af861a93873','頌古九首  其四','釋梵言','宋','宋诗','song-poetry','','[]','風雲會合又相期，覿面難明第一機。',32,'全唐诗/poet.song.71000.json','["風雲會合又相期，覿面難明第一機。", "霹靂一聲天地迥，西河師子卻生兒。"]'),
('e1034280-45ff-4e69-b77f-cea447351001','頌古九首  其五','釋梵言','宋','宋诗','song-poetry','','[]','庭前柏樹子，不是祖師心。',24,'全唐诗/poet.song.71000.json','["庭前柏樹子，不是祖師心。", "莫執一時見，便忘千古音。"]'),
('e3ea1fd9-68e8-4d51-ba85-437e3d3d8b7f','頌古九首  其六','釋梵言','宋','宋诗','song-poetry','','[]','汗馬功勞要立身，將軍一等掃邊塵。',32,'全唐诗/poet.song.71000.json','["汗馬功勞要立身，將軍一等掃邊塵。", "全身只待英雄士，不遇英雄愁殺人。"]'),
('e9f76969-ced6-490c-8ba5-c0ab66ba15a2','頌古九首  其七','釋梵言','宋','宋诗','song-poetry','','[]','查渡湖南涉路歧，雲門不惜兩莖眉。',32,'全唐诗/poet.song.71000.json','["查渡湖南涉路歧，雲門不惜兩莖眉。", "萬古碧潭空界月，再三撈摝始應知。"]'),
('d7bf3dd9-1091-47ff-bb96-4034556a86bc','頌古九首  其八','釋梵言','宋','宋诗','song-poetry','','[]','仰之彌高，鑽之彌固。',36,'全唐诗/poet.song.71000.json','["仰之彌高，鑽之彌固。", "昭昭明明，如藤倚樹。", "大笑呵呵誇白牛，碧雲繚繞無尋處。"]'),
('5070ad51-b6df-42e6-b768-a618b1fca33d','頌古九首  其九','釋梵言','宋','宋诗','song-poetry','','[]','當日臨崖看滸眼，至今觀水憶南泉。',32,'全唐诗/poet.song.71000.json','["當日臨崖看滸眼，至今觀水憶南泉。", "趙州頭戴草鞋去，漁翁腰带好牽船。"]'),
('53c0b4e7-ab88-488d-9077-21ea61600e3a','張提舉到山有作','釋梵言','宋','宋诗','song-poetry','','[]','清世朝賢難會面，巖堂語道霜風扇。',56,'全唐诗/poet.song.71000.json','["清世朝賢難會面，巖堂語道霜風扇。", "借問何時出帝鄉，笑云西蜀烏頭賤。", "阿呵阿，誰人薦裴相。", "當年典豫章，不惜眉毛又相見。"]'),
('992c3aae-2a63-4acc-8159-921e6e802f01','送務紳禪者分衛歌','釋梵言','宋','宋诗','song-poetry','','[]','豁靈明，開正道，脫卻多年骯臭破布襖。',134,'全唐诗/poet.song.71000.json','["豁靈明，開正道，脫卻多年骯臭破布襖。", "頂門一劄，眼睛便定動，如今識得無能老天。", "真智現，非作造，卷衲攜筇下雲嶠。", "直去廬陵化有緣，萬戶千門須徧到。", "禾山鼓，清平調，俯仰順從心一照。", "那邊若遇本色人，點著皆知妙不妙。", "子莫學，石頭老，書信不通行太早。", "得箇清源鈯斧兒，南臺石上鋤荒草。"]'),
('8a0f9c14-e270-404a-bec4-44140379d7b8','示曇清侍者牧牛歌','釋梵言','宋','宋诗','song-poetry','','[]','儂家牧箇白牛，年來可縱可收。',132,'全唐诗/poet.song.71000.json','["儂家牧箇白牛，年來可縱可收。", "不用鼻頭絭索，任渠放蕩林丘。", "風清月瑩，蹤跡難儔。", "香嚴鞭杖，鞏放繩頭，跨入白雲深處游。", "直得通身無影象，時吹木笛有來由。", "小牛兒，莫容易，淺草平田且隨意。", "勿令逐隊上高坡，筋力未能登嶮巇。", "傍水依山養，令頭角完備。", "叱，豈不見貍奴白牯解作師子游戲。"]'),
('14518d68-c179-4045-b0f9-c6beace27e1e','偈','釋善資','宋','宋诗','song-poetry','','[]','諸方五日一參，壽寧日日陞座。',42,'全唐诗/poet.song.71000.json','["諸方五日一參，壽寧日日陞座。", "莫怪重說偈言，過在西來達磨。", "上士處處逢渠，後學時時蹉過。"]'),
('d96e6a5d-dcc0-4dac-89f2-d3420410822c','偈','釋本','宋','宋诗','song-poetry','','[]','五峰家風，南北西東。',20,'全唐诗/poet.song.71000.json','["五峰家風，南北西東。", "要用便用，以橛釘空。"]'),
('fc4f1cef-bd8f-4bad-8c7f-ee904cc86e10','偈三首  其一','釋進英','宋','宋诗','song-poetry','','[]','報慈有一公案，諸方未曾結斷。',28,'全唐诗/poet.song.71000.json','["報慈有一公案，諸方未曾結斷。", "幸遇改旦拈出，各請高著眼看。"]'),
('85188815-476f-46f3-8827-3e64b2102684','偈三首  其二','釋進英','宋','宋诗','song-poetry','','[]','與麽上來，猛虎出林。',46,'全唐诗/poet.song.71000.json','["與麽上來，猛虎出林。", "與麽下去，驚蛇入草。", "不上不下，日輪杲杲。", "瀟瀟江水碧溶溶，出門便是長安道。"]'),
('6abfaf6e-2e91-467e-b038-3aefcc453557','偈三首  其三','釋進英','宋','宋诗','song-poetry','','[]','三世一切佛，同入這窼窟。',20,'全唐诗/poet.song.71000.json','["三世一切佛，同入這窼窟。", "衲僧喚作遼天鶻。"]'),
('61ae6bcb-1b9f-48ad-b8cf-c80782816742','偈','釋靜','宋','宋诗','song-poetry','','[]','聲前認得，已涉廉纖。',40,'全唐诗/poet.song.71000.json','["聲前認得，已涉廉纖。", "句下承當，猶爲鈍漢。", "電光石火，尚在遲疑。", "點著不來，橫屍萬里。"]'),
('31b3d46d-da69-4e63-b191-d7239b661cc0','唐處厚邀同歐陽元老彭志南遊金鑾寺','吳則禮','宋','宋诗','song-poetry','','[]','秋老萬木脫，浮雲暮連空。',72,'全唐诗/poet.song.71000.json','["秋老萬木脫，浮雲暮連空。", "落景不可挽，冥冥有飛鴻。", "偶與二三友，返轡釋子宮。", "幽事固可喜，逸興殊未窮。", "更期霜華隕，黄菊開舊叢。", "濁醪倘可載，浩歌凌西風。"]'),
('a09b0c12-951a-4ab2-bbef-7fade314d726','春事','吳則禮','宋','宋诗','song-poetry','','[]','春事豈堪論，桃花遽如許。',48,'全唐诗/poet.song.71000.json','["春事豈堪論，桃花遽如許。", "薄暮短墻頭，已作迴風舞。", "翛然斷經過，睡足南窗雨。", "幽夢與誰言，迢遞墮三楚。"]'),
('ac813782-12c9-458b-9bcd-1824e709f69a','送曾公卷之汶陽','吳則禮','宋','宋诗','song-poetry','','[]','投策上前坂，薄暮寒雲滋。',48,'全唐诗/poet.song.71000.json','["投策上前坂，薄暮寒雲滋。", "華轂不可停，奈此長相思。", "鴈影正疾逝，馬鳴一何悲。", "歸期無淹留，黄花殊未衰。"]'),
('01dc9e23-70c9-47f3-9d12-8ffa8d8fbbb6','次韓子蒼韻','吳則禮','宋','宋诗','song-poetry','','[]','一丘當快營，五車要盡捐。',72,'全唐诗/poet.song.71000.json','["一丘當快營，五車要盡捐。", "宿昔有足欣，卿去我欲眠。", "層層江上峰，頗欲窮其巔。", "誰令雨冥冥，復作雷填填。", "不讀離騷經，罷參祖師禪。", "獨奈執熱何，西南有寒泉。"]'),
('6e037e28-c72f-4847-8443-3432121d4dc9','次沈坦之簡周開祖韻','吳則禮','宋','宋诗','song-poetry','','[]','老夫藜糝債，宿昔圭竇姿。',48,'全唐诗/poet.song.71000.json','["老夫藜糝債，宿昔圭竇姿。", "人或謂醜拙，儂亦自笑之。", "沈侯江左士，端肯相携持。", "即時一盃酒，到手慎莫遲。"]'),
('137036ec-af60-4bc3-a100-8958de8c6e2b','無著以東坡西湖觀月聽琴詩示予因次韻','吳則禮','宋','宋诗','song-poetry','','["\u897f\u6e56"]','白月在湖底，脫冠睇微雲。',96,'全唐诗/poet.song.71000.json','["白月在湖底，脫冠睇微雲。", "從來雍門恨，世上惟有君。", "往時東坡老，爲子持一樽。", "東坡只飯豆，未辦汁滓醺。", "獨愛三昩語，昵昵出斷紋。", "東坡拍手笑，俗耳曾不聞。", "延州亦窮相，坐睡徒昏昏。", "都梁固高徹，淮水元自渾。"]'),
('fb9f3589-6c87-4330-96ad-511585055571','再用前韻','吳則禮','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','玉澗安在哉，注目匡山雲。',96,'全唐诗/poet.song.71000.json','["玉澗安在哉，注目匡山雲。", "都梁有奇特，渠自能挽君。", "伏雌端可烹，豈惟酒盈樽。", "老子堪料理，枯腸爲之醺。", "奕奕弦上語，大似機中紋。", "白頭得勝妙，歎咤初未聞。", "更彈醉翁操，洗我蒲團昏。", "且復瀹龍焙，誰言淮水渾。"]'),
('5c15fc2e-5a0d-45f1-a8c8-2988fe33d424','次子仁贈永翁韻','吳則禮','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','脫我頭上巾，星星復種種。',96,'全唐诗/poet.song.71000.json','["脫我頭上巾，星星復種種。", "聊欲對可人，洗此塵事冗。", "歸受一大錢，知渠笑劉寵。", "且當澆渴心，長江岌翻動。", "辦君諸方脚，擬尋小有洞。", "黄帽與青鞋，甘作五湖夢。", "鴻飛強冥冥，姑以白眼送。", "兒輩無足論，急流未爲勇。"]'),
('52d5e1e6-f8ff-4f72-aa39-f0423e41675f','次寄綠莎翁韻','吳則禮','宋','宋诗','song-poetry','','[]','劇談要且置，麈尾寧用長。',84,'全唐诗/poet.song.71000.json','["劇談要且置，麈尾寧用長。", "從來一大事，吾曹可稱量。", "世上有何好，投身淨名坊。", "老夫百不如，摩腹魚稻鄉。", "緬懷眼中人，跛跛豈易忘。", "尚欲投羽扇，無心問糟牀。", "端笑說拍浮，疇昔取腐腸。"]'),
('a39d4f77-4902-4853-8f9f-a675cc1381e0','次坦之韻','吳則禮','宋','宋诗','song-poetry','','[]','隱侯天下士，早從北山遊。',72,'全唐诗/poet.song.71000.json','["隱侯天下士，早從北山遊。", "至今華屋處，淚眥嬰西州。", "予實老且病，聞螘類鬬牛。", "力不任毛頴，况能佩吳鈎。", "蟲鳴夜復久，試起商聲謳。", "姑置鐵如意，珊瑚爲君投。"]'),
('6b23301e-1a6a-41d3-8d74-2c6e978c6b84','九日過宋遇雨呈曾元矩并先寄呂少馮','吳則禮','宋','宋诗','song-poetry','','[]','黄菊濕不鮮，白鴈寒更哀。',48,'全唐诗/poet.song.71000.json','["黄菊濕不鮮，白鴈寒更哀。", "何由穿雨屐，一登宋王臺。", "眷予良友生，南山安在哉。", "行將北湖鬢，投老炤清淮。"]'),
('4edefdf1-498b-4278-bb1e-b57f0c99a4a4','向趙聖源請賦雲壑詩會余東去西來匆匆不暇今追寄之','吳則禮','宋','宋诗','song-poetry','','[]','王孫我輩人，著身一雲壑。',120,'全唐诗/poet.song.71000.json','["王孫我輩人，著身一雲壑。", "五斗炊官倉，糟丘初不惡。", "天公亦好奇，與著尋山屫。", "大笑杜陵翁，不嗔驢失脚。", "一來看都梁，幾見胡鴈泊。", "我昔邊頭歸，淮南秋水落。", "白魚能許肥，宿昔鱠葉薄。", "棖香已思儂，吳虀真可作。", "誰言會面初，晤語如有昨。", "丹青可盡年，此事要商略。"]'),
('fa1ab8a2-d5e8-42c6-8911-62abdc73bcca','窺園','吳則禮','宋','宋诗','song-poetry','','[]','白露幾時下，凉秋晚蕭蕭。',48,'全唐诗/poet.song.71000.json','["白露幾時下，凉秋晚蕭蕭。", "已辭尾涏涏，况復聲咬咬。", "捉麈坐清樾，扶藜經短橋。", "雲邊有鳴鴈，過去不可招。"]'),
('b4df8136-4734-4c69-bb20-08a96cd4bb91','露坐','吳則禮','宋','宋诗','song-poetry','','[]','纖雲卷窮秋，天宇凈如洗。',48,'全唐诗/poet.song.71000.json','["纖雲卷窮秋，天宇凈如洗。", "輕飈入高梧，筞筞鳴不已。", "浩歌步前楹，俛仰多可喜。", "暉夜如相親，輝輝過書几。"]'),
('f6a084fe-261c-4a03-bb06-de5b57de20b2','簡鮑欽止','吳則禮','宋','宋诗','song-poetry','','[]','劇談解人頤，湖海鮑工部。',48,'全唐诗/poet.song.71000.json','["劇談解人頤，湖海鮑工部。", "端能於口前，截斷第二句。", "瘦藤尋上方，住此鼓鐘暮。", "快辦呼酒尊，梅花已無數。"]'),
('df717253-a404-4c68-b538-cc5735340e5e','過開寶謁田端彦','吳則禮','宋','宋诗','song-poetry','','[]','翛然策羸馬，偶造釋子居。',96,'全唐诗/poet.song.71000.json','["翛然策羸馬，偶造釋子居。", "欣與遯世士，共閲瞿曇書。", "脫屐弄清泚，曲肱翳扶疏。", "鳥起短笻外，鐘鳴幽夢餘。", "高論信絕俗，磊落包六虚。", "萬古纔一瞬，天地真蘧廬。", "逸興殊未已，恨彼白日徂。", "詎覺厭塵滓，徜徉方自娛。"]'),
('2a423e18-7c5b-47cd-8567-9a4e5c5a1e76','觀賈表之獵','吳則禮','宋','宋诗','song-poetry','','[]','軒軒大鷹腦，落落饑鶻拳。',144,'全唐诗/poet.song.71000.json','["軒軒大鷹腦，落落饑鶻拳。", "忽張六翮去，勢拉淮南天。", "賈侯實老俊，文字初著鞭。", "平生坐高飛，孤吟餞流年。", "收身事鞍馬，未愛冕有蟬。", "歸來對名妾，含笑脫兩鞬。", "能復飯斗米，白眼捉彘肩。", "玩世今種種，掉頭羞乞憐。", "儂也飽憂患，慣視跕跕鳶。", "澆寒一盃足，撐腸謝三鱣。", "惟樂不可過，快臂烏號還。", "徑横鐵如意，露頂催烹鮮。"]'),
('17db32e4-a543-4a23-bb81-0bf8fdceb60b','遣興  其一','吳則禮','宋','宋诗','song-poetry','','[]','放船秋正佳，日落鴈噭初。',48,'全唐诗/poet.song.71000.json','["放船秋正佳，日落鴈噭初。", "晨炊儻無米，寧尋謝胡奴。", "督郵端可揮，從事良欲呼。", "大是陶淵明，且還讀我書。"]'),
('44df6c9c-8301-4355-ac1c-d328879c1e91','遣興  其二','吳則禮','宋','宋诗','song-poetry','','[]','鮮鮮黄金花，種種白髪人。',48,'全唐诗/poet.song.71000.json','["鮮鮮黄金花，種種白髪人。", "晚歲色不改，宿昔情相親。", "浪因五斗米，愧此流轉身。", "我輩有能事，大笑非伯倫。"]'),
('d0839de8-18d3-4101-9ee7-dbe693e723f3','離淮南寄公卷','吳則禮','宋','宋诗','song-poetry','','[]','船頭看淮南，去入蓮芡海。',48,'全唐诗/poet.song.71000.json','["船頭看淮南，去入蓮芡海。", "九年窮不死，魚鳥怪我在。", "昨日别友人，鬢髪忽已改。", "溥溥白露多，初濕柁樓背。"]'),
('966e8c8b-8aa0-4973-9b8e-11a112c25ec8','良辰','吳則禮','宋','宋诗','song-poetry','','[]','良辰入奇懷，端欲挽我行。',144,'全唐诗/poet.song.71000.json','["良辰入奇懷，端欲挽我行。", "幽花迎人笑，欣然媚柴荆。", "春醪處處佳，姑瀉濁與清。", "好鳥何許來，日暮獨一鳴。", "江山雨新洗，坐使老眼明。", "天公喑鵓鴣，要作爛熳晴。", "平生木上坐，莫逆惟有卿。", "歸尋茅三間，遙取烏几憑。", "長腰雪不如，付兹腹彭亨。", "短蔬勝肥肉，甘哉北湖羮。", "一飽便可足，此外豈所營。", "莫語兒子輩，吾儕寧要名。"]'),
('0492557d-d039-471f-b51f-4a13a5a3c1a1','寄歐陽元老','吳則禮','宋','宋诗','song-poetry','','[]','耿耿坐不寐，浩歌睇流雲。',48,'全唐诗/poet.song.71000.json','["耿耿坐不寐，浩歌睇流雲。", "寒商動清夜，落木何紛紛。", "幽閨納華月，宴几停餘薰。", "聊復飲蘭露，無因持寄君。"]'),
('910b70ee-2eea-4a7a-bcd3-7f80b7c9f869','悠然閣','吳則禮','宋','宋诗','song-poetry','','[]','吏抱簿書去，聊兹駐屏星。',48,'全唐诗/poet.song.71000.json','["吏抱簿書去，聊兹駐屏星。", "亦復喚名酒，脫巾姑細傾。", "慎勿閉我門，要著屐齒痕。", "悠然見南山，疇昔初不言。"]'),
('a87f3be0-9b1b-4efd-a8e2-da741d772de4','將至泗上微雪快晴','吳則禮','宋','宋诗','song-poetry','','[]','僧伽憐我來，娛我六出英。',36,'全唐诗/poet.song.71000.json','["僧伽憐我來，娛我六出英。", "又復憂我寒，迎我以好晴。", "何以謝僧伽，汲水添淨缾。"]'),
('ab224a85-969d-4920-8f7a-b5feb7957a70','贈泗州楊吉老','吳則禮','宋','宋诗','song-poetry','','[]','先生箇中人，百骸一破甑。',120,'全唐诗/poet.song.71000.json','["先生箇中人，百骸一破甑。", "端憎屐滿門，姑現維摩病。", "枕邊黄帝書，大笑毉多盧。", "酬對雖種種，而我初如如。", "要喫十方飯，不擔叢林板。", "久入無碍禪，遂具通身眼。", "客來據胡床，喚婢傳酒觴。", "深藏世諦舌，浩歌看屋梁。", "孔兄掉頭去，寧復挽渠住。", "未辦作癡兒，戶樞以鐵鑄。"]'),
('e6824c8a-dc42-401e-a9f3-fbca5ef4421c','發龜山先寄少馮亢之','吳則禮','宋','宋诗','song-poetry','','[]','貼貼淮不動，翻翻雁能鳴。',72,'全唐诗/poet.song.71000.json','["貼貼淮不動，翻翻雁能鳴。", "強垂投老鬢，又過盱眙城。", "僧伽飽知我，大小身後名。", "快作鼓考考，要聽隨堂聲。", "都梁呂少馮，維吾佳友生。", "更招虞仲子，共看金盆傾。"]'),
('b5e76ef8-7d78-41d3-9c54-5f1aa4727d4b','泗州南山贈呂少馮','吳則禮','宋','宋诗','song-poetry','','[]','跛跛踐危磴，行行把長蘿。',120,'全唐诗/poet.song.71000.json','["跛跛踐危磴，行行把長蘿。", "拊兹都梁岑，睨彼淮水波。", "花木春娬麗，杖屨吾蹉跎。", "輦轂端不遠，舟檝今如何。", "寒泉聚陰竇，落景輸陽坡。", "求羣有頡頏，捉臂無詆訶。", "峰巒會撩客，腰脚強作魔。", "送眺吳楚迥，遐想江湖多。", "情親故人健，齒脫老語訛。", "拍手蒼翠上，一笑忘負痾。"]'),
('e326cdd7-283b-4492-805e-8e502ecf8731','朱涇寺','吳則禮','宋','宋诗','song-poetry','','[]','冀馬日馳突，無地制奔放。',120,'全唐诗/poet.song.71000.json','["冀馬日馳突，無地制奔放。", "來爭天東南，束手莫與抗。", "我航指四百，去之迷所向。", "十里望雲屋，遠意屬崑閬。", "尺五跬步天，丈六歡喜相。", "更參船子師，稽首問無恙。", "平生客江湖，半世狎烟浪。", "漁監選常登，釣尹職不曠。", "此手誤遮日，久矣翳塵妄。", "願師賜金篦，試與開眼障。"]'),
('caf360df-49e9-45ae-aca6-2737163d60b6','登太行','吳則禮','宋','宋诗','song-poetry','','[]','君看太行高，歷井安足道。',72,'全唐诗/poet.song.71000.json','["君看太行高，歷井安足道。", "回頭看禹門，砥柱一何小。", "歇鞍坐蒼崖，九地俯飛鳥。", "瑰詭平生無，摧車亦復好。", "白輝作許奇，梁宋紅未了。", "兀然流轉軀，甘與君王老。"]'),
('9f4164d7-92ed-463d-a804-62ad7cb18cc6','過紫巖寺','吳則禮','宋','宋诗','song-poetry','','[]','初辭戎馬邊，紺宇忽如此。',72,'全唐诗/poet.song.71000.json','["初辭戎馬邊，紺宇忽如此。", "突兀青巒几，故作巖谷紫。", "三年夢招提，一笑來脫屣。", "天憐乘障歸，勞之以奇詭。", "門前古澗流，甘滑無與比。", "衲僧初不知，中有曹溪水。"]'),
('3d6ecec1-9536-4e96-a5a8-2d47e9a25984','得黄濟川書','吳則禮','宋','宋诗','song-poetry','','[]','荆南黄濟川，少小但兩屐。',72,'全唐诗/poet.song.71000.json','["荆南黄濟川，少小但兩屐。", "長大身轉窮，四壁只麽立。", "書來可憐人，苦說遙相憶。", "兒輩滿眼前，吾髪何由黑。", "幾時打僧包，爲子去得得。", "要論十年夢，已復話疇昔。"]'),
('2731ff3c-f21d-47d5-8558-d4c46dc2e4e0','至楚約諸人飯而聖功不來翌旦乃見過','吳則禮','宋','宋诗','song-poetry','','[]','前身坐衲僧，積此葵莧債。',72,'全唐诗/poet.song.71000.json','["前身坐衲僧，積此葵莧債。", "今朝偶烹鮮，居士輒破戒。", "摩挲羈臣腹，商略九州大。", "平生折脚鐺，箇裏有妙解。", "關郎作底忙，使我一長喟。", "明發得得來，猶較些子在。"]'),
('a1ad0e2d-7264-47e4-b7ed-6f3de4dfd564','法雲期曾存之不至','吳則禮','宋','宋诗','song-poetry','','[]','解鞍就塵榻，聊與幽人期。',48,'全唐诗/poet.song.71000.json','["解鞍就塵榻，聊與幽人期。", "寒花受微雨，清香散前墀。", "箯輿杳不來，坐恨白日遲。", "茗甌無復共，何以慰相思。"]'),
('57743454-6ca2-4eec-b2d1-44e48202cb78','木平像吾友宣老所藏宣示寂久矣余因歸朱方遇其徒慈俊乞得之喜而作此','吳則禮','宋','宋诗','song-poetry','','[]','布襪元不破，霜雪遮頭顱。',144,'全唐诗/poet.song.71000.json','["布襪元不破，霜雪遮頭顱。", "政自要老醜，肯剃頷底鬚。", "經卷聊關身，帳座種種無。", "安用古銅缾，捉以高鼻奴。", "草鞋掛龍牀，九州一蚍蜉。", "如何是木平，初落斤斧歟。", "龐眉宣道人，緬想骨已枯。", "舊炊玉粒飯，洗鉢獨我呼。", "跛跛遷臣歸，饑面黧且癯。", "至今說法處，井索纒轆轤。", "唐時李衛公，鑄鐵爲浮圖。", "此塔有壞滅，是事端弗渝。"]'),
('4749677b-2824-4b7a-81b5-4681a4227c76','北湖','吳則禮','宋','宋诗','song-poetry','','[]','北湖真大癡，醜拙人共憎。',48,'全唐诗/poet.song.71000.json','["北湖真大癡，醜拙人共憎。", "宿昔有鼻孔，不穿牯牛繩。", "亭亭僧伽塔，要以兩脚登。", "折腰怕督郵，此事豈吾能。"]'),
('74d05934-60be-4bef-bd3f-ceaa87287dc2','贈趙聖源','吳則禮','宋','宋诗','song-poetry','','[]','北湖河西來，繫船清洛尾。',120,'全唐诗/poet.song.71000.json','["北湖河西來，繫船清洛尾。", "老眼便許奇，日日南山紫。", "脫身戎馬間，見此佳公子。", "手捉有錦嚢，胡牀教脫屣。", "劇談倚蒲團，勝處輒啟齒。", "非關偶追尋，臭味有相似。", "不知官如何，但說丘壑事。", "俗子初未侵，喚醒雲壑睡。", "古圖開巨然，茗椀同料理。", "落日望長空，西風鴈行起。"]'),
('aa057487-de6d-4e36-8a33-a6cefc850053','贈王子和','吳則禮','宋','宋诗','song-poetry','','[]','二年紫塞頭，日日思都梁。',144,'全唐诗/poet.song.71000.json','["二年紫塞頭，日日思都梁。", "歸來向清淮，白魚初飽霜。", "走馬脫轡頭，搴旗向沙場。", "不如把蟹螯，欹帽呼酒觴。", "要聽阿燕歌，頹然倚胡床。", "姮娥一笑粲，韻此九月凉。", "緬懷去從軍，隻影天一方。", "誰令投老夢，猶咤登太行。", "采采東籬花，其香何揚揚。", "昭華喚驚鸞，玉支况在傍。", "自慚老不解，著句說小粧。", "獨知折齒屐，尚可追二王。"]'),
('7729a3e8-c501-44b2-9006-d5d1371fcf55','贈董無求','吳則禮','宋','宋诗','song-poetry','','[]','董侯湖海俊，短小精悍姿。',48,'全唐诗/poet.song.71000.json','["董侯湖海俊，短小精悍姿。", "梁園固多士，末至獨好辭。", "相逢要作語，老語竟不奇。", "飽知匡鼎來，我曹無說詩。"]'),
('ca38dcac-0e14-4692-8c23-dca316bd80c3','贈夷白介然','吳則禮','宋','宋诗','song-poetry','','[]','頃游古新秦，打包過黄河。',120,'全唐诗/poet.song.71000.json','["頃游古新秦，打包過黄河。", "跛跛登摧車，白髪仍荷戈。", "行人十七八，兒女載駱駞。", "戍鼓已斷腸，况乃有邊歌。", "歸來見二老，壞衲夙昔磨。", "舉頭僧伽塔，便如到補陀。", "軟語作許甘，耄矣所得多。", "隨堂一鉢飯，捫腹端無他。", "度淮太早生，船鼓將鳴鼉。", "且置茶鐺事，誰獨相詆訶。"]'),
('1b940875-f89d-4fe6-a1e6-7e8d3aacabc0','再至山陽','吳則禮','宋','宋诗','song-poetry','','[]','北湖錐也無，四海一兒子。',120,'全唐诗/poet.song.71000.json','["北湖錐也無，四海一兒子。", "此生吾知之，不過老病死。", "五斗一強謀，要飽聊爾耳。", "禿髪猶讀書，盡勝種種事。", "初解行脚包，問訊長淮水。", "端欲洗枯腸，相見輒歡喜。", "將借官屋居，聊復置牀几。", "更煮楚州糜，尚欠淮南睡。", "手中楞嚴經，咀嚼真有味。", "姑降老鼻雷，豈復論字義。"]'),
('82d9eb63-774d-4a7b-b09d-b74e965ee674','田不伐遺披雲圖','吳則禮','宋','宋诗','song-poetry','','[]','田郎具眼人，會遣披雲嘯。',48,'全唐诗/poet.song.71000.json','["田郎具眼人，會遣披雲嘯。", "翺也未絕參，儼公初不笑。", "聊須論翰墨，寧數金粟妙。", "全體已見前，大是頂門竅。"]'),
('92e003cd-582f-4ee0-a36f-44a471fe4e18','過歐陽元老草堂','吳則禮','宋','宋诗','song-poetry','','[]','知子廊廟器，誅茅楚江邊。',264,'全唐诗/poet.song.71000.json','["知子廊廟器，誅茅楚江邊。", "緬懷靖節意，心遠地自偏。", "綠髪走關塞，蹭蹬成華顛。", "老益抱孤操，冥鴻正翩翩。", "草堂足幽趣，茗飲共留連。", "新詩出錦囊，火齊堆我前。", "芙蕖頗秀發，灼灼初爭妍。", "解衣俯方塘，潑潑鮪與鱣。", "屋角升赤日，長空隨飛鳶。", "羽扇無停揮，聒耳憚鳴蟬。", "蠻簟敷龍牙，曲肱偶欹眠。", "輕風灑梁棟，爽氣回九天。", "壁間湖灘圖，百仞懸驚泉。", "詎復畏執熱，况若聞潺湲。", "時延遯世人，坐鼓薫風絃。", "得意委萬類，高軼象帝先。", "惟兹霜露零，黄菊輸金鈿。", "白眼望河漢，雲收月娟娟。", "濁酒可消憂，况乃數擊鮮。", "聊持魚枕蕉，脫屣秋水壖。", "商略周八極，落落遺簡編。", "誰言厭羈旅，便欲終殘年。"]'),
('ddcce837-d434-4171-924b-1f9cb6765686','元老見過因誦新詩','吳則禮','宋','宋诗','song-poetry','','[]','西風動湖海，木落蓬戶幽。',168,'全唐诗/poet.song.71000.json','["西風動湖海，木落蓬戶幽。", "稍回長者車，聊以銷我憂。", "脫巾哦新詩，爽氣凌高秋。", "蕭然漂轉餘，文字慵雕鎪。", "老驥語尤壯，屹屹孰與儔。", "一笑曾莫逆，未覺悲淹留。", "歲晚餘稉稻，呼兒具肴羞。", "蔬畦綠可擷，濁酒供獻酬。", "平生山林姿，絕意宮錦裘。", "黄雞忽登俎，豈羡烹全牛。", "念昔佐帷幄，飲甘佩吳鈎。", "滄波會入手，此事非人謀。", "羲和驅白日，疾遊無停輈。", "散髪倚前檻，江天雲自愁。"]'),
('a07f63a0-6c20-4fa9-b40c-18b65006831d','買菊','吳則禮','宋','宋诗','song-poetry','','[]','偶煩孔方兄，聘此高妙姿。',48,'全唐诗/poet.song.71000.json','["偶煩孔方兄，聘此高妙姿。", "粲然顧我笑，佳哉今何時。", "維摩初不病，坐獲大奇勝。", "便拈楖栗來，祖師有律令。"]'),
('34881b62-522d-47cb-a309-b8ea1f10c509','移菊','吳則禮','宋','宋诗','song-poetry','','[]','愛此秋氣凉，捐書坐北戶。',144,'全唐诗/poet.song.71000.json','["愛此秋氣凉，捐書坐北戶。", "黄花手自栽，開花忽無數。", "朔風吹寒雲，色映茅簷暮。", "起立佇幽香，泥衣有零露。", "旋移霜中花，娛此羈旅人。", "白髮圖一笑，天公初不嗔。", "平生飽參鼻，宿昔應供身。", "老大無所著，幽花如絕倫。", "勝處那可已，聊復運意根。", "漉彼汁滓酒，澆兹葵莧唇。", "憑君辦好語，與招江海魂。", "端欲道逸想，緬焉難具論。"]'),
('feb2a7af-ca29-4395-ab4d-458959feb932','讀德操詩文','吳則禮','宋','宋诗','song-poetry','','[]','平生饒德操，飽讀世上書。',72,'全唐诗/poet.song.71000.json','["平生饒德操，飽讀世上書。", "坐斷諸方舌，脊梁儂不如。", "去耕鄧州田，要作青鞋錢。", "忽然騎聖僧，我子真天然。", "胸中姑一吐，戲說無義語。", "端有本分椎，莫打老師鼓。"]'),
('6fde8ef7-a11a-467a-b1a6-7abcb89242ac','王和鼎石銚甚佳以詩丐之','吳則禮','宋','宋诗','song-poetry','','[]','枵腹強自滿，日愛幾合陳。',96,'全唐诗/poet.song.71000.json','["枵腹強自滿，日愛幾合陳。", "豆粥咄嗟辦，豈是吾曹人。", "故應彭亨腹，稱此病痩身。", "君從東海來，便便作雲根。", "我有紫玉璧，氣壓連城珍。", "要渠作蟹眼，一洗胸次塵。", "王郎實好奇，宿昔飽幽事。", "莫逆無與疇，端以同臭味。"]'),
('b661fc09-2845-4242-b0c5-38424defef5f','即事','吳則禮','宋','宋诗','song-poetry','','[]','子規日日啼，凋我兩鬢毛。',48,'全唐诗/poet.song.71000.json','["子規日日啼，凋我兩鬢毛。", "鄰家洗甕盎，漸欲見濁醪。", "飽聞荆江邊，古柳繫酒船。", "沙頭昨夜夢，一笑水浮天。"]'),
('ffb564c7-b77b-41d0-9be9-75eb563f785d','少馮約同趙伯山飲贈伯山','吳則禮','宋','宋诗','song-poetry','','[]','頃聞趙伯山，亦復哦其詩。',120,'全唐诗/poet.song.71000.json','["頃聞趙伯山，亦復哦其詩。", "今者得會面，真能解人頤。", "往時黄宜州，句法天下奇。", "平生老婆相，不救枯腸饑。", "或架屋下屋，辛苦僅得皮。", "君看趙伯山，獨將聖僧騎。", "維舟都梁岸，捉手那復疑。", "歡然悅情話，似有宿昔期。", "吾友呂少馮，辦此一笑嬉。", "莫論夜如何，明發當語誰。"]'),
('0d70ba43-83fa-4bf2-9d0a-65b8dee31260','招李漢臣飲與漢臣别九年相視癯然各已翁矣','吳則禮','宋','宋诗','song-poetry','','[]','平生三毛爾，鬢髪眉與鬚。',144,'全唐诗/poet.song.71000.json','["平生三毛爾，鬢髪眉與鬚。", "奈何忽霜雪，星星欲無餘。", "手中木上座，枯槁正類渠。", "而我方兩忘，隱几者誰歟。", "是身那有堅，寢飯姑如如。", "舊持祖師令，似守商君書。", "老夫亦耄矣，戒律今全除。", "惟兹笑及嗔，二法元不殊。", "獨當招故人，濁酒滿眼沽。", "非徒洗離羣，且復澆索居。", "白魚良已佳，黄菊端未疏。", "肯來共情話，寧辭辦籃輿。"]'),
('5f069020-3f94-40fc-aaa7-b2ef2b9594d6','比以補陀刻寄少馮有詩復答之并示楊吉老釋介然','吳則禮','宋','宋诗','song-poetry','','[]','我以無作語，刊彼月面背。',48,'全唐诗/poet.song.71000.json','["我以無作語，刊彼月面背。", "遣似呂南山，未要餘子會。", "平生太玄雄，猶有一語在。", "只憐粥飯和，已復不驚怪。"]'),
('d6ad1bbc-a356-4b5e-8ebd-c259f91d7870','送覺老住鹿門','吳則禮','宋','宋诗','song-poetry','','[]','平生作許奇，三匝繞茅舍。',96,'全唐诗/poet.song.71000.json','["平生作許奇，三匝繞茅舍。", "白髪右掖門，朝參隨萬馬。", "覺也鐵脊梁，兒子笑諸方。", "時時容子美，來過贊公房。", "袖書僕射府，打包鹿門去。", "獨有田恊律，知渠逸羣句。", "余方在泥滓，妄意水傳器。", "他年著行纒，一鉢有能事。"]'),
('8cb38588-cf19-4f8a-b4b8-6d8bc97afcc1','入汴示坰','吳則禮','宋','宋诗','song-poetry','','[]','前年泝洛水，楊花白如氈。',48,'全唐诗/poet.song.71000.json','["前年泝洛水，楊花白如氈。", "今年泝洛水，青青未三眠。", "猶喫嵩福飯，強尋梁宋船。", "一笑真自喜，蒲團媚癯仙。"]'),
('fd6110d0-d43c-4493-826c-076e4d91643e','懷妙老','吳則禮','宋','宋诗','song-poetry','','[]','屋頭風雨交，喚此耋老夢。',48,'全唐诗/poet.song.71000.json','["屋頭風雨交，喚此耋老夢。", "粥魚腹遽鳴，來作枕中供。", "底處有可人，齋鉢是日用。", "時時要同盤，穿雪菜甲動。"]'),
('90d54472-80e0-4d51-a995-ca86f23e8ff2','代書寄凈明道人','吳則禮','宋','宋诗','song-poetry','','[]','凈明端可人，日用一僧鉢。',48,'全唐诗/poet.song.71000.json','["凈明端可人，日用一僧鉢。", "覓句殊未休，平生箇中活。", "眷我梁宋遊，茗椀屢澆潑。", "淮南霜露寒，轉柁何由達。"]'),
('4054d1e8-a72e-4bda-9670-ad8a8b8d70c8','寄印老并招壁公','吳則禮','宋','宋诗','song-poetry','','[]','半生阿印奇，不作俗子見。',48,'全唐诗/poet.song.71000.json','["半生阿印奇，不作俗子見。", "罷說北固禪，去喫長蘆飯。", "堂中壁道人，大是一好漢。", "遣意有或來，誰云可招喚。"]'),
('b22f0fd9-4df9-4a3c-9d30-c8620513a914','永城道中','吳則禮','宋','宋诗','song-poetry','','[]','聊挾儒生書，更打衲子包。',72,'全唐诗/poet.song.71000.json','["聊挾儒生書，更打衲子包。", "五斗亦何直，老夫今二毛。", "道邊霜鬢翁，煮茗澆我勞。", "大笑陶淵明，罷官緣折腰。", "奴輩不解事，歎息腹屢枵。", "歸來買大甑，炊飯謝汝曹。"]'),
('1a01eb7c-9854-4390-8299-c3ca185f83f1','閑居','吳則禮','宋','宋诗','song-poetry','','[]','阿堵安用多，十年著一冠。',144,'全唐诗/poet.song.71000.json','["阿堵安用多，十年著一冠。", "且作楚州夢，從人憎鼻鼾。", "柴桑閑居詩，讀罷始永歎。", "鶬鶊幾時鳴，眷此春事闌。", "何以韻今日，朱絲發清彈。", "大部華嚴經，字字要飽觀。", "鞭筍真肥白，媚我晨炊盤。", "小君孟德耀，老夫梁伯鸞。", "端須如龐公，妻兒坐團欒。", "好作竹漉籬，未憂終歲餐。", "濃煎飯後茶，箇中良可安。", "宿昔逸羣句，慰渠舉似看。"]'),
('ae1b8c01-c9cc-4ec4-a249-80b6da763aea','巖齋','吳則禮','宋','宋诗','song-poetry','','[]','從來謝幼輿，宜置丘壑中。',48,'全唐诗/poet.song.71000.json','["從來謝幼輿，宜置丘壑中。", "虎頭有妙理，誰謂毛頴工。", "崎崎磊磊間，聊復着此翁。", "平生烏皮几，不與兒曹同。"]'),
('82bcda30-805e-41cf-9f26-01bc78d5cd90','魯侯以上巳日宴高陽偶成長句','吳則禮','宋','宋诗','song-poetry','','[]','羅幃繡箔凌蒼穹，揚飛白雪初濛濛。',320,'全唐诗/poet.song.71000.json','["羅幃繡箔凌蒼穹，揚飛白雪初濛濛。", "雲收海面吐朝日，漸射碧瓦光曈曨。", "聊停隼旆駐雙節，琥珀瀲灧黄金鍾。", "雛鶯乳燕弄清晝，幽香薄暮飄殘紅。", "遊絲芳草入望眼，天低旅鴈鳴嗈嗈。", "溪深漲渌浮畫棟，雨餘山色虚無中。", "修眉翠袖倚長笛，五馬矯首嘶春風。", "輕煙漠漠暝蘭檝，鷗鳥静不驚笙鏞。", "玉堂念昔掌帝制，文彩詎獨如醉翁。", "夜聽宮漏對蓮燭，突兀萬卷蟠心胸。", "雄辭妙語委椽筆，波濤洶洶來何窮。", "法嚴義古跨兩漢，磊落未許盤誥工。", "晚握銅魚坐虎帳，錦衣鐵騎懸刀弓。", "熊羆俯仰隨杖屨，棘門覇上真兒童。", "葛巾羽扇姑自適，指麾俎豆威羌戎。", "飲酣隱几騁談辯，逸氣凛凛侔銛鋒。", "氈裘辮髪豈足數，終使萬物歸埏鎔。", "塞垣佳景寄新詠，璀璨千丈垂晴虹。", "章江倦客謾歎息，轉徙八極猶孤蓬。", "登臨暫喜脱人境，安得健翮超寒空。"]'),
('6238eaba-17b9-4018-82ee-6adbb0ee5bf4','二疏遺榮圖','吳則禮','宋','宋诗','song-poetry','','[]','飽聞疇昔設供帳，祖道都門車百兩。',192,'全唐诗/poet.song.71000.json','["飽聞疇昔設供帳，祖道都門車百兩。", "脱冠著屐良有人，五鼎一毛真邁往。", "彭澤縣令亦勝流，徑捐五斗因督郵。", "著書頗復恨枯槁，臭味絕知殊二老。", "龍眠一世論丹青，不數輞川王右丞。", "丹青之引誠落寞，世上只今無少陵。", "二疏妙致不可孤，昔人亦作二疏圖。", "龍眠捉筆守圭竇，兒輩亦復知廣受。", "昔人獨能圖二疏，圖以韻語至今無。", "丹青之引有句眼，昨者少陵今隱居。", "龍眠平生有妙思，筆如周商鐘鼎字。", "二疏之迹定不磨，照人真若前日事。"]'),
('e6586253-ca22-4560-889a-08e5cc1f5516','寄尚志','吳則禮','宋','宋诗','song-poetry','','[]','孤城慘淡臨寒水，戰馬不收眠隴底。',64,'全唐诗/poet.song.71000.json','["孤城慘淡臨寒水，戰馬不收眠隴底。", "戍鼓吹角夜迢迢，霜月徘徊夢驚起。", "遙知横槊興方新，綠入沙塲細草春。", "憔悴誰憐蘇季子，貂裘空復敝黄塵。"]'),
('4bae44b6-bcee-4cd2-9ba9-3407fb766d34','寄韓子蒼','吳則禮','宋','宋诗','song-poetry','','[]','忍饑徹困聊上書，世故如許可復耐。',64,'全唐诗/poet.song.71000.json','["忍饑徹困聊上書，世故如許可復耐。", "孔兄有底喚不來，人意政緣俗物敗。", "撐腸一鉢十方糜，要是堅持衲僧戒。", "失身文字因果中，黄髪猶還毛頴債。"]'),
('4456a770-1f26-4902-acd8-7da477eb4239','寄天牖元翰','吳則禮','宋','宋诗','song-poetry','','[]','嗷嗷沙磧鴈鳴初，淮南已復憐春餘。',64,'全唐诗/poet.song.71000.json','["嗷嗷沙磧鴈鳴初，淮南已復憐春餘。", "梅邊白雲莫謾好，桃底紅雨嗟何如。", "今者無端近戎馬，遠方不復呼籃輿。", "江頭也有東橋竹，作報獨少將軍書。"]'),
('d9f87d16-0e4b-4bd1-93f2-62be11dde2c0','田不伐玉磬歌','吳則禮','宋','宋诗','song-poetry','','[]','田侯玉磬何瑰奇，吳子見之俄朵頤。',224,'全唐诗/poet.song.71000.json','["田侯玉磬何瑰奇，吳子見之俄朵頤。", "宣王石鼓氣忽喪，摩挲篆刻還嗟咨。", "作止休論惟柷敔，曾窺兩階舞干羽。", "常臨罍洗薦清廟，獲邇天球親簋簠。", "緬懷戛擊良匪遙，少師汝曹疑可招。", "老儒詎復知肉味，惝怳便欲聞簫韶。", "正聲初滛器益訛，九州漸漸嬰兵戈。", "鬼神憤惋莫得秘，直恐世上遭詆訶。", "田侯憫我形影孤，明眼常云絕代無。", "是事寧殊衲衣底，啓齒須逢袒臂胡。", "即今陛下聖且仁，律呂從來惡奪倫。", "克諧八音有夔在，獨驚堯顙如高辛。", "人間詎睹荆山璞，碔砆難言合雕琢。", "憑君持入古銀臺，似說太常修雅樂。"]'),
('9d7c2574-95c7-47d8-b204-529bebfb8b98','聽梁聖民家琵琶','吳則禮','宋','宋诗','song-poetry','','[]','宮様纈羅舞袖長，纖眉巧學時世粧。',88,'全唐诗/poet.song.71000.json','["宮様纈羅舞袖長，纖眉巧學時世粧。", "薫爐夜燒司衣香，酒杯到手天雨霜。", "檀槽徐作春雷轉，龍紋撥打黄金面。", "梨園妙處世不知，爲君弹徹霓裳遍。", "淮南日日花信風，新聲投老愛輕攏，試與小桃催小紅。"]'),
('3f78afce-cbe6-4552-b1cf-cdf02eb96350','送曾公善赴定武','吳則禮','宋','宋诗','song-poetry','','[]','關河落落孤鴻飛，燕然山南霜草齊。',160,'全唐诗/poet.song.71000.json','["關河落落孤鴻飛，燕然山南霜草齊。", "邊笳戍角自悲壯，千里不聞邊馬嘶。", "刁斗夜急虎帳静，皎皎隴月臨牙旗。", "轅門柳色壓毳幕，鐵甲十萬真熊羆。", "少年公子身許國，請佐帷幄辭龍墀。", "屯雲漸對白玉斝，密雪欲犯黄金覊。", "晚風蕭蕭近昜水，想見懷古當傾曦。", "連城笙鏞斷羽檄，往往横槊多新詩。", "雙輪稍蹉隔前坂，轉眄各在天一涯。", "吳鈎錦帯豈足贈，寄聲但有長相思。"]'),
('cd0e5be1-97f0-4f65-a559-68aa6774fc9d','以淮白寄公卷','吳則禮','宋','宋诗','song-poetry','','[]','淮魚潑潑初飽霜，赬尾寧數河之魴。',160,'全唐诗/poet.song.71000.json','["淮魚潑潑初飽霜，赬尾寧數河之魴。", "即今誰獨可寄似，風味高徹惟曾郎。", "曾郎結髪傍輦轂，黄羊舊厭官廚肉。", "藜藿奚爲便作魔，九年雷繞羈臣腹。", "羈臣曩者僕射兒，裘馬詎省論輕肥。", "詩書堆牀四壁立，疇昔裋褐操鉏犁。", "儂亦大是窮相人，小黠不足癡無倫。", "江南江北白月底，簸弄扁舟天不嗔。", "正須晚菘冒香棖，餘生要此一釜羮。", "别來曷如姑問訊，看取老子終騎鯨。"]'),
('e89d0615-a36b-44e3-a37d-b3886a2d6cac','續百憂集行','吳則禮','宋','宋诗','song-poetry','','[]','少陵昨者百憂集，但言兒啼四壁空。',224,'全唐诗/poet.song.71000.json','["少陵昨者百憂集，但言兒啼四壁空。", "覉臣即今百憂集，永痛母氏崩心胸。", "疇昔罪臣投荆州，板輿惴惴那得留。", "老人端已怕勞事，况乃離别酸鼻頭。", "荆州破屋冷似鐵，眼邊種種那堪說。", "縛竹爲瓦安得完，往往稀間過霜雪。", "母氏癯然由暑熱，喘卧十日遽死訣。", "至斯極矣其予乎，毎輙念此骨欲折。", "九重陛下仁如天，逢赦却上沙市船。", "飽聞荆江西江惡，舉家性命實可憐。", "餘生休論飯不足，今費君王嶽祠禄。", "母氏棄我如許時，殊方只有看雲哭。", "賀公吳語慎莫嫌，渠自山陰一茅屋。", "痩妻稚子姑團欒，此叟堆灰未窮獨。"]'),
('6e8a883b-32b4-4970-b54d-78075b193ce8','伯時三馬圖','吳則禮','宋','宋诗','song-poetry','','[]','從來畫馬稱神妙，至今只說江都王。',120,'全唐诗/poet.song.71000.json','["從來畫馬稱神妙，至今只說江都王。", "將軍曹覇實仲季，沙苑丞輩猶諸郎。", "龍眠老人亦畫馬，獨與三子遙相望。", "兩馬駢立真驌驦，一馬脱去仍騰驤。", "龍眠老人今則亡，嗚呼三馬誰平章。", "北湖居士兩鬢蒼，初無長吉古錦囊。", "飯豆不足將遊梁，手持三馬三太息，檣烏已復催船檣。"]'),
('3bb6e5e0-0a94-4ad8-a229-75d3feb00572','題賈表之所藏九馬圖','吳則禮','宋','宋诗','song-poetry','','[]','龍顱豹股貌者誰，將軍曹覇韓幹師。',288,'全唐诗/poet.song.71000.json','["龍顱豹股貌者誰，將軍曹覇韓幹師。", "權奇倜儻得殊相，筆墨真似沙中錐。", "監牧攻駒張太僕，曾令大奴守天育。", "豈如九馬百戰餘，高氣硉兀初不除。", "太宗結髪定天下，蹴踏九州惟九馬。", "太宗廣顙復高鼻，去驂九馬隨羣帝。", "將軍畫肉兼畫骨，跼蹐長楸欲馳突。", "爲儂喚取拳毛來，要遣老儒雙眼開。", "追飛細綺與輕紈，可但殷紅馬腦盤。", "將軍拜舞矜絕藝，兒輩于今說能事。", "緬懷疇昔玉花驄，畫工如山貌不同。", "將軍侍立遽承詔，江都那得稱神妙。", "毎嗟將軍嘗引見，何人更上南薫殿。", "褒公鄂公安在哉，淮泗羈臣想生面。", "羈臣馬癖無與鄰，苦心阿遁真前身。", "生憎駑駘喜汗血，歷塊寧須論一蹶。", "賈侯射虎嗤猨臂，錦囊九馬仍瑰異。", "終甘飽死聽奚官，八鸞六轡君姑置。"]'),
('8970580c-d9f1-4353-9602-da8c16a483b1','曾公卷誦陳子南昭亭詩因次韻','吳則禮','宋','宋诗','song-poetry','','[]','君不見唐時畫馬曹將軍，肯道江都也絕倫。',70,'全唐诗/poet.song.71000.json','["君不見唐時畫馬曹將軍，肯道江都也絕倫。", "又不見即今陳郎論句法，頭頭未背少陵人。", "往時屢費曾郎酒，作意澆潑昭亭春。", "一丘一壑正著相，慎勿來喚天公嗔。"]'),
('b16933d9-eb5d-4d5b-a716-c41eee6b60a5','從貫道求雙幅圖','吳則禮','宋','宋诗','song-poetry','','[]','江郎平生筆五色，戲遣秀句爲奇石。',64,'全唐诗/poet.song.71000.json','["江郎平生筆五色，戲遣秀句爲奇石。", "好絹自作凌亂光，萬里須論才咫尺。", "大兒小兒何足誇，右丞北苑有等差。", "孤舟自横天拍水，江南江北多雲沙。"]'),
('5cbb97f8-81dc-43b5-b5e7-28a0dbfd8f71','和蠟梅詩','吳則禮','宋','宋诗','song-poetry','','[]','江邊一樹垂垂花，酒杯曾覓黄公家。',128,'全唐诗/poet.song.71000.json','["江邊一樹垂垂花，酒杯曾覓黄公家。", "誰教五出作黄蠟，六出休論屬尤物。", "鼻端有竅儂自知，羣兒空誦詩人詩。", "天公與花不與葉，要遣孤芳作超絕。", "緬懷南徐江上山，醉入梅花海中眠。", "梅花亂落青鳥去，大是天公送君句。", "天公定不辜吾人，蠟梅句法聊付君。", "禅牀僧几夢吳越，煮菜從來滿齋鉢。"]'),
('74ccba13-44ef-46c5-9fb2-63a9a5e08046','從王謹常求墨戲','吳則禮','宋','宋诗','song-poetry','','[]','阿常爲官真拓落，胸次平生著丘壑。',64,'全唐诗/poet.song.71000.json','["阿常爲官真拓落，胸次平生著丘壑。", "權奇突兀要舉似，毛頴從來有能事。", "老子於此興不淺，孤鴻斜日秋江遠。", "忘懷丹青以句鳴，只數輞川王右丞。"]'),
('5d5cb3a8-ba74-4261-b70e-5bdd9c1e4ad4','偶作呈曾存子','吳則禮','宋','宋诗','song-poetry','','[]','北窗永日捐羣書，自憐所得才腐餘。',64,'全唐诗/poet.song.71000.json','["北窗永日捐羣書，自憐所得才腐餘。", "東風吹花欲爛熳，强自羈縶同轅駒。", "曲肱静聽百鳥語，圭竇甕牖思吾廬。", "遙憐春水帯刳艇，歸鴈已應辭五湖。"]'),
('b7fa308a-e2f5-4e7b-8d09-44c097cc0287','呈王濟川','吳則禮','宋','宋诗','song-poetry','','[]','鵓鴣争鳴燕方乳，飛絮忽來縈短麈。',64,'全唐诗/poet.song.71000.json','["鵓鴣争鳴燕方乳，飛絮忽來縈短麈。", "眼底桃花且向人，薄暮東風卷紅雨。", "江南春盡水如天，誰呼艇子石城邊。", "急觴到手聊一噱，識字須悲有投閣。"]'),
('ebb26d86-6c22-41c4-9919-c77c6227cb18','謹常以墨戲見遺作此答之','吳則禮','宋','宋诗','song-poetry','','[]','吾人著作翰墨塲，得此三昧惟阿常。',64,'全唐诗/poet.song.71000.json','["吾人著作翰墨塲，得此三昧惟阿常。", "平生韻語真戲劇，化作輪囷抱孤石。", "胸中塊磊安用澆，端要吐出驚兒曹。", "疇能與渠辦兹事，喚取從來管城子。"]'),
('a81689b4-0917-49ca-b780-a8c8b3e1fa85','知府毛公顯謨以詩寵還書軸謹次嚴韻以叙拳拳服膺之萬一','吳則禮','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','天邊疊巘雲濤外，南人啟齒北人怪。',112,'全唐诗/poet.song.71000.json','["天邊疊巘雲濤外，南人啟齒北人怪。", "給事筆力鼎可扛，九鼎初如一毛細。", "曲肱左省清夢餘，長江拍拍天一隅。", "後車聊載高陽徒，行復持被承明廬。", "即今司業誰姓蘇，還能辦人酒錢無。", "生憎枯槁屈大夫，金盤鱠縷日可須。", "公也慎莫言歸歟，美姿要作凌烟圖。"]'),
('d85233d3-307c-429e-898a-557e7f95f79c','貫道惠其所作屏料理爲大軸題之以詩','吳則禮','宋','宋诗','song-poetry','','[]','李成既死作者誰，元豐以來惟郭熙。',109,'全唐诗/poet.song.71000.json','["李成既死作者誰，元豐以來惟郭熙。", "江郎遽出繼二老，自有三昧非毛錐。", "江郎挽弓要射虎，心醉覇陵石飲羽。", "論交一世越與秦，白眼終甘守環堵。", "君不見昔者崑崙方壺圖，筆墨妙好絕代無。", "十日五日歲月徂，豈如江郎咄嗟雲出岫，石上松老楓樹枯。"]'),
('c4313257-2782-42f5-bd3f-246f19bbe888','郭因芍藥洛中本','吳則禮','宋','宋诗','song-poetry','','[]','粲粲忽來紅粉晚，故入吾人醉時眼。',64,'全唐诗/poet.song.71000.json','["粲粲忽來紅粉晚，故入吾人醉時眼。", "吾人宿昔翰墨場，消得文君作小粧。", "莫遣邊頭風雨惡，驚破文君夢伊洛。", "孤芳勝韻明年春，坐中誰作伊洛人。"]'),
('1c5f43fd-2042-43f8-9f1b-0fa2197e9d91','不伐寄長短句因答之','吳則禮','宋','宋诗','song-poetry','','[]','安得不教青鬢老，飛雁年年太行道。',64,'全唐诗/poet.song.71000.json','["安得不教青鬢老，飛雁年年太行道。", "低吟一曲歎疆場，獨遣老子驚絕倒。", "句法吾人莫細論，天教阿傑解玄文。", "衡門飽飯脱兩屨，此事玄文初不與。"]'),
('be439458-f96c-4e96-8846-46080e329aa7','懷子西','吳則禮','宋','宋诗','song-poetry','','[]','眼邊寒策良可親，我曹齪齪渠笑人。',128,'全唐诗/poet.song.71000.json','["眼邊寒策良可親，我曹齪齪渠笑人。", "青鞋布襪有能事，喚取子西來細論。", "老夫箇裏得妙解，挈挈獨提彌勒袋。", "他日還炊何許糜，只今且煮南徐菜。", "八年吳頭并楚尾，痿痿羸羸饑不死。", "端無一物娱此生，天公乞與毛錐子。", "莫嗔朱顔漸殊故，且以粗言作依處。", "幾時雪片似車輪，著屐梅花海中去。"]'),
('fa8038b7-0eb3-4b13-afdb-4e9d535dd6e9','小雨倦出懷介然','吳則禮','宋','宋诗','song-poetry','','[]','北風吹雨鳴船篷，高岸泥滑愁老翁。',64,'全唐诗/poet.song.71000.json','["北風吹雨鳴船篷，高岸泥滑愁老翁。", "少陵病骨端欲折，扶杖無因尋贊公。", "贊公從來懶剃頭，破衲未禦寒颼颼。", "東窗朝日會晴好，共看雪霧翻茶甌。"]'),
('70b540f8-8282-40c4-89f1-170c60280307','戲作簡朱天球','吳則禮','宋','宋诗','song-poetry','','[]','江頭雪花一尺圍，不妨屋角梅垂垂。',192,'全唐诗/poet.song.71000.json','["江頭雪花一尺圍，不妨屋角梅垂垂。", "江頭三日浪簸船，不妨老子被底眠。", "權奇突兀衆所嗔，大是箇中英特人。", "何曾論渠破與墮，餘生且辦擔板過。", "嗟我星星復種種，四十八年環堵夢。", "君看後省粱肉盤，只似蓽門葵莧供。", "莫云儂詩太愁絕，半世全凴毛頴脱。", "熟處難忘却自嫌，面目堪憎爲饒舌。", "腐儒諸方飽行脚，習氣偶存言語縛。", "獨憂湯餅喚睡魔，背貼蒲團鼻雷惡。", "拈時勿著文字相，肯對癡兒誇伎倆。", "屈宋真眼向前會，阿球端知有此事。"]'),
('1007b166-41b8-40a2-a9a6-72364d6320c2','江邊簡新之','吳則禮','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','青鞋布襪茲何時，江邊杏花渾欲飛。',160,'全唐诗/poet.song.71000.json','["青鞋布襪茲何時，江邊杏花渾欲飛。", "銅鉼恰受斗酒許，亟呼長鬚令抱持。", "要尋楚郎與啟齒，有底鵓鴣鳴不已。", "解事提壺却喚人，兩脚尚輕聊爾耳。", "楚郎天生五車書，以錐畫沙絕世無。", "窮年飽喫衲子飯，粱肉臭腐寧關渠。", "衛家一兒誰復似，更遣韻語論胸次。", "獨付匡山教外傳，端合從之問奇字。", "白髪南徐覉旅臣，江湖幾載捐冠巾。", "且扶痩藤隨行好，安能齪齪守煆竈。"]'),
('c963a674-fb73-4191-a17c-c266136af395','同李漢臣賦陳道人茶匕詩','吳則禮','宋','宋诗','song-poetry','','[]','諸方妙手嗟誰何，舊聞江東卜頭陀。',160,'全唐诗/poet.song.71000.json','["諸方妙手嗟誰何，舊聞江東卜頭陀。", "即今世上稱絕倫，只數錢塘陳道人。", "宣和日試龍焙香，獨以勝韻媚君王。", "平生底處虀鹽眼，飽識斕斑翰林椀。", "腐儒慣燒折脚鐺，兩耳要聽蒼蠅聲。", "苦遭湯餅作魔事，坐睡只教渠喚醒。", "豈如公子不論價，千金争買都堂胯。", "心知二叟操鈐鎚，種種幻出真瑰奇。", "何當爲我調雲腴，豆飯藜羮與掃除。", "箇中風味太高徹，問取老師三昧舌。"]'),
('fb8e0ffe-dfad-4caf-8dc2-27f6a893a875','紅梅','吳則禮','宋','宋诗','song-poetry','','[]','楚州紅梅如許紅，作魔猶有幾信風。',64,'全唐诗/poet.song.71000.json','["楚州紅梅如許紅，作魔猶有幾信風。", "天公笑人但飽飯，不辨青春看花眼。", "呼兒徑買北湖酒，澆我瀾翻說詩口。", "莫教一片飛黄昏，喚取百舌來細論。"]'),
('1f172ff2-ae1c-459b-97d5-d925d1ad81b2','題鍾隱簡寂觀圖','吳則禮','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','飽知阿隱有妙處，未負從來丘壑謀。',64,'全唐诗/poet.song.71000.json','["飽知阿隱有妙處，未負從來丘壑謀。", "徑呼管城辦能事，長江貼貼仍晚秋。", "白頭故作西河夢，獨遣老眼酬南州。", "邊笳牧馬豈不好，平安火過消人憂。"]'),
('e15166a3-532b-48ec-9e21-b8432ee6be48','阿坰以歙鉢供太希先偶成','吳則禮','宋','宋诗','song-poetry','','[]','君不見上公之鼎烹養牛，高足巨耳誰與儔。',208,'全唐诗/poet.song.71000.json','["君不見上公之鼎烹養牛，高足巨耳誰與儔。", "又不見便便瓦釡煮黄獨，媚此枵然轉雷腹。", "養牛大嚼良快意，老儒那有王侯鼻。", "黄獨飽火正可憐，自捉長鑱寧用錢。", "太希先，阿坰贈君北湖歙州鉢，天遣吾人箇中活。", "撐腸等取一生足，養牛何曾異黄獨。", "要須以鐵爲脊梁，才可提渠示諸方。", "應笑連牀並頭顱，五更戢戢聽木魚。", "太希先，爾時勿作隨堂解，真是窮年粥飯債。", "覊臣白髪無住著，瀹腐舂陳殊未錯。", "客來摩挲渾不嗔，慎勿觸我紅麒麟。", "南徐祖令儂自知，雪打西安嘗豆糜。"]'),
('5695e6f5-4547-4546-b9b7-64ccfe61801d','次公采贈太希先密雲團韻','吳則禮','宋','宋诗','song-poetry','','[]','道人祝融屩，胡爲墮南州。',188,'全唐诗/poet.song.71000.json','["道人祝融屩，胡爲墮南州。", "都無作相但粥飯，平生衲被姑蒙頭。", "曾郎手中大圓鏡，朵頤贈之非暗投。", "快燒銅缾作蟹眼，鑄成八載心如抽。", "吾行踽踽飽閲世，葵莧獨與衲子游。", "君來適逢小搖落，水天拍拍團滄州。", "喚醒北固龕底夢，擬披袈裟上扁舟。", "且澆玉川七椀句，仍洗船子三寸鈎。", "摩挲正焙連城璧，少林老僧初不識。", "他時一笑示靈源，五百比丘端失色。", "幽叢鮮鮮凉雨餘，亦有黄花净供無。", "知渠肉團久炯炯，玷翳渾滅如大珠。"]'),
('cf4ce0d6-3336-44af-95fb-646d99be5c2c','贈希先','吳則禮','宋','宋诗','song-poetry','','[]','太兄遠從方廣來，緊打脚綳帩草鞋。',128,'全唐诗/poet.song.71000.json','["太兄遠從方廣來，緊打脚綳帩草鞋。", "堂頭老人未相見，道眼心知如覿面。", "山間五百大弟子，僕射魯公辦能事。", "且燒湯鼎試中𤃩，憑仗阿先歸舉似。", "叢林梁棟權與洪，戲爲韻語亦復工。", "曾參陶謝得一滴，漆盂蔬筍要洗滌。", "白髪佳縗只要閒，夢想連牀六尺单。", "豈徒衲帔痿羸坐，共守團爐黄獨火。"]'),
('bbfc320d-8c69-43bf-a476-7bc3a16747bb','次坰韻','吳則禮','宋','宋诗','song-poetry','','[]','北湖先生作許癡，閉門覓句嗔人知。',64,'全唐诗/poet.song.71000.json','["北湖先生作許癡，閉門覓句嗔人知。", "日炊官米著處飽，獨憎飯頭行飯遲。", "天教五車與癯痩，大笑阿蒼如瓠肥。", "小糟秫糜已溜溜，老子捧甖聊朵頤。"]'),
('adbbf1ba-4c42-44e6-931a-c5c30e2c8254','次子蒼寄余清老韻','吳則禮','宋','宋诗','song-poetry','','[]','從來三仕及三已，總落道人坐定裏。',240,'全唐诗/poet.song.71000.json','["從來三仕及三已，總落道人坐定裏。", "滑稽社中黄髪將，詎與阿朔論輩行。", "平生芋魁曾未錯，粱肉寧殊腐腸藥。", "百年兀兀且飽睡，夢事有無渾不記。", "久甘袖手菩提坊，餓死肯踏狙公鄉。", "山林誰云跡如掃，天乞江湖娱此老。", "癯然且喫諸方飯，汝自矻矻儂晏晏。", "坐聽木魚人笑癡，政復朵頤成屢莞。", "要隨煙霧入窮溟，或置一牀如浄名。", "生憎阿秦六國印，蒲團禪板猶關情。", "眼邊雖言有黄卷，絕知口不談書傳。", "舊拈槌拂吾已許，喚取渠來姑語語。", "相望幾時懷抱惡，白玉爲丹堪咀嚼。", "且試車聲銅鼎湯，瀹茗徑可撩枯腸。", "此言何可束高閣，自謂過之一丘壑。"]'),
('fa2a550a-efe7-426f-853e-41de4678c8e0','次天啟贈浄名吳道人韻','吳則禮','宋','宋诗','song-poetry','','[]','君名詎要書黄紙，兒曹安能相汝爾。',192,'全唐诗/poet.song.71000.json','["君名詎要書黄紙，兒曹安能相汝爾。", "平生胸中著丘壑，何曾輙作數日惡。", "看渠老死争名場，肩摩轂擊非儂郷。", "從來俗子貪著帽，露頂心知寡同好。", "可不與飯惟有卿，白眼未分遭題評。", "蘇郎六印蠶作蠒，劇飲濁醪適吾願。", "此事未容人遽知，百醜千拙人笑之。", "勝處豈徒論得髓，覿面端如傳器水。", "典刑真有阿度風，世上眼目無王龔。", "滄波老樹我亦愛，聞說津頭有船賣。", "斯人要是江左人，逕入坐牀寧肯嗔。", "星星種種旋非故，禪板蒲團只如許。"]'),
('6984568b-1569-45b2-80a4-dffb47acef94','次朱天球贈吳茂先韻','吳則禮','宋','宋诗','song-poetry','','[]','暮年挈挈儂與君，端覺高歌有鬼神。',224,'全唐诗/poet.song.71000.json','["暮年挈挈儂與君，端覺高歌有鬼神。", "平生王恭無長物，此事逼人殊咄咄。", "戲談韁馬決鼻牛，夫子大是孫殷流。", "休言他日隨計上，且看南徐拍天浪。", "阿球高氣寧用論，爲卿三倒實飽聞。", "眼邊詎肯作懸特，葵藿撐腸方自嘿。", "屋頭雲錦秋水明，兀然隱几渠寧貧。", "詩書撩人姑把玩，只與毛錐爲老伴。", "紅塵著脚笑參差，索食祖仁那更疑。", "於世無堪大瓠種，獨可剖心如叔仲。", "江湖作意從之遊，老夫頗欲學操舟。", "清言解頤未云已，兒子屢驚雷遶齒。", "好事誰過揚子雲，一樽聊與細論文。", "政須林宗巾角折，仍要時時見顔色。"]'),
('b28bf112-e1e8-4acf-a83b-0a83f8e07d2b','無著有還玉澗之意作詩留之','吳則禮','宋','宋诗','song-poetry','','[]','淮山誰言鈍滯人，沙鴈求羣正如許。',64,'全唐诗/poet.song.71000.json','["淮山誰言鈍滯人，沙鴈求羣正如許。", "先生掉頭嗟奚爲，要著行纒抱琴去。", "徑須摺折楖栗杖，我曹窮措有妙處。", "時時覆鉢過橋來，白頭看打僧伽鼓。"]'),
('bbfabb9e-c1c1-411c-82df-c67a96858662','無著復欲去再作此留之','吳則禮','宋','宋诗','song-poetry','','[]','都梁日日招吾人，梅花已復矜小春。',64,'全唐诗/poet.song.71000.json','["都梁日日招吾人，梅花已復矜小春。", "胡爲要隨白鴈去，莫起此念僧伽嗔。", "彈琴幾時鬢毛脱，端是天教箇中活。", "僧伽初不負先生，久辦淮山作衣鉢。"]'),
('fb054ca3-b8c0-4eac-a423-817c3590c4ed','坰邀公卷煎茶','吳則禮','宋','宋诗','song-poetry','','[]','阿坰手持都堂胯，百千硨磲未論價。',128,'全唐诗/poet.song.71000.json','["阿坰手持都堂胯，百千硨磲未論價。", "渇心知我生塵埃，故遣一甌官茗來。", "上方井水絕世無，中𤃩谷簾定庸奴。", "徑當澆汝三尺喙，要著胸中萬卷書。", "外家典刑有諸老，封胡羯末端復好。", "皎如珊瑚在琳房，况迺薫以正焙香。", "阿坰性獨愛文字，望見俗物輒走避。", "雖然此事已可久，莫負從來鐵御史。"]'),
('dc140383-90d6-4392-83aa-3ddd64a3ab47','周介然所惠石銚取淮水瀹茶','吳則禮','宋','宋诗','song-poetry','','[]','吾人老懷丘壑情，洗君石銚盱眙城。',64,'全唐诗/poet.song.71000.json','["吾人老懷丘壑情，洗君石銚盱眙城。", "要煎淮水作蟹眼，飯飽睡魔聊一醒。", "僧伽孤塔何亭亭，試喚僧伽真肯譍。", "擬向山陽買白菜，圍爐爛煮北湖羮。"]'),
('4918af87-ac7e-44d5-a021-517ef1221e71','贈江貫道','吳則禮','宋','宋诗','song-poetry','','[]','即今海內丹青妙，只有南徐江貫道。',128,'全唐诗/poet.song.71000.json','["即今海內丹青妙，只有南徐江貫道。", "孤峰疊巘真自奇，老樹滄波亦復好。", "扶杖時來問麴生，戲捉毛錐吾絕倒。", "龍眠居士喚不譍，世上從交韋偃少。", "一生管城良有味，彈琴寧論老會至。", "時調白羽臂烏號，楊葉曾穿有能事。", "獨憐老子跛跛歸，故遣七絃聲作雷。", "老子從來知賀若，爲我剩彈烏夜啼。"]'),
('e02e50b9-233a-426e-aa90-ec85348a9279','贈醉吟先生許體之','吳則禮','宋','宋诗','song-poetry','','[]','種種未似哦北窗，頭頭不如喚酒觴。',64,'全唐诗/poet.song.71000.json','["種種未似哦北窗，頭頭不如喚酒觴。", "論文處度過裴迪，覓句介然真佛光。", "曲肱飽作南山夢，提鉢徑坐僧伽床。", "時時裹脛著兩履，盱眙城底淮聲長。"]'),
('071cc8f1-1951-40cd-a98c-fff9535ae7a9','贈江器博','吳則禮','宋','宋诗','song-poetry','','[]','先生行年今七十，植杖端如孤鶴立。',160,'全唐诗/poet.song.71000.json','["先生行年今七十，植杖端如孤鶴立。", "江天小雨作許奇，洲渚横斜鴈行濕。", "先生隸法老更精，未要中郎作典刑。", "筆含鍾鼎小篆意，啟齒要須斯與冰。", "先生宿昔愛彈琴，不愛越琴愛雷琴。", "摩挲龜背蛇蚹紋，太和欵識尤出倫。", "先生真已棄百事，舊參堯典舜典字。", "端有江湖著老儒，笑大耳兒長結眊。", "學書初不論永和，書到石鼓才不磨。", "不見吏部石鼓歌，往載安得數駱駞。"]'),
('a673836a-899d-4395-b034-de58ed804ccf','贈元暉','吳則禮','宋','宋诗','song-poetry','','[]','南宮先生晚爲郎，學語小兒說元章。',160,'全唐诗/poet.song.71000.json','["南宮先生晚爲郎，學語小兒說元章。", "屋下架屋安足數，突過鍾王妙如許。", "平生韻語何處有，瀾翻舊識論詩口。", "不落鈐鎚或自憎，舉似癡兒真敝帚。", "誰當料理晉馬曹，詎復酬答視愈高。", "憑君快寫拄板相，政應頰上加三毛。", "阿暉詎獨愛奇字，徑割全牛烹大胾。", "筆墨須論顧陸間，豈止遠過楊契丹。", "痿癯我作老摩詰，惟子堪任來問疾。", "是事且置默然坐，舌端種種一時墮。"]'),
('96e7af9c-b43f-4f1c-9b39-669d92eeac99','贈子發','吳則禮','宋','宋诗','song-poetry','','[]','金銅仙人辭漢歌，近時作者嗟誰何。',160,'全唐诗/poet.song.71000.json','["金銅仙人辭漢歌，近時作者嗟誰何。", "王侯之種合瑰詭，君復鼻高胸塊磊。", "著身丘壑謝幼輿，此事端憐卿輩無。", "口譚名理脚穿屐，手捉毛錐家四壁。", "平生三尺古錦嚢，掉頭不愛尚書郎。", "飽知得句要得眼，肯道挽弓須挽强。", "老夫天與覊臣骨，大笑癡兒曾咄咄。", "折牀舊喜存烏皮，渇釡初欣識黔突。", "未辦澆渠酒一尊，藜羮且可細論文。", "政思横說與豎說，莫廢本來微妙舌。"]'),
('aab6d4f1-99b7-4c35-9d5b-2e3b03c9143d','竹爐次韻','吳則禮','宋','宋诗','song-poetry','','[]','薫爐好妙非吾欲，古銅惟憐鼎三足。',64,'全唐诗/poet.song.71000.json','["薫爐好妙非吾欲，古銅惟憐鼎三足。", "手中一瓣非碌碌，傳語此君驚世俗。", "快燒篤耨置一牀，枕上齁齁氣味長。", "似是馬曹真未會，不喚此君聞妙香。"]'),
('f673a9f3-69b2-4879-8e69-9e703fcd53f1','又次竹枕韻','吳則禮','宋','宋诗','song-poetry','','[]','銜蟬慣惱平頭奴，遙取魚肉豐其膚。',128,'全唐诗/poet.song.71000.json','["銜蟬慣惱平頭奴，遙取魚肉豐其膚。", "胡爲掉尾懶相乳，化作青士形已枯。", "試拈支頭當陶瓦，不許卞璞登氍毹。", "猶能攫拏翻鼎無，踞視穿墉疑欲圖。", "涎流潑潑穿長蒲，夫人一笑呼與娱。", "摩挲初欲論夢事，有底耽耽而睢盱。", "偶從蠻藤落吳會，鄊縣直過青草湖。", "老夫得此良自稱，熟睡不管癡兒呼。"]'),
('c0cd6cec-82e7-407c-9d92-ba95fd4e94ab','已老','吳則禮','宋','宋诗','song-poetry','','[]','北湖居士端已老，後日懸知有老壊。',64,'全唐诗/poet.song.71000.json','["北湖居士端已老，後日懸知有老壊。", "此生何處辦庵糧，忽然老壊可復奈。", "不如罷讀瞿曇書，二時粥飯學予餬。", "都無筋力堪井臼，睡起飽聽鶬鶊呼。"]'),
('48b7d262-68ba-4078-ab2a-aa37c219734b','坰請作棗飲詩','吳則禮','宋','宋诗','song-poetry','','[]','阿坰自說棗飲法，請我試吟棗飲詩。',64,'全唐诗/poet.song.71000.json','["阿坰自說棗飲法，請我試吟棗飲詩。", "手提北湖折脚鼎，北湖見之已解頤。", "罌粟作腐杏成酪，來問白蘇儂飽知。", "他時携去尋衲子，通紅更撥騏驎兒。"]'),
('48754c02-1011-4c08-82d1-03254610abb2','即事','吳則禮','宋','宋诗','song-poetry','','[]','先生寧負虀鹽口，歲歲來沽春社酒。',64,'全唐诗/poet.song.71000.json','["先生寧負虀鹽口，歲歲來沽春社酒。", "好事晴鳩喚睡醒，與人穀穀論花柳。", "白頭强作懷抱寛，我曹未辦憎儒冠。", "不知無米知覓句，大似騎驢杜工部。"]'),
('6ed48772-f4b4-4c96-a420-112a2cc5c22f','寒食','吳則禮','宋','宋诗','song-poetry','','[]','正憎風雨暗炊熟，朝日似爲寒食晴。',64,'全唐诗/poet.song.71000.json','["正憎風雨暗炊熟，朝日似爲寒食晴。", "樹頭樹底作許好，舉揚春事憐音聲。", "聊呼上坐行飽飯，著處小立惟青青。", "更無花片近老眼，快遣鶬鶊來一鳴。"]'),
('367f739e-8814-487c-a4e6-f2119861798a','北湖飽飯徑寢頽然甘甚殆疇昔所未有也作此以示阿坰','吳則禮','宋','宋诗','song-poetry','','[]','讀書聊爾只欲眠，半世浪比邊孝先。',96,'全唐诗/poet.song.71000.json','["讀書聊爾只欲眠，半世浪比邊孝先。", "白頭來煮阿弓糜，偶然甘寢如許奇。", "醍醐酥乳無上味，方我飽眠方掩鼻。", "諸天種種妙伎樂，方我飽眠堪作惡。", "北湖久參真法器，老年端入睡三昧。", "齁齁休遣鶯喚醒，妙處只今兒輩聽。"]'),
('eb849135-d1a3-478b-a436-3741b414062b','已至都梁簡介然時介然欲至城北而食言','吳則禮','宋','宋诗','song-poetry','','[]','擊舟落尾端復佳，獨恐幽人費招喚。',64,'全唐诗/poet.song.71000.json','["擊舟落尾端復佳，獨恐幽人費招喚。", "老鼻行參宴坐香，晨炊飽喫連牀飯。", "巾邊白髪已星星，霜底黄華猶粲粲。", "從來一事大因緣，塔裏僧伽爲儂辦。"]'),
('9b61c803-80a0-47e5-b174-c90e940a958a','徐八聖猷碾茶有作因酬之','吳則禮','宋','宋诗','song-poetry','','[]','北湖老矣不事事，日割黄羊分大胾。',64,'全唐诗/poet.song.71000.json','["北湖老矣不事事，日割黄羊分大胾。", "底物堪澆塊磊胸，即今鬬焙惟高峰。", "邊頭那知見阿八，端笑吾人號癡絕。", "喚取阿八來細評，沙泉水甘似中𤃩。"]'),
('5b2789d4-c4bd-49a9-a067-83ddc58345dd','由刁園步至因勝求浴','吳則禮','宋','宋诗','song-poetry','','[]','鳥聲已迎一百五，野逕微行誰復嗔。',64,'全唐诗/poet.song.71000.json','["鳥聲已迎一百五，野逕微行誰復嗔。", "放飯要穿花底屐，捐書聊著頭上巾。", "老夫踽踽只白眼，爛蘂細細徒青春。", "憑仗石槽三昧水，浴茲從昔無垢人。"]'),
('e3c7545b-3ee9-4847-b7db-86650dfa6a22','有懷介然偶作因記之','吳則禮','宋','宋诗','song-poetry','','[]','介然平生三隻襪，意行跛跛復挈挈。',32,'全唐诗/poet.song.71000.json','["介然平生三隻襪，意行跛跛復挈挈。", "上堂懶把椎拂拏，却過淮來伴僧伽。"]'),
('4e87717a-91ec-48c0-834e-5864e14450f7','次韻林初心先輩  其一','吳則禮','宋','宋诗','song-poetry','','[]','太史滯周南，醇儒去廣川。',48,'全唐诗/poet.song.71000.json','["太史滯周南，醇儒去廣川。", "功名欺白髪，風雨送流年。", "故國悲歌裏，滄洲醉夢邊。", "平生心似鐵，相對肯凄然。"]'),
('d1e9ed2d-4914-4d9d-8fe9-d9b78f94e442','次韻林初心先輩  其二','吳則禮','宋','宋诗','song-poetry','','[]','倦客無人問，逢人祗自嗟。',48,'全唐诗/poet.song.71000.json','["倦客無人問，逢人祗自嗟。", "孤舟在江漢，老夢繞京華。", "聽雨閒扉掩，看雲短幘斜。", "固窮吾已定，莫向五侯家。"]'),
('d8beaaa3-7acd-4997-ae4b-5cd4176de497','登北樓','吳則禮','宋','宋诗','song-poetry','','[]','落景孤雲共，清商戍角和。',48,'全唐诗/poet.song.71000.json','["落景孤雲共，清商戍角和。", "蒼煙澹伊洛，白露濕關河。", "牧馬隨鴻鴈，行人掣駱駞。", "暮年餘習在，猶欲聽邊歌。"]'),
('a6c9cc91-f7de-40d3-9578-b0fa8ffe1991','曉角','吳則禮','宋','宋诗','song-poetry','','[]','曉角催行鼓，儒生也據鞍。',48,'全唐诗/poet.song.71000.json','["曉角催行鼓，儒生也據鞍。", "轅門天漢入，幕屋塞雲蟠。", "馳山一騎落，拔幟萬人觀。", "湖海鷗羣老，空餘子夏冠。"]'),
('8a97cc9a-1663-4c56-bc81-eb2523dbab50','陪劉仲馮登城樓','吳則禮','宋','宋诗','song-poetry','','[]','秋老歲忽晚，登臨清興賒。',48,'全唐诗/poet.song.71000.json','["秋老歲忽晚，登臨清興賒。", "孤鴻鳴宴几，落日在高牙。", "木脱戍樓寂，雲低寒水斜。", "扁舟與倦客，相望各天涯。"]'),
('dc3080f6-b8e6-4e4c-a905-01f506ac084c','神堂道中聽後騎短笛妙甚而花柳已有思澗流濺濺可喜','吳則禮','宋','宋诗','song-poetry','','[]','從來十八拍，笛裏更清新。',48,'全唐诗/poet.song.71000.json','["從來十八拍，笛裏更清新。", "著處是淺笑，可人惟晚春。", "末扳紅簌簌，且掲碧鱗鱗。", "小雨爲我止，鵓鴣長自馴。"]'),
('5467612b-c0f7-4f71-98c1-14c45e3600b5','謁陳尚志於太原之清凉','吳則禮','宋','宋诗','song-poetry','','[]','酒罇元有味，絕倒更能麽。',48,'全唐诗/poet.song.71000.json','["酒罇元有味，絕倒更能麽。", "昨夢不堪說，白頭無奈多。", "底時辭部曲，著處尚關河。", "相見好歡喜，當如遲暮何。"]'),
('09076348-b182-4526-86ec-305a80932b63','游昆羅山寺二首  其一','吳則禮','宋','宋诗','song-poetry','','[]','木落關河淡，天高更鴈翔。',48,'全唐诗/poet.song.71000.json','["木落關河淡，天高更鴈翔。", "凝笳亂流水，歸馬得斜陽。", "尊罍當白露，旗旆卷清商。", "山徑作許好，寒花渾欲黄。"]'),
('0d761d71-982f-4dab-a05c-378e5694ab57','游昆羅山寺二首  其二','吳則禮','宋','宋诗','song-poetry','','[]','據鞍風嫋嫋，横策水泠泠。',48,'全唐诗/poet.song.71000.json','["據鞍風嫋嫋，横策水泠泠。", "華屋聳雲谷，朱闌依翠屏。", "偶携千騎出，更爲九秋停。", "何必論黑月，歸途聊戴星。"]'),
('7436136c-a4b9-4fbc-a64f-0aedff290e87','吳山寺汛','吳則禮','宋','宋诗','song-poetry','','[]','空山無人境，汛掃寺兩廊。',48,'全唐诗/poet.song.71000.json','["空山無人境，汛掃寺兩廊。", "毎荷佛下榻，更蒙天與凉。", "沉瓜冷出井，澆汗暖注湯。", "落日下山去，好風如許長。"]'),
('346e174a-2c02-44f2-924f-8171ed3b559e','偶憩','吳則禮','宋','宋诗','song-poetry','','[]','繫馬後河川，可人冬景妍。',48,'全唐诗/poet.song.71000.json','["繫馬後河川，可人冬景妍。", "要看花到晚，付與水浮天。", "未覺隨戎馬，端來喚酒船。", "誰云是關塞，勝事總堪傳。"]'),
('05c1c636-6898-467e-ba2b-0ccbd19a4ac0','勸耕神堂快活林','吳則禮','宋','宋诗','song-poetry','','[]','凝笳作悲壯，細馬載嬋娟。',48,'全唐诗/poet.song.71000.json','["凝笳作悲壯，細馬載嬋娟。", "可是杏花晚，只教楊柳眠。", "酒醆漢旌底，清歌春雁邊。", "不須催部曲，聊欲酌寒泉。"]'),
('f971296f-a960-4c49-90fb-699219f78c63','和劉坰并簡楊虞卿','吳則禮','宋','宋诗','song-poetry','','[]','少日負書笈，老年看戰車。',48,'全唐诗/poet.song.71000.json','["少日負書笈，老年看戰車。", "此生渾覓句，隨處有烹茶。", "乞我炊黍米，煩君問蕨芽。", "斕斑赤銅椀，渠輩久名家。"]'),
('2665bf9c-cc8c-4862-b055-842a719f8a06','三堂道中寄公卷','吳則禮','宋','宋诗','song-poetry','','[]','久坐懶成癖，誰令老作魔。',48,'全唐诗/poet.song.71000.json','["久坐懶成癖，誰令老作魔。", "逢人說江海，著處是關河。", "隴底烽燧暗，海門鴻鴈多。", "西樓雲水白，猶奈酒樽麽。"]'),
('e040175d-d7eb-4e03-b71d-fb259f521556','寄曾公卷','吳則禮','宋','宋诗','song-poetry','','[]','作業定相似，懷君徒惋傷。',48,'全唐诗/poet.song.71000.json','["作業定相似，懷君徒惋傷。", "解包真有處，展鉢且隨方。", "月出淮天白，梅繁水國香。", "垂垂老工部，獨少贊公房。"]'),
('eedebd2d-083e-4324-8332-7655f7f2c029','同坰寄黄濟川五首  其一','吳則禮','宋','宋诗','song-poetry','','[]','飯飽團欒坐，前身或姓龐。',48,'全唐诗/poet.song.71000.json','["飯飽團欒坐，前身或姓龐。", "痴雲黏楚甸，小雪著荆江。", "尚要評詩律，何因喚酒缸。", "歸來底處好，脱屐弄艂艭。"]'),
('52e460b6-5bc4-437c-86bf-a268672ff7d2','同坰寄黄濟川五首  其二','吳則禮','宋','宋诗','song-poetry','','[]','平生黄卷裏，老罷白鷗邊。',48,'全唐诗/poet.song.71000.json','["平生黄卷裏，老罷白鷗邊。", "莫作驚人語，深參飽睡禪。", "隨堂姑一鉢，喚客或三鱣。", "寧要蘇司業，時時與酒錢。"]'),
('2a00b068-d079-4872-b055-194688290ada','同坰寄黄濟川五首  其三','吳則禮','宋','宋诗','song-poetry','','[]','今年一尺雪，大盎想春沽。',48,'全唐诗/poet.song.71000.json','["今年一尺雪，大盎想春沽。", "烏帽有何好，青鞋絕世無。", "老泓元有韻，瘦頴要時呼。", "跛跛沒伎倆，歸來真老盧。"]'),
('523044a4-d886-45a4-958a-adb1087bbf43','同坰寄黄濟川五首  其四','吳則禮','宋','宋诗','song-poetry','','[]','甘作華顛老，聊尋潁上梅。',48,'全唐诗/poet.song.71000.json','["甘作華顛老，聊尋潁上梅。", "長鬚喚舟檝，赤脚洗尊罍。", "白日要可挽，清香不受摧。", "若爲教騕褭，載得阿川來。"]'),
('2ce47c90-d35e-4054-98e1-4e19299c8c4c','同坰寄黄濟川五首  其五','吳則禮','宋','宋诗','song-poetry','','[]','齋盂隨處有，阿堵半生無。',48,'全唐诗/poet.song.71000.json','["齋盂隨處有，阿堵半生無。", "不作論文杜，姑爲踏磑盧。", "清言韻舌本，殘雪著頭顱。", "請說楚州菜，白菘如臂粗。"]'),
('b53ee28a-1ffa-46e8-93e9-0ec8bd00d09b','呈余清老','吳則禮','宋','宋诗','song-poetry','','[]','俛仰塞境斷，追隨春事幽。',48,'全唐诗/poet.song.71000.json','["俛仰塞境斷，追隨春事幽。", "碧山朝曳屐，白浪晚維舟。", "鐘鼓鳴江渚，煙雲暗郡樓。", "下簾煮新茗，聊爲道人留。"]'),
('69066ac8-5d6a-4280-9afd-d2895a6d5023','次李德充别劉長因韻','吳則禮','宋','宋诗','song-poetry','','[]','懸榻有妙致，脱冠論古情。',48,'全唐诗/poet.song.71000.json','["懸榻有妙致，脱冠論古情。", "羈愁一杯盡，好句萬人驚。", "談麈初未厭，檣烏俄小征。", "遙憐柁樓底，别夜月孤明。"]'),
('d262cefa-a46d-4ffd-9d5d-d8071fabb5e5','晚過元老','吳則禮','宋','宋诗','song-poetry','','[]','煮茗月纔上，觀棋興未央。',48,'全唐诗/poet.song.71000.json','["煮茗月纔上，觀棋興未央。", "綸巾墮清夜，羽扇委初凉。", "玉露飛蓮沼，銀河帯草堂。", "聊憑明浄几，那覺是他鄉。"]'),
('6765172e-f95e-49d8-9a95-f677af56cf39','出城道傍决明甚開可喜','吳則禮','宋','宋诗','song-poetry','','[]','籬落秋逾晚，鷄豚地更偏。',48,'全唐诗/poet.song.71000.json','["籬落秋逾晚，鷄豚地更偏。", "何時有蓬戶，無處著金錢。", "芒屨林邊石，茶鐺澗底泉。", "心知鴻鴈到，老子愛江天。"]'),
('ff70b718-f0cb-450d-9300-943d0bb1906e','不奈','吳則禮','宋','宋诗','song-poetry','','[]','不奈淮南熱，遙知秋可憐。',48,'全唐诗/poet.song.71000.json','["不奈淮南熱，遙知秋可憐。", "烏皮垂老事，白髪半生禪。", "井水從兒汲，茶鐺姑自煎。", "何時决明好，堂下晚鮮鮮。"]'),
('9ce5a737-360e-4457-8b00-6a4b87035b98','晚步','吳則禮','宋','宋诗','song-poetry','','[]','暮林帯斜日，隱隱聞疏鐘。',48,'全唐诗/poet.song.71000.json','["暮林帯斜日，隱隱聞疏鐘。", "息憊有孤石，扶衰憐短笻。", "垂楊暖自綠，春事老渾慵。", "正念余影獨，忽與幽鳥逢。"]'),
('1d8c7f6d-20a1-454e-b71c-eacbc7bc2e81','過静老','吳則禮','宋','宋诗','song-poetry','','[]','老夫無住相，大是箇中人。',48,'全唐诗/poet.song.71000.json','["老夫無住相，大是箇中人。", "聊作宰官相，偶名居士身。", "拍手與公笑，同牀憐我真。", "端來趁齋鼓，共坐不曾嗔。"]'),
('efc31152-6a91-4600-8e79-9c0145a66e3d','與曾公路呂少馮飲曾公卷舟中','吳則禮','宋','宋诗','song-poetry','','[]','百年久付一毫端，異縣追隨得自寛。',64,'全唐诗/poet.song.71000.json','["百年久付一毫端，異縣追隨得自寛。", "聲入浦雲歌扇麗，影浮江月酒罇寒。", "黄花窈窕且經眼，白髪蕭條初映冠。", "共倚檣竿竚歸鴈，西風嫋嫋露漙漙。"]'),
('d72ee36a-145a-4a2c-8833-d01962be4cfb','呈曾侯','吳則禮','宋','宋诗','song-poetry','','[]','滹沱流水抱城斜，旌節重來鬢欲華。',64,'全唐诗/poet.song.71000.json','["滹沱流水抱城斜，旌節重來鬢欲華。", "春雨一溪藏釣艇，秋風十里對荷花。", "銅符舊總山西將，鐵騎還吹塞北笳。", "魚蟹初肥稻粱熟，他時歸向楚人誇。"]'),
('cd975872-4e7e-4dde-be5b-90814b87b273','過智海呈陳無己','吳則禮','宋','宋诗','song-poetry','','[]','暫展經奩試茗芽，共憐日日困塵沙。',64,'全唐诗/poet.song.71000.json','["暫展經奩試茗芽，共憐日日困塵沙。", "木魚夢覺響晴景，鐵鳯雨餘翔落霞。", "漠漠清香縈暮竹，蕭蕭晏几近幽花。", "道人槌拂總無用，身世俱忘鬢已華。"]'),
('e4fd11fe-3234-4368-b5ae-3cfedd5d9b02','贈郭功父','吳則禮','宋','宋诗','song-poetry','','[]','兒童疇昔看揮毫，未覺雄辭愧廣騷。',64,'全唐诗/poet.song.71000.json','["兒童疇昔看揮毫，未覺雄辭愧廣騷。", "談塵縱横走雪電，詩壇磊落建麾旄。", "捐身魚鳥黄塵遠，隱几江湖白浪高。", "短褐婆娑弄明月，紛紛冔冕一鴻毛。"]'),
('52ef7a56-b555-4224-936f-8b3178b5fe8a','上元寄魯侯道輔時二公在真定','吳則禮','宋','宋诗','song-poetry','','[]','留連京洛未成歸，行及北潭花絮時。',64,'全唐诗/poet.song.71000.json','["留連京洛未成歸，行及北潭花絮時。", "樓外孤蟾吐華月，帳前小隊簇春旗。", "夜闌白雪回歌扇，舞徹紅燈照酒巵。", "更有風流峴山客，明珠百斛坐題詩。"]'),
('1bdc8b86-e9bc-48b2-b73b-9ca599b3adbe','懷彭志南因寄之','吳則禮','宋','宋诗','song-poetry','','[]','年光六馬去駸駸，末路漂流愧此心。',64,'全唐诗/poet.song.71000.json','["年光六馬去駸駸，末路漂流愧此心。", "玉佩金貂自鐘鼎，綸巾羽扇本山林。", "舟横落月梅花淡，鴈貼寒雲春水深。", "漠漠東風閉蓬戶，相思華髪忽盈簪。"]'),
('239d6515-1b64-40c3-a6c2-962aae79cc4d','和至之秋宴感懷時至之已有歸休意','吳則禮','宋','宋诗','song-poetry','','[]','紛紛舉世事輕肥，三徑蕭條獨可依。',64,'全唐诗/poet.song.71000.json','["紛紛舉世事輕肥，三徑蕭條獨可依。", "壯志未隨黄髪改，故山將伴白雲歸。", "林泉定落幽人手，塵土空侵病客衣。", "明月滿帆秋水碧，扁舟去逐鴈南飛。"]'),
('290b029b-ff69-49f3-961c-8218d1866246','勸耕神堂快活林','吳則禮','宋','宋诗','song-poetry','','[]','小雨尚復連清明，晴鳩撩我争喚晴。',64,'全唐诗/poet.song.71000.json','["小雨尚復連清明，晴鳩撩我争喚晴。", "餘寒不奈殘春酒，遲日初斜細柳營。", "黑貂强脱行作吏，白髪渾生來勸耕。", "樹底樹頭牽老眼，幾時喬木有鶯鳴。"]'),
('4f10a2b5-d47f-41e1-bf80-6e9a7bd81156','爲盧天驥作','吳則禮','宋','宋诗','song-poetry','','[]','撩我千巖固好在，未論應接徒惋欷。',64,'全唐诗/poet.song.71000.json','["撩我千巖固好在，未論應接徒惋欷。", "湖山飽窺使者節，魚鳥不避霜臺威。", "坐罷清言良亹亹，來朝爽氣殊霏霏。", "鷗羣非鬥舞不下，要略滄州如打圍。"]'),
('cb7fd4a4-fb43-473c-b540-9b1d61e3d1be','登城樓','吳則禮','宋','宋诗','song-poetry','','[]','河西諸將氣食牛，白羽雕弧錦臂韝。',64,'全唐诗/poet.song.71000.json','["河西諸將氣食牛，白羽雕弧錦臂韝。", "他日粥飯真衲子，莫年酒肉雜氈裘。", "坐上儒冠揮麈尾，帳前羌種看刀頭。", "吳檣楚柁自江海，聊復看雲倚戍樓。"]'),
('2fc4c7ee-89e2-4ed0-af4d-4381cb8c8712','送公桓行','吳則禮','宋','宋诗','song-poetry','','[]','汾河水落雁南飛，一馬蕭蕭木脱時。',64,'全唐诗/poet.song.71000.json','["汾河水落雁南飛，一馬蕭蕭木脱時。", "蒼鬢寧堪異鄉别，幽人况有故園悲。", "山頭日没邊笳斷，隴底駞鳴塞草衰。", "千里黄雲太行路，自憐北望獨相思。"]'),
('c8b94bd4-e39f-446e-912e-298f6256f26d','三堂書懷','吳則禮','宋','宋诗','song-poetry','','[]','青春已復作許妙，蜀錦輕覆千林殷。',64,'全唐诗/poet.song.71000.json','["青春已復作許妙，蜀錦輕覆千林殷。", "愧無好語贈秦嶺，猶想柁樓縈戍山。", "少日清尊兼白墮，暮年華髪與蒼顔。", "自憐飽作三堂夢，不在邊笳牧馬閒。"]'),
('a58eb873-4eaf-4d39-8541-8188a24dbf37','送王詩客莊依湖外使者','吳則禮','宋','宋诗','song-poetry','','[]','問舍求田話昔時，共憂南北未安枝。',64,'全唐诗/poet.song.71000.json','["問舍求田話昔時，共憂南北未安枝。", "青山笑我空成夢，白髪憐君苦作詩。", "風月誰教太瀟灑，功名自是小差池。", "要須附驥還金馬，晝錦歸來亦未遲。"]'),
('babec607-1ddb-48ae-9267-ddea4bd6d7ee','次毛澤民曾公卷韻','吳則禮','宋','宋诗','song-poetry','','[]','毛侯曾子有新句，鳴籟素秋相與清。',64,'全唐诗/poet.song.71000.json','["毛侯曾子有新句，鳴籟素秋相與清。", "我若邶鄘甘退舍，君如秦楚正連衡。", "一尊鴻鴈到時酒，萬里江湖别後情。", "魚目驪珠固非敵，搴旗况已慴先聲。"]'),
('13102f44-fbf5-4786-b0da-691875eb5a6e','銀城道中','吳則禮','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','疇昔一丘安在哉，馬鳴笳響有奇懷。',64,'全唐诗/poet.song.71000.json','["疇昔一丘安在哉，馬鳴笳響有奇懷。", "嬛嬛試遣鴈催發，濯濯已憑春喚回。", "獨憐短槊横未已，端恨長江扳不來。", "看取東風姹然笑，北湖老眼爲渠開。"]'),
('fe8e0cf6-8349-40a2-aa0e-220ddaebb4e5','送陳漕時權帥還自静州','吳則禮','宋','宋诗','song-poetry','','[]','漢節亭亭晻靄間，邦人多看錦鵰還。',64,'全唐诗/poet.song.71000.json','["漢節亭亭晻靄間，邦人多看錦鵰還。", "初傳使者驅千騎，俄見將軍定百蠻。", "雲盡月光依組練，雪消春信滿湖山。", "佇聞禁掖催頗牧，玉陛歸親咫尺顔。"]'),
('b9b5f81b-322a-4d80-b7a5-96796ed11ef8','至龜山先寄呂少馮','吳則禮','宋','宋诗','song-poetry','','[]','出舟跛跛爲情親，催遣籃輿煩故人。',64,'全唐诗/poet.song.71000.json','["出舟跛跛爲情親，催遣籃輿煩故人。", "九死僅全真去楚，百年未了更游秦。", "晨炊要索祖仁飯，老鬢舊著淵明巾。", "傳語淮山元好在，初捐一笑與覉臣。"]'),
('ec00fbca-51a4-4a01-8d0b-a956dcc8717d','入汴先寄韓子蒼','吳則禮','宋','宋诗','song-poetry','','[]','軟煮芋魁初不饑，天教吐出胸中奇。',64,'全唐诗/poet.song.71000.json','["軟煮芋魁初不饑，天教吐出胸中奇。", "追隨且褁子輿飯，持似只有香巖錐。", "刺船迎客菊笑處，覓句懷人霜落時。", "我輩阿馮真解事，與儂細舉南山詩。"]'),
('1e5edd6f-bd09-4f92-961d-326ca6ee91f8','寄呂少馮時余單騎入都將發楚','吳則禮','宋','宋诗','song-poetry','','[]','老夫得酒有何好，且飲中秋白露團。',64,'全唐诗/poet.song.71000.json','["老夫得酒有何好，且飲中秋白露團。", "已戒奴人送斗米，更呼友生共盤飱。", "坐談稍覺佳月出，起舞不知清夜寒。", "明發垂垂向梁宋，軒然禿髪映儒冠。"]'),
('4ef2cd6b-f95f-418a-88a8-deec81e2d6af','寄黄濟川','吳則禮','宋','宋诗','song-poetry','','[]','一片桃花有底急，咬咬已復韻春懷。',64,'全唐诗/poet.song.71000.json','["一片桃花有底急，咬咬已復韻春懷。", "痿羸不覺楊花罷，欵久忽然蝴蝶來。", "如許快人帆腹飽，絕如撩我浪頭開。", "異時古錦囊中事，回首赤狐安在哉。"]'),
('f509a58c-1923-4672-9e20-32921328f306','寄相之并示坰','吳則禮','宋','宋诗','song-poetry','','[]','一飲一石陶靖節，誰言此理可消憂。',64,'全唐诗/poet.song.71000.json','["一飲一石陶靖節，誰言此理可消憂。", "飽知渭北黄花酒，不似淮南白鴈秋。", "快解檣竿倒檣尾，要鳴船鼓轉船頭。", "魏郎宿昔要覓句，有語定能撩阿游。"]'),
('4555b0d6-62bc-4706-9a30-b592c6310651','至洪澤寄呂少馮介然','吳則禮','宋','宋诗','song-poetry','','[]','來往都梁真有期，瘦藤挈挈要追隨。',64,'全唐诗/poet.song.71000.json','["來往都梁真有期，瘦藤挈挈要追隨。", "獨憐老子蒙頭睡，不見梅花如雪時。", "經爐飽附僧伽火，齋鉢長分庾氏糜。", "歲暮東窗好晴日，傳聲阿遁正相思。"]'),
('c494695d-0a83-4196-8d82-480030fe8d75','離朱方寄懷子和','吳則禮','宋','宋诗','song-poetry','','[]','南國誰云貴公子，肯共野人葵莧盤。',64,'全唐诗/poet.song.71000.json','["南國誰云貴公子，肯共野人葵莧盤。", "獨許二毛有句眼，仍憐九死坐儒冠。", "自知胸次丘壑在，敢負海門天水寛。", "後夜淮南一杯酒，白頭付與菊花團。"]'),
('37500c36-ecc9-45e4-b116-a3c043ac7af9','發陳留寄智夫姪','吳則禮','宋','宋诗','song-poetry','','[]','五斗莫作糴太倉，幽事關人殊未央。',64,'全唐诗/poet.song.71000.json','["五斗莫作糴太倉，幽事關人殊未央。", "白鴈撩人下清洛，黄花喚夢著都梁。", "平生浪喜得詩瘦，投老相從要酒狂。", "欲到淮南先一笑，蟹螯渾已飽新霜。"]'),
('eddf8a14-253b-49a2-ab0d-77aa761dd480','泛汴寄清姪','吳則禮','宋','宋诗','song-poetry','','[]','莫咤别愁關老鬢，且論幽討入奇懷。',64,'全唐诗/poet.song.71000.json','["莫咤别愁關老鬢，且論幽討入奇懷。", "忽思白魚淮海去，付與清秋鴻鴈來。", "不爲督郵聊轉柁，要呼從事試登臺。", "老夫正想西風笛，江北江南安在哉。"]'),
('974d25e2-2241-411b-8d87-1e9992c3dd73','到朱方寄智夫智夫時爲戶部官','吳則禮','宋','宋诗','song-poetry','','[]','逐客藜糝大官羊，蓬廬畫省遙相望。',64,'全唐诗/poet.song.71000.json','["逐客藜糝大官羊，蓬廬畫省遙相望。", "囊中錐處吾罷矣，地上錢流君未央。", "一身投老雞豚社，百戰平生翰墨塲。", "拍拍水天高著眼，海門乞與雁隨陽。"]'),
('2d86c540-2394-4c09-b962-63492bd2062a','寄題紀信廟','吳則禮','宋','宋诗','song-poetry','','[]','貌齊隆凖伏危機，辦爲君王解急圍。',64,'全唐诗/poet.song.71000.json','["貌齊隆凖伏危機，辦爲君王解急圍。", "楚炬無情燎黄屋，晉城有土瘞遺衣。", "功名不與山河誓，義烈終同日月輝。", "新廟落成牲醴盛，千年魂魄想依依。"]'),
('8e9cd593-2a80-4c74-815a-d8fdf7818d08','歸自河西泛舟東下示坰','吳則禮','宋','宋诗','song-poetry','','[]','露濕船篷今夜凉，秋風端已灑衣裳。',64,'全唐诗/poet.song.71000.json','["露濕船篷今夜凉，秋風端已灑衣裳。", "漸炊大甑長腰米，共說平生細肋羊。", "試問錦貂看射虎，何如烏几聽鳴桹。", "真須快捉蟹螯去，處處休吟古戰場。"]'),
('5a0a6ae2-e975-434a-adf8-c109f49d895d','簡田升之時升之赴金陵','吳則禮','宋','宋诗','song-poetry','','[]','建業風流端可憐，石城江色曉鮮鮮。',64,'全唐诗/poet.song.71000.json','["建業風流端可憐，石城江色曉鮮鮮。", "鳥窺漢節梅花底，雨濕柁樓春水邊。", "霜髪讐書有東觀，錦囊覓句屬南天。", "枯腸不飽大官肉，我種芋魁今十年。"]'),
('3b1d328b-5456-4685-8183-217edf1f8369','發金陵','吳則禮','宋','宋诗','song-poetry','','[]','湖海歸來近釣筒，此身南北一飄蓬。',64,'全唐诗/poet.song.71000.json','["湖海歸來近釣筒，此身南北一飄蓬。", "船頭已壓三山浪，檣尾初回五雨風。", "天淡鼓聲催落日，雲高帆影趁飛鴻。", "道林窣堵自崷崒，隱几寒光連暮空。"]'),
('64df10cc-0c7a-464a-b90f-131ad4cb1929','劉明適屢欲子蒼過其居小酌以詩招之','吳則禮','宋','宋诗','song-poetry','','[]','吐心著地誰復識，只有平生韓子蒼。',64,'全唐诗/poet.song.71000.json','["吐心著地誰復識，只有平生韓子蒼。", "端恨茅屋付秋草，試吟玉繩低建章。", "枯腸君飽大官肉，秃鬢我老尚書郎。", "愛酒不論天下士，快來脱帽持一觴。"]'),
('a3a73db2-aeea-466a-9301-90e32154de47','寄魏道輔','吳則禮','宋','宋诗','song-poetry','','[]','漠漠長煙暝戍樓，登臨永日强消憂。',64,'全唐诗/poet.song.71000.json','["漠漠長煙暝戍樓，登臨永日强消憂。", "殊方日落青山暮，舊國雲深碧樹秋。", "向老江湖雙病眼，此身天地一浮鷗。", "高談早晚對犀麈，衮衮遙憐湘漢流。"]'),
('dcd0801e-3ada-4440-8534-c64dcab899a6','和魏道輔銅雀硯','吳則禮','宋','宋诗','song-poetry','','[]','寂寞漳河遶故宮，悠悠千古付飛蓬。',64,'全唐诗/poet.song.71000.json','["寂寞漳河遶故宮，悠悠千古付飛蓬。", "當時流落干戈際，今日埋藏塵土中。", "楚岫月明芒屩遠，湘江春盡草堂空。", "提携願逐先生去，閒詠灘頭一笛風。"]'),
('e235d708-32e0-47ee-bfb7-1e1ff3a01b72','次李漢臣韻漢臣有超然絕棄百事深入祖門之意而語與予合','吳則禮','宋','宋诗','song-poetry','','[]','禪版蒲團俱似誰，電光石火竟奚爲。',64,'全唐诗/poet.song.71000.json','["禪版蒲團俱似誰，電光石火竟奚爲。", "儻能徑作白鼻去，未信只教黄面知。", "柁樓故略鳬鴈海，月魄端護兼葭池。", "一語休論偶相契，粗言且擬寒山詩。"]'),
('ace40578-e5fe-4451-a8b1-ec2ede515bd6','黄伯鈞示詩因次韻','吳則禮','宋','宋诗','song-poetry','','[]','鬢毛蕭瑟强儒冠，塵土追隨意已闌。',64,'全唐诗/poet.song.71000.json','["鬢毛蕭瑟强儒冠，塵土追隨意已闌。", "午枕夢回書帙亂，暮林秋老雨聲寒。", "百骸久悟歲月速，一室詎知天地寛。", "忽憶玉虹孤笛夜，曲肱終約聽鳴湍。"]'),
('1b588000-d9b2-4ff1-ba98-1456e82f4725','簡翟密州','吳則禮','宋','宋诗','song-poetry','','[]','酒杯到手慎莫停，江月已復連疏星。',64,'全唐诗/poet.song.71000.json','["酒杯到手慎莫停，江月已復連疏星。", "豈謂灌園三徑老，來逢横槊萬人英。", "飛花不作我鬢白，韻語政如公眼青。", "宿昔瀾翻說詩口，真慚肯與醉時聽。"]'),
('91598dd6-e660-4c9b-9044-6b9094858b99','簡呂少馮','吳則禮','宋','宋诗','song-poetry','','[]','此生不說老婆禪，兀兀坐睡忘永嘆。',64,'全唐诗/poet.song.71000.json','["此生不說老婆禪，兀兀坐睡忘永嘆。", "要聽車聲出銅鼎，故教鼻竅吼蒲團。", "淮山宿昔面目好，葵藿從來骨相寒。", "白髪軒然同一笑，未嫌跛跛著南冠。"]'),
('a79a0c18-29d0-419e-82b2-7d6387e347b0','簡子蒼','吳則禮','宋','宋诗','song-poetry','','[]','底時待詔辭公車，疇昔胸中著異書。',64,'全唐诗/poet.song.71000.json','["底時待詔辭公車，疇昔胸中著異書。", "端愧騎鯨老正字，會尋覓句舊題輿。", "春殘詎有花經眼，夢罷試教鶯喚雛。", "徑欲追隨說情話，即今猶奈酒尊無。"]'),
('7a32135e-e0ce-4913-a252-cf736da0f561','簡蔡天任','吳則禮','宋','宋诗','song-poetry','','[]','天公與此强健身，故遣雨洗南徐春。',64,'全唐诗/poet.song.71000.json','["天公與此强健身，故遣雨洗南徐春。", "梅柳暮年經老眼，江湖疇昔著羈臣。", "要穿遙集脚底屐，不負淵明頭上巾。", "頗欲扶笻說幽事，漫郎端肯恕醉人。"]'),
('f663c05c-46ca-4c4c-812b-ecdcfe66f0ff','閒居','吳則禮','宋','宋诗','song-poetry','','[]','自斷餘生更不疑，三間茅屋大江垂。',64,'全唐诗/poet.song.71000.json','["自斷餘生更不疑，三間茅屋大江垂。", "會降前代李長吉，只有後身韓退之。", "羣羊正飽官厨肉，野飯寧忘環堵葵。", "能事阿穰今落寞，何人便捉畫沙錐。"]'),
('56cad082-dd1b-44da-8d89-88afc0383298','同澄之器博飯浮玉','吳則禮','宋','宋诗','song-poetry','','[]','疇昔清都步武聯，軒軒鶴骨稱癯仙。',64,'全唐诗/poet.song.71000.json','["疇昔清都步武聯，軒軒鶴骨稱癯仙。", "君横七弦可忘老，我得一丘端盡年。", "白首終成裹飯去，青燈更作曲肱眠。", "步虚聲裏雲旗下，病眼心知有勝緣。"]'),
('cb20a238-72a8-4e5e-9ced-634bc6a4ddb1','舟行對菊寄智夫姪','吳則禮','宋','宋诗','song-poetry','','[]','洛水微寒澹晚秋，從教風雨打船頭。',64,'全唐诗/poet.song.71000.json','["洛水微寒澹晚秋，從教風雨打船頭。", "莫嗔宿昔愛霜菊，可是平生怕督郵。", "未辦作詩論句法，且當貰酒消人憂。", "白眉清眼見小阮，共卧淮山百尺樓。"]'),
('4e161ecb-0a89-469b-874f-d87f8eaaf8a3','元日呈王長元次元關聖功','吳則禮','宋','宋诗','song-poetry','','[]','是身久付一蒲團，半世讀書真畫墁。',64,'全唐诗/poet.song.71000.json','["是身久付一蒲團，半世讀書真畫墁。", "喚取平生三語掾，來分投老五辛盤。", "猶堪白墮樽邊笑，端奈紅梅花底寒。", "莫問侏儒飽欲死，從教霜雪映南冠。"]'),
('a0bc1526-fd71-4239-a769-9a6f5aed6892','送子仁兄赴定武倅','吳則禮','宋','宋诗','song-poetry','','[]','杳杳東風吹雁行，淡煙疏柳暗河梁。',64,'全唐诗/poet.song.71000.json','["杳杳東風吹雁行，淡煙疏柳暗河梁。", "邊笳忽起暮天遠，塞鴈不鳴春草長。", "野館夢回花似霰，戍樓詩就月如霜。", "應憐投老尚漂泊，白鳥青山堪斷腸。"]'),
('43ba71e0-6c6c-450f-b32b-33358566e3a0','新亭梅偶作','吳則禮','宋','宋诗','song-poetry','','[]','衡門宿昔只棲遲，慚愧三堂春事奇。',64,'全唐诗/poet.song.71000.json','["衡門宿昔只棲遲，慚愧三堂春事奇。", "爲有叢筠傍流水，故教疏影作横枝。", "香羅未辦凌波去，素魄休論啼鴂時。", "乞與江南風格在，鼻端聊遣廣文知。"]'),
('f73d63b0-535a-4612-bf5c-3ce6105641f2','至青陽先寄韓子蒼','吳則禮','宋','宋诗','song-poetry','','[]','秃髪羈臣百不憂，樹頭樹底鳴栗留。',64,'全唐诗/poet.song.71000.json','["秃髪羈臣百不憂，樹頭樹底鳴栗留。", "遊方便具屈宋眼，出世真成陶謝流。", "著冠來糴太倉米，捩柁故轉長淮舟。", "莫問銅錢恰三百，澆腸一斗與君謀。"]'),
('8c67d551-2d9a-4ccc-b654-0b7cd2bd8ace','至楚懷慎漢公','吳則禮','宋','宋诗','song-poetry','','[]','抱甕何許欲灌園，獨憐帆腹會孤掀。',64,'全唐诗/poet.song.71000.json','["抱甕何許欲灌園，獨憐帆腹會孤掀。", "雙輪有蒲良未好，束帛加璧安足論。", "少日讀書守貧巷，異時簪茟登修門。", "相思徒吟老駞句，不見君來欲斷魂。"]'),
('c6d2004d-6243-431d-9346-0f9750282e4f','夢過盱眙城追寄普照老','吳則禮','宋','宋诗','song-poetry','','[]','篷背有霜篷底眠，夢中猶念草鞋錢。',64,'全唐诗/poet.song.71000.json','["篷背有霜篷底眠，夢中猶念草鞋錢。", "强炊五斗官倉米，也趁千艘落水船。", "居士禿巾撩楚鴈，僧伽孤塔供淮天。", "盱眙城在石色古，浪打至今端可憐。"]'),
('0447b957-b72b-4990-9a01-440248006963','奉酬漢臣見簡之什','吳則禮','宋','宋诗','song-poetry','','[]','手捉長藤懶坐禪，起行飽飯且欹冠。',64,'全唐诗/poet.song.71000.json','["手捉長藤懶坐禪，起行飽飯且欹冠。", "稍憐臘後霜畦色，已落春前湯餅盤。", "快過鄰墻無量酒，可奈淮楚如許寒。", "一樹梅花合催發，垂垂要遣腐儒看。"]'),
('ed916331-b492-44ab-bd44-a143b01ae89b','放船先寄普照老夷白','吳則禮','宋','宋诗','song-poetry','','[]','柁樓澹沲冬日斜，半世三鍾并五車。',64,'全唐诗/poet.song.71000.json','["柁樓澹沲冬日斜，半世三鍾并五車。", "處處談禪作居士，年年行脚見僧伽。", "偶然摩腹船鳴鼓，聊復捐書雁聚沙。", "先遣毛錐交說似，即今鏡裏有霜華。"]'),
('cf3d6b8d-c64f-48d6-a7cc-f02c022e24a9','寄因勝觀老','吳則禮','宋','宋诗','song-poetry','','[]','秋晚銅爐一炷香，人間餘習未全忘。',64,'全唐诗/poet.song.71000.json','["秋晚銅爐一炷香，人間餘習未全忘。", "雲溪尚想穿幽屐，雪屋猶憐共折牀。", "山林投老成漂轉，文字他時妄揣量。", "憔悴少陵空白髪，敢期重賦贊公房。"]'),
('b157465a-b458-48dd-a913-d1a3f9148175','有懷介然偶作因寄之','吳則禮','宋','宋诗','song-poetry','','[]','此生端與衲僧期，折脚茶鐺能解頤。',64,'全唐诗/poet.song.71000.json','["此生端與衲僧期，折脚茶鐺能解頤。", "君對幽人洗銀轂，我書春事有毛錐。", "喚醒飽睡真痴絕，驚倒羣兒要語奇。", "想爲梅花從定出，横擔拄杖傍疏籬。"]'),
('af41dc8c-613d-42ca-993d-fa0be5a8c5db','題沙泉鵲梨古柳','吳則禮','宋','宋诗','song-poetry','','[]','莫遣殊方一片飛，風光有底肯相遺。',64,'全唐诗/poet.song.71000.json','["莫遣殊方一片飛，風光有底肯相遺。", "含愁要作紅雨去，絕恨獨眠清晝時。", "古井猶窺光燦燦，儒冠不道鬢垂垂。", "鳥歌長日偏稱意，辦得喚人來朵頤。"]'),
('872b3535-daef-46eb-95c4-a422b3b89ebf','懷子蒼','吳則禮','宋','宋诗','song-poetry','','[]','爛爛白眼安在哉，只今懷抱向誰開。',64,'全唐诗/poet.song.71000.json','["爛爛白眼安在哉，只今懷抱向誰開。", "端知脊梁只似鐵，想見舌本長如雷。", "茅屋關心句突兀，藜羮不糝胸崔嵬。", "江頭日日望好語，有底都無驛使來。"]'),
('14a4c28f-7ebe-441c-8f43-53d906df4976','懷關聖功','吳則禮','宋','宋诗','song-poetry','','[]','破除午夢晴鳥呼，起喚奴人轉轆轤。',64,'全唐诗/poet.song.71000.json','["破除午夢晴鳥呼，起喚奴人轉轆轤。", "半世奇奇兼怪怪，一春白白與朱朱。", "生憎張儀舌尚在，大笑香巖錐也無。", "矻矻休論抱關事，快來相對說江湖。"]'),
('04fd7a59-91d6-4929-9621-ebb24b6a371a','性之以團茶贈行並遺新詩因次其韻','吳則禮','宋','宋诗','song-poetry','','[]','年年御焙試春風，白玉宮人拆絳封。',64,'全唐诗/poet.song.71000.json','["年年御焙試春風，白玉宮人拆絳封。", "疇昔饑腸知脱粟，即今老眼見翔龍。", "笑持俊逸無雙句，去上東南第一峰。", "却倚柁樓搔短髪，回頭青闕五雲濃。"]'),
('566a13f2-8222-49ae-8de4-9dff472bbcfa','寄甘露傳祖宣老二首  其一','吳則禮','宋','宋诗','song-poetry','','[]','千秋北固舊知名，想見禪房掩晝扃。',64,'全唐诗/poet.song.71000.json','["千秋北固舊知名，想見禪房掩晝扃。", "坐上休論失匕筯，定中那復駭雷霆。", "圖書遮榻青燈暗，鐘鼓喧江白浪腥。", "天外樓臺近浮玉，與誰飛錫過南𤃩。"]'),
('a632ab53-2c78-4fc4-a816-6db5541b3a27','寄甘露傳祖宣老二首  其二','吳則禮','宋','宋诗','song-poetry','','[]','鐵塔亭亭石徑斜，參差樓殿倚青霞。',64,'全唐诗/poet.song.71000.json','["鐵塔亭亭石徑斜，參差樓殿倚青霞。", "秋江曾試中𤃩水，春焙仍分北苑芽。", "隱几飛帆過别浦，翻經孤雁起寒沙。", "禪龕坐隔幾千里，想見煙雲亂雨花。"]'),
('0e26d510-f649-4586-becf-262b1d7bddba','送純師赴黄檗用李師顔韻','吳則禮','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','沙尾潮生浪影微，東風洲渚蕨芽肥。',64,'全唐诗/poet.song.71000.json','["沙尾潮生浪影微，東風洲渚蕨芽肥。", "西江水借銅缾潤，北闕雲隨錫杖飛。", "日煖鳬鷖迎宴几，春深花絮護禪衣。", "遙知一榻諸天外，歸夢時時近紫闈。"]'),
('de158c2b-3476-43e3-8084-65dc80dc6df3','同曾公卷出南城','吳則禮','宋','宋诗','song-poetry','','[]','著處籃輿得小停，偶尋奇詭對屏星。',64,'全唐诗/poet.song.71000.json','["著處籃輿得小停，偶尋奇詭對屏星。", "山南山北有幽囀，樹底樹頭惟落英。", "兩鬢已脱吾種種，三眠欲罷渠青青。", "招提故作疏鐘晚，更約杖藜來細聽。"]'),
('aa6a900a-925b-4349-895f-91a46c795549','遷居','吳則禮','宋','宋诗','song-poetry','','[]','久傍修門乏壯圖，侵尋華髪欲捐書。',64,'全唐诗/poet.song.71000.json','["久傍修門乏壯圖，侵尋華髪欲捐書。", "貂裘平日敝塵土，茅屋晚歲依江湖。", "落落青天月上後，蕭蕭紅葉鴈來初。", "故人載酒端好事，遣我陶然忘舊廬。"]'),
('d33aadce-83db-493d-95c4-b1f8bf324c57','携家遊南山','吳則禮','宋','宋诗','song-poetry','','[]','都梁山色楊柳青，天乞羈臣如許情。',64,'全唐诗/poet.song.71000.json','["都梁山色楊柳青，天乞羈臣如許情。", "不嫌野褐垂垂老，故作春風踽踽行。", "幽花傍水有孤笑，好鳥隨人時一鳴。", "晚飯招提且僧鉢，關心七尺瘦藤輕。"]'),
('a30e80af-f933-40da-955b-7033fb63c553','次坰尋春韻','吳則禮','宋','宋诗','song-poetry','','[]','攀翻聊復得晴景，抖擻貂裘季子塵。',64,'全唐诗/poet.song.71000.json','["攀翻聊復得晴景，抖擻貂裘季子塵。", "豈有好事來載酒，獨憐幽鳥解喚人。", "二毛衰晚端不恨，五鼎宿昔元未珍。", "剩把小紅娱老眼，他時細說淮南春。"]'),
('b7f8dd77-34fb-49ea-af5a-8ec2b32e98ee','次周開祖遊鶴林韻','吳則禮','宋','宋诗','song-poetry','','[]','消渇茂陵端倦遊，穿雲踏石良未休。',64,'全唐诗/poet.song.71000.json','["消渇茂陵端倦遊，穿雲踏石良未休。", "諸天辦供林谷曉，一寺鳴鐘江海秋。", "吾曹大是許詢輩，道人豈非支遁流。", "莫因妻兒要歸去，杖藜聊爲茶鐺留。"]'),
('54867bb5-9b36-4e43-83da-ea50903c0e52','客有自南徐來者云紅梅已開作此','吳則禮','宋','宋诗','song-poetry','','[]','十日天寒守圭竇，今朝對客何佳哉。',64,'全唐诗/poet.song.71000.json','["十日天寒守圭竇，今朝對客何佳哉。", "春催江上紅梅發，雪喚淮南青子來。", "從兒作相論句法，乞我澆饞持酒杯。", "半世儒冠今種種，端須拽取鼻頭回。"]'),
('a76764b8-a99c-459b-a141-24eeb53cbd86','和人梅詩','吳則禮','宋','宋诗','song-poetry','','[]','玉妃從以萬玉女，正倚廣寒琪樹柯。',64,'全唐诗/poet.song.71000.json','["玉妃從以萬玉女，正倚廣寒琪樹柯。", "端憐横笛隴頭罷，不恨落梅江上多。", "翠袖清尊知老矣，薫爐茗椀奈儂何。", "夢驚篷背遽如許，會喚陽春有豔歌。"]'),
('ef03c520-3292-45ae-a5d8-070198a0d229','懷春','吳則禮','宋','宋诗','song-poetry','','[]','青春已辭淮水湄，底物遺我堪解頤。',64,'全唐诗/poet.song.71000.json','["青春已辭淮水湄，底物遺我堪解頤。", "風味不除惟白墮，典刑猶在有黄鸝。", "老夫只覺禪坐好，兒輩争論句法奇。", "到處何曾問炊米，半生人笑北湖癡。"]'),
('02e335c7-8f81-426c-92c5-2822cad20089','同聖功南園探春','吳則禮','宋','宋诗','song-poetry','','[]','春風如許可復奈，扶藜與子一笑懷。',64,'全唐诗/poet.song.71000.json','["春風如許可復奈，扶藜與子一笑懷。", "初緣晴日垂垂發，更爲吾人細細開。", "莫憎白眼校尉老，快喚青州從事來。", "徑欲尋君說幽意，夕陽故挽一枝回。"]'),
('4033c9f8-4741-4cf0-9734-b4ff1e14208d','識舟亭','吳則禮','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','飽聞會稽道中好，未似隱几來歸舟。',64,'全唐诗/poet.song.71000.json','["飽聞會稽道中好，未似隱几來歸舟。", "衰鬢猶堪扶檻笑，長江故作拍天流。", "知容遙集幾兩屐，絕勝元龍百尺樓。", "時換薫爐辦幽事，孤鴻落處有汀洲。"]'),
('2aaf2c80-4eb2-4f9b-b3e6-42f35f9af875','携茶過智海','吳則禮','宋','宋诗','song-poetry','','[]','牀頭白羽已相親，茗椀才嘗正焙新。',64,'全唐诗/poet.song.71000.json','["牀頭白羽已相親，茗椀才嘗正焙新。", "透出老禪三昧眼，喚醒逋客二毛身。", "坐聞考考赴堂鼓，起覓垂垂洗鉢人。", "稍有黄鸝來舉似，似憐老子獨知真。"]'),
('62e45579-1dbb-4b9d-9978-b555895a3f98','赴大舟投老齋','吳則禮','宋','宋诗','song-poetry','','[]','枕邊夢事忽蘧蘧，起着青鞋喚竹輿。',64,'全唐诗/poet.song.71000.json','["枕邊夢事忽蘧蘧，起着青鞋喚竹輿。", "投老惟堪聽齋鼓，此生端愧坐儒書。", "十年枵腹猶堪在，一鉢連床便有餘。", "驀直從來大舟路，横擔拄杖正憐渠。"]'),
('9a762fd9-25b1-4225-a7b7-f02835bdb126','宣老示寂有懷','吳則禮','宋','宋诗','song-poetry','','[]','暮年流落偶相親，握臂難忘一語真。',64,'全唐诗/poet.song.71000.json','["暮年流落偶相親，握臂難忘一語真。", "茗椀齋盂成昨夢，蒲團禪板記前身。", "塵埃雲衲翛翛敝，歲月霜毛種種新。", "遊戲諸天無復返，自嗟青眼更何人。"]'),
('0b7333ee-b244-44e9-8bfe-fabd7d0a3e95','同王子和過張氏小園','吳則禮','宋','宋诗','song-poetry','','[]','永夏追凉得午陰，扶藜仍有小叢林。',64,'全唐诗/poet.song.71000.json','["永夏追凉得午陰，扶藜仍有小叢林。", "應憐老子腰脚健，可是禪房花木深。", "卷簾高竹與佳色，隱几黄鸝供好音。", "更遣驚人十様錦，并澆宿昔江湖心。"]'),
('682dfa21-c701-40d7-a47e-73ec3be8c015','書事  其一','吳則禮','宋','宋诗','song-poetry','','[]','小雨渾晴不作泥，老年澆舌要如飴。',64,'全唐诗/poet.song.71000.json','["小雨渾晴不作泥，老年澆舌要如飴。", "應憐長日只麽過，故遣飛英如許奇。", "澗底涓涓催着屐，屋頭聒聒喚支頤。", "孰云烏几獨少味，看盡朱朱白白時。"]'),
('b1e7deae-755f-41d0-8719-f11c1b548b62','書事  其二','吳則禮','宋','宋诗','song-poetry','','[]','溪北溪南梅樹枝，斬新華蕚出疏籬。',64,'全唐诗/poet.song.71000.json','["溪北溪南梅樹枝，斬新華蕚出疏籬。", "獨憐醉處錦成幄，端恨愁時雪打圍。", "老夫不奈羽觴急，幽討未辜春日遲。", "慚愧鄰翁會人意，殺鷄炊黍要追隨。"]'),
('56db1bde-f8f8-4495-9336-42cc56e7b197','寄江仲嘉','吳則禮','宋','宋诗','song-poetry','','[]','憶昨南宮戰，鶱騰實妙年。',288,'全唐诗/poet.song.71000.json','["憶昨南宮戰，鶱騰實妙年。", "操戈萬人廢，受鎧百城連。", "器敵南溟大，姿逾白璧堅。", "一官聊負弩，四部合磨鉛。", "取友何蕃俊，論交鮑叔賢。", "未聆歌出谷，俄忽愧沉淵。", "識字今奚補，能詩昔謾傳。", "且酬持釣手，那問買山錢。", "軒冕亦姑爾，林泉寧偶然。", "鳴蛙當鼓吹，短褐等貂蟬。", "蹭蹬甘垂翅，虺尵罷著鞭。", "紉蘭徒自好，懷瑾復誰憐。", "末路成悲咤，微軀任棄捐。", "塵埃避烏几，香火付華顛。", "泫露滋籬槿，飛霜墮渚蓮。", "幽畦方寂歷，寒蝶正便嬛。", "揮麈晚洲外，騎鯨高浪前。", "尚思終夜語，獨想對牀眠。", "鴈逝聞號月，漁歸覺扣舷。", "劇談容促膝，痛飲或差肩。", "江闊尊罍净，樓空雲水鮮。", "解衣尋窈窕，脱足弄潺湲。", "柁轉峰巒碎，帆收橘柚圓。", "捫蘿且扶憊，曳策毎争先。"]'),
('405de507-1e8d-4adb-b5ef-d598626750c4','白髪','吳則禮','宋','宋诗','song-poetry','','[]','白髪不奈短，青春何太奇。',96,'全唐诗/poet.song.71000.json','["白髪不奈短，青春何太奇。", "酒尊花雨後，茶鼎柳綿時。", "痩莧枯腸慣，清香老鼻知。", "胡牀元自穩，羽扇未應遲。", "情話要可紀，吾人真自癡。", "且揮孫氏麈，更費阿弓麋。", "稍覺燕迎社，莫嗔鶯哺兒。", "老夫行去國，船掠漲淮湄。"]'),
('ca083ac8-131e-414d-89fc-4906694d55fa','憶昨呈元老','吳則禮','宋','宋诗','song-poetry','','[]','憶昨參戎幕，交情子獨真。',192,'全唐诗/poet.song.71000.json','["憶昨參戎幕，交情子獨真。", "共爲關塞客，各負水雲身。", "跡遠金閨藉，衣沾玉壘塵。", "雕鞍暮横槊，錦幄曉行春。", "隱几軍書斷，登樓隴月新。", "鳴笳孤障底，落鴈古河濱。", "魯酒寒醅薄，燕姬翠黛頻。", "沙場供寫睇，戍角解傷神。", "白首投南國，青冥望北辰。", "山林方自屏，雞黍復相親。", "道舊嗟遊楚，論文偉過秦。", "高標識麟鳯，壯節見松筠。", "陋巷無車轍，扁舟有釣綸。", "悲秋把黄菊，取醉墮烏巾。", "藜藿良易足，圖書端不貧。", "一廛如可借，煩爲闢荆榛。"]'),
('655d23d9-adf2-4711-a16f-ad2d68af1d61','簡王長元次元時復欲入都','吳則禮','宋','宋诗','song-poetry','','[]','跛跛鬢毛短，娟娟春日長。',120,'全唐诗/poet.song.71000.json','["跛跛鬢毛短，娟娟春日長。", "繁花麗澤國，疊鼓摻漁陽。", "喚婢理雙屩，遣兒謀一觴。", "惟知作寒食，那復問殊方。", "石鼎官芽滑，銅盆井水凉。", "有時拈拄杖，隨意坐胡牀。", "涏涏定巢尾，咬咬求友吭。", "籃輿元落眼，豆飯或撐腸。", "楚柁連江色，淮天著鴈行。", "關儂五斗粟，老子復游梁。"]'),
('fa114e07-2f7c-4c5a-b552-d2caea200f9e','自太和衝雪歸據鞍偶作書贈令權元凱','吳則禮','宋','宋诗','song-poetry','','[]','老去龍紋匕，平生獸錦袍。',24,'全唐诗/poet.song.71000.json','["老去龍紋匕，平生獸錦袍。", "端知有奇語，大雪滿弓刀。"]'),
('094edd57-0a53-426e-80eb-d6ec9617373f','仁老畫梅二首  其一','吳則禮','宋','宋诗','song-poetry','','[]','疏影只横斜，覊臣真耄耋。',24,'全唐诗/poet.song.71000.json','["疏影只横斜，覊臣真耄耋。", "觀渠小開落，得此大夢覺。"]'),
('c81af113-c237-4bc3-a02e-e8ffc7930c5e','仁老畫梅二首  其二','吳則禮','宋','宋诗','song-poetry','','[]','玄牝要飽知，六出端不死。',24,'全唐诗/poet.song.71000.json','["玄牝要飽知，六出端不死。", "妙高一瓣香，付與毛錐子。"]'),
('d239e832-781a-4bfc-b176-11ef3cbc7dcf','予謫居荆南賦詩百餘篇書爲兩軸丙戌夏泛舟歸潤道由漢陽廖明略邀予飲于郎官湖因攜示之明略堅欲抄錄會予舟行甚速期以他日見歸不幸明略死矣此本不復可得今將可記者錄之忘者將復乞於渚宮諸友然平生作語老不自已又安用如許汙後人耳目乎因感而有作','吳則禮','宋','宋诗','song-poetry','','[]','三年放逐臣，今復得歸去。',24,'全唐诗/poet.song.71000.json','["三年放逐臣，今復得歸去。", "夢已到南徐，船回正鳴櫓。"]'),
('e81368a6-e67e-44ce-b031-8e8600abc178','懷謹常三首  其一','吳則禮','宋','宋诗','song-poetry','','[]','今晨詎復嬾，要與阿戎談。',24,'全唐诗/poet.song.71000.json','["今晨詎復嬾，要與阿戎談。", "寒温事且置，竟論後三三。"]'),
('4eb8c439-9015-481d-a200-b27cc9026f30','懷謹常三首  其二','吳則禮','宋','宋诗','song-poetry','','[]','高氣初不羣，咄咄端逼人。',24,'全唐诗/poet.song.71000.json','["高氣初不羣，咄咄端逼人。", "妙處欲絕倒，未怕兒輩嗔。"]'),
('f90cbd87-3658-4a3b-bc75-4e7f2e790021','懷謹常三首  其三','吳則禮','宋','宋诗','song-poetry','','[]','我有銅鼎湯，快瀹龍焙香。',24,'全唐诗/poet.song.71000.json','["我有銅鼎湯，快瀹龍焙香。", "政使澆舌本，君無問糟牀。"]'),
('cb423d70-33af-42df-a834-cf059453e859','十二月八日携家過因勝','吳則禮','宋','宋诗','song-poetry','','[]','吾人真鐵人，疇昔已百鍊。',24,'全唐诗/poet.song.71000.json','["吾人真鐵人，疇昔已百鍊。", "携家過殘年，來喫隨堂飯。"]'),
('9fcd9b53-5303-432f-93cf-88003a111cb1','呈希道兼寄不伐  其一','吳則禮','宋','宋诗','song-poetry','','[]','不見虎頭墨妙，聊尋燕頷將軍。',28,'全唐诗/poet.song.71000.json','["不見虎頭墨妙，聊尋燕頷將軍。", "興來未妨覓句，勝處端須策勳。"]'),
('4949a782-08d9-4084-8489-78a4a7013c8f','呈希道兼寄不伐  其二','吳則禮','宋','宋诗','song-poetry','','[]','試問邊頭花柳，不忘夢處江湖。',28,'全唐诗/poet.song.71000.json','["試問邊頭花柳，不忘夢處江湖。", "横槊要尋塞雁，磨刀仍膾河魚。"]'),
('3ebcef11-00f2-4667-9e4b-e38b89de50d7','書江貫道所畫扇','吳則禮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','胸中豈止丘壑，更有洞庭瀟湘。',28,'全唐诗/poet.song.71000.json','["胸中豈止丘壑，更有洞庭瀟湘。", "傳語東坡居士，後來惟教江郎。"]'),
('6f30bf82-6738-423d-8609-e296899e6371','題惠崇小景扇  其一','吳則禮','宋','宋诗','song-poetry','','[]','惠崇桃塢鵝鴨，春老不畫風煙。',28,'全唐诗/poet.song.71000.json','["惠崇桃塢鵝鴨，春老不畫風煙。", "看取團團璧月，中吞萬里江天。"]'),
('1b594c8d-5f2e-43b4-bc26-c89a9253bf8b','題惠崇小景扇  其二','吳則禮','宋','宋诗','song-poetry','','[]','綠鴨白鵝並戲，桃花不隔蒼煙。',28,'全唐诗/poet.song.71000.json','["綠鴨白鵝並戲，桃花不隔蒼煙。", "烏去自顰孤影，斷魂春水連天。"]'),
('9fd5bc0c-b2dd-43ec-bc07-aa2df3b8f612','風雨不止而夾岸黄花盛開偶成','吳則禮','宋','宋诗','song-poetry','','[]','風雨放船不惡，淮南九月未霜。',28,'全唐诗/poet.song.71000.json','["風雨放船不惡，淮南九月未霜。", "一色黄花十里，後身猶作柴桑。"]'),
('d4273eab-77be-469b-aa5c-f49833e29432','過寶晉齋贈元暉','吳則禮','宋','宋诗','song-poetry','','[]','窺徑紫苔娬麗，入門黄卷縱横。',28,'全唐诗/poet.song.71000.json','["窺徑紫苔娬麗，入門黄卷縱横。", "欲知箇裏妙處，時遣鶬鶊一鳴。"]'),
('b041f114-4769-4164-8702-d689c893b1e5','題米元暉臨北苑山水','吳則禮','宋','宋诗','song-poetry','','[]','平生胸中丘壑，天公乞與覊臣。',28,'全唐诗/poet.song.71000.json','["平生胸中丘壑，天公乞與覊臣。", "要遣毛錐舉似，此事兒輩不嗔。"]'),
('a25f208a-8e75-441a-b493-84e9e5c4685c','寄介然二首  其一','吳則禮','宋','宋诗','song-poetry','','[]','生事石田茅屋，世家青瑣金鑾。',28,'全唐诗/poet.song.71000.json','["生事石田茅屋，世家青瑣金鑾。", "崇福略無王事，自慚也費縣官。"]'),
('23b21863-c63d-425b-900a-4e8edbd542fb','寄介然二首  其二','吳則禮','宋','宋诗','song-poetry','','[]','昨者偶持漢節，白頭未識烏蠻。',28,'全唐诗/poet.song.71000.json','["昨者偶持漢節，白頭未識烏蠻。", "飽飯癯然摩腹，笑聽船鼓過灣。"]'),
('b885e7eb-1c69-4707-a091-262ead9df901','又寄介然','吳則禮','宋','宋诗','song-poetry','','[]','寄聲吾黨阿介，米賤惟有淮南。',28,'全唐诗/poet.song.71000.json','["寄聲吾黨阿介，米賤惟有淮南。", "更無一語不契，前身定是同參。"]'),
('e289292f-9477-48d2-9e8e-a1b0ff1b7c73','題吳道人庵壁間米元暉畫','吳則禮','宋','宋诗','song-poetry','','[]','阿暉戲拈禿筆，便與北苑争雄。',28,'全唐诗/poet.song.71000.json','["阿暉戲拈禿筆，便與北苑争雄。", "幻出幼輿丘壑，仍現一漚影中。"]'),
('8a474043-c935-4cf1-8a23-8c4694a98f4b','自太和衝雪歸而旅鴈數鳴據鞍偶作書贈令權元凱','吳則禮','宋','宋诗','song-poetry','','[]','休論駞背錦糢糊，且試腰間金僕姑。',32,'全唐诗/poet.song.71000.json','["休論駞背錦糢糊，且試腰間金僕姑。", "邊頭可是憐儂輩，忽作徐熙雪鴈圖。"]'),
('cd97f45e-d92e-44e6-a757-130098ee613e','太和道中和頤字韻','吳則禮','宋','宋诗','song-poetry','','[]','蘢葱峭蒨朝日微，時出奇詭解我頤。',32,'全唐诗/poet.song.71000.json','["蘢葱峭蒨朝日微，時出奇詭解我頤。", "已聽胡笳有韻曲，更行摩詰無聲詩。"]'),
('24f6b757-49b7-479e-8bea-8daacd65bb23','太和道中雪作因與諸友下馬索酒快飲率爾成詩','吳則禮','宋','宋诗','song-poetry','','[]','興來下馬索酒觴，雪打戰袍殊未央。',32,'全唐诗/poet.song.71000.json','["興來下馬索酒觴，雪打戰袍殊未央。", "有底須尋戴安道，端憐吳語賀知章。"]'),
('3fe0fed4-bc41-444c-8b87-3b3530505250','古殿珠','吳則禮','宋','宋诗','song-poetry','','[]','塞上歸來兩鬢蓬，飽知邊馬依北風。',32,'全唐诗/poet.song.71000.json','["塞上歸來兩鬢蓬，飽知邊馬依北風。", "從他垂棘連城璧，乞我僧伽古殿紅。"]'),
('888c12ce-12f3-4f4c-8b37-d2e742102264','簡吉老','吳則禮','宋','宋诗','song-poetry','','[]','盱眙水落秋鴈回，都梁霜薄梅花開。',32,'全唐诗/poet.song.71000.json','["盱眙水落秋鴈回，都梁霜薄梅花開。", "極知玄文不浪與，踽踽故作侯芭來。"]'),
('d9e25e78-1003-4c4e-ac8f-7cb2403ffab9','簡友人  其一','吳則禮','宋','宋诗','song-poetry','','[]','江頭洲渚晚陽斜，宿鴈已復取圓沙。',32,'全唐诗/poet.song.71000.json','["江頭洲渚晚陽斜，宿鴈已復取圓沙。", "老子尚堪巾屨在，憑君著意問梅花。"]'),
('16db6756-be4a-44f7-a559-4a6aac1e2a2e','簡友人  其二','吳則禮','宋','宋诗','song-poetry','','[]','溪水遶屋初鱗鱗，溪邊桃花正迎人。',32,'全唐诗/poet.song.71000.json','["溪水遶屋初鱗鱗，溪邊桃花正迎人。", "桃花迎人可復奈，幽事如許難具陳。"]'),
('ef69e622-49f2-4076-8483-a037cd88c91e','簡友人  其三','吳則禮','宋','宋诗','song-poetry','','[]','江山端無適俗韻，曳屐出門忘負痾。',32,'全唐诗/poet.song.71000.json','["江山端無適俗韻，曳屐出門忘負痾。", "林花工辦作紅雨，其奈一年春老何。"]'),
('e66c7476-e9d6-4a41-8355-1943752c4cfb','簡友人  其四','吳則禮','宋','宋诗','song-poetry','','[]','從來老子興不淺，未怕霜鬢渾欲斑。',32,'全唐诗/poet.song.71000.json','["從來老子興不淺，未怕霜鬢渾欲斑。", "安得希有大勇健，盡尋南徐江上山。"]'),
('69ff48bf-db25-4691-aba5-dadb1bc95aae','簡張子偉','吳則禮','宋','宋诗','song-poetry','','[]','軒軒禿髪穀城孫，有底天寒不出門。',32,'全唐诗/poet.song.71000.json','["軒軒禿髪穀城孫，有底天寒不出門。", "肯說今年閒貴賤，只將丘壑共人論。"]'),
('222d8854-4cb4-44f7-859f-441fc9ac5421','戲簡狄周臣','吳則禮','宋','宋诗','song-poetry','','[]','簾捲秋風燭影紅，少年公子倒金鍾。',32,'全唐诗/poet.song.71000.json','["簾捲秋風燭影紅，少年公子倒金鍾。", "艷歌聲入流雲去，肯問西鄰有病翁。"]'),
