('f067e3bc-f069-4dfc-8429-b3b102cd7f9b','題劉常梅','吳則禮','宋','宋诗','song-poetry','','[]','生憎長紅涴淺白，只有疏影連暗香。',32,'全唐诗/poet.song.71000.json','["生憎長紅涴淺白，只有疏影連暗香。", "憑君且置風月事，一笑姑爲時世粧。"]'),
('d0f3ab04-e3f4-438e-9a0b-2316c31a353c','戲嘲壁上畫軸','吳則禮','宋','宋诗','song-poetry','','[]','寒林淡墨人争看，對面奇峰孰會心。',32,'全唐诗/poet.song.71000.json','["寒林淡墨人争看，對面奇峰孰會心。", "可是世人唯識假，只緣清景少人尋。"]'),
('17c570f0-c4a1-487b-81c5-4e2fd791d95a','賦魏相之所收花光老小景','吳則禮','宋','宋诗','song-poetry','','[]','湖北湖南天水寛，道人付此一毫端。',32,'全唐诗/poet.song.71000.json','["湖北湖南天水寛，道人付此一毫端。", "魏郎得之不自供，要遺西山老眼看。"]'),
('a48b47ea-fe4f-46ac-b3b0-4df6d32eb3e7','又畫嘗醋翁','吳則禮','宋','宋诗','song-poetry','','[]','石先戲作忍酸相，未信從來嘗醋難。',32,'全唐诗/poet.song.71000.json','["石先戲作忍酸相，未信從來嘗醋難。", "頭毛鬅鬙面白皺，老夫笑作嬰兒看。"]'),
('d0089bf9-7dd4-4d64-aae3-077eff0a0e49','又再至山陽作','吳則禮','宋','宋诗','song-poetry','','[]','楚州白菘大於臂，天乞吾曹作好春。',32,'全唐诗/poet.song.71000.json','["楚州白菘大於臂，天乞吾曹作好春。", "北湖食來如食肉，塔裏僧伽不笑人。"]'),
('b3654b95-be3c-4d4a-8793-c365df2be04d','清谷水煎茶','吳則禮','宋','宋诗','song-poetry','','[]','快燒銅鼎欹胡牀，邊頭初試蟹眼湯。',32,'全唐诗/poet.song.71000.json','["快燒銅鼎欹胡牀，邊頭初試蟹眼湯。", "竟陵谷簾定少味，喚取阿羽來說嘗。"]'),
('98a428b5-3cfc-4132-9f27-7534a76f504d','蘭臯煎茶','吳則禮','宋','宋诗','song-poetry','','[]','掠水纖纖紫燕斜，聊憑烏几竚幽花。',32,'全唐诗/poet.song.71000.json','["掠水纖纖紫燕斜，聊憑烏几竚幽花。", "今年未識雲腴面，且撥去年官焙芽。"]'),
('0b1f1b10-e88b-4871-b47c-81f300f55d5b','寄夷白坦然二首  其一','吳則禮','宋','宋诗','song-poetry','','[]','夷白不應忘北湖，住持事繁無近書。',32,'全唐诗/poet.song.71000.json','["夷白不應忘北湖，住持事繁無近書。", "北湖頭白更饞相，何日從之聽木魚。"]'),
('1a2f9ffb-ebde-40f8-88df-694713a00baf','寄夷白坦然二首  其二','吳則禮','宋','宋诗','song-poetry','','[]','北湖飯飽初不知，惟見從來方朵頤。',32,'全唐诗/poet.song.71000.json','["北湖飯飽初不知，惟見從來方朵頤。", "天公大似撩我輩，不遣細和夔州詩。"]'),
('05b68429-a0b9-436a-81b1-c837f1ff94d2','奉聖念老得法於大通禪師游行十年歸以其法接引晉人北湖見而喜之贈一絕句','吳則禮','宋','宋诗','song-poetry','','[]','從教白浪長浮天，脚跟飽踏吳江船。',32,'全唐诗/poet.song.71000.json','["從教白浪長浮天，脚跟飽踏吳江船。", "晉人初不知祖令，拍手施與龍山禪。"]'),
('12f1cca9-ae17-4886-92b2-d74197503766','簡航禪師','吳則禮','宋','宋诗','song-poetry','','[]','縱横古帙散繩牀，卧對疏簾卷夕陽。',32,'全唐诗/poet.song.71000.json','["縱横古帙散繩牀，卧對疏簾卷夕陽。", "春去殘花已無跡，姢娟新綠上篔簹。"]'),
('12f59683-a5aa-4150-9768-20ba614cf5cd','石恪畫醉僧','吳則禮','宋','宋诗','song-poetry','','[]','倒街卧路誰復嗔，粥魚齋鼓强喚人。',32,'全唐诗/poet.song.71000.json','["倒街卧路誰復嗔，粥魚齋鼓强喚人。", "莫疑只今五斗醉，要會從來三昧身。"]'),
('952a0eed-f1c4-4939-abd2-7f9a7d7aebd3','夷白','吳則禮','宋','宋诗','song-poetry','','[]','夷白諸法只麽會，不作奇奇并怪怪。',32,'全唐诗/poet.song.71000.json','["夷白諸法只麽會，不作奇奇并怪怪。", "人來施與僧伽禪，事到付之彌勒袋。"]'),
('44e45409-8df4-423a-bc15-4a66870483f0','又偶作寄夷白老','吳則禮','宋','宋诗','song-poetry','','[]','去年臘雪一尺圍，著處梅花如許肥。',32,'全唐诗/poet.song.71000.json','["去年臘雪一尺圍，著處梅花如許肥。", "道人定復有幻法，莫遣都梁萬點飛。"]'),
('d8f31bc3-9998-45d5-9428-99ef0b94eafa','坐睡','吳則禮','宋','宋诗','song-poetry','','[]','白灰如雪麒麟紅，一老已打齋時鐘。',32,'全唐诗/poet.song.71000.json','["白灰如雪麒麟紅，一老已打齋時鐘。", "衲子末來且坐睡，蒲團與我作新冬。"]'),
('c67b6ab9-38b7-41bf-836c-fd230d0f0b02','舟行坐睡','吳則禮','宋','宋诗','song-poetry','','[]','撩天鼻孔蟠雷車，世間諸法種種壞。',32,'全唐诗/poet.song.71000.json','["撩天鼻孔蟠雷車，世間諸法種種壞。", "飽參飯後蒲團禪，北湖端爲第一代。"]'),
('0e081963-46f6-4d33-a7c6-fadd916fe6b0','絕句二首  其一','吳則禮','宋','宋诗','song-poetry','','[]','華館相望接使星，長淮南北已休兵。',32,'全唐诗/poet.song.71000.json','["華館相望接使星，長淮南北已休兵。", "便須買酒催行樂，更覓何時是太平。"]'),
('677c59f0-6382-4fbf-a16c-ad9600301a7d','絕句二首  其二','吳則禮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','滿船買了洞庭柑，雪色新裁白苧衫。',32,'全唐诗/poet.song.71000.json','["滿船買了洞庭柑，雪色新裁白苧衫。", "喚得吳姬同一醉，春風相送過江南。"]'),
('e5511243-4586-4760-b18d-7bf16291b535','詩一首','吳則禮','宋','宋诗','song-poetry','','[]','楓葉蘆花滿釣船，水風清處椀琴眠。',32,'全唐诗/poet.song.71000.json','["楓葉蘆花滿釣船，水風清處椀琴眠。", "覺來失卻瀟湘月，卻問青山覓酒錢。"]'),
('b72abb62-6feb-4d2c-9d36-d0ee9839b804','次竹樽韻','吳則禮','宋','宋诗','song-poetry','','[]','北湖飯豆病且癯，經年不問觴爲壺。',129,'全唐诗/poet.song.71000.json','["北湖飯豆病且癯，經年不問觴爲壺。", "誰令如許彭亨腹，時喚麴生澆老儒。", "此君風味美無有，會與淵明著名酒。", "侏儒飽死死非締交，仍挽皤罌作寮友。", "堂上燭滅渠快哉，一飲一石今塵埃。", "此君莫遣太孤絕，更須喚取鴟夷來。", "老年經丘尋壑意，痿痿羸羸殊少味。", "惟思著句與摩挲，徑就便便圖一醉。"]'),
('9e8a2066-c9b2-44d3-a518-88b49e1b1149','句','吳則禮','宋','宋诗','song-poetry','','[]','老子只堪持蟹螯。',8,'全唐诗/poet.song.71000.json','["老子只堪持蟹螯。"]'),
('99c6e97a-8d68-489d-b159-72254358b241','武夷仙架船巖','翁彥約','宋','宋诗','song-poetry','','[]','西溪漂渺接明河，鼓棹仙人泛立波。',32,'全唐诗/poet.song.71000.json','["西溪漂渺接明河，鼓棹仙人泛立波。", "却御長風天上去，虛舟千古插嵯峨。"]'),
('5d8cd9bb-cf8e-4025-b3ed-de15821ddc4a','武夷仙機石','翁彥約','宋','宋诗','song-poetry','','[]','辛苦支機耐寂寥，肯同嬴女只吹簫。',32,'全唐诗/poet.song.71000.json','["辛苦支機耐寂寥，肯同嬴女只吹簫。", "金梭昨夜成龍去，上與天孫織絳綃。"]'),
('82b649cd-36a9-4236-bef2-3b75a3dabaa5','武夷雞窠巖','翁彥約','宋','宋诗','song-poetry','','[]','仙人清磬讀黄庭，長聽金雞半夜聲。',32,'全唐诗/poet.song.71000.json','["仙人清磬讀黄庭，長聽金雞半夜聲。", "一夕都隨黄鶴去，滿巢明月白雲生。"]'),
('cef12f54-21d0-4d80-89db-82fc006b179b','武夷三層峰','翁彥約','宋','宋诗','song-poetry','','[]','層峰三疊倚青冥，霧宿雲飛自有程。',32,'全唐诗/poet.song.71000.json','["層峰三疊倚青冥，霧宿雲飛自有程。", "杳靄又因關造化，故教人世驗陰晴。"]'),
('cfa70921-6710-43f0-a5e7-40b53afb7b9b','武夷毛竹洞','翁彥約','宋','宋诗','song-poetry','','[]','毛竹連雲路欲迷，洞門深鎖落花遲。',32,'全唐诗/poet.song.71000.json','["毛竹連雲路欲迷，洞門深鎖落花遲。", "魯孫幾度春風老，未了仙人一局棋。"]'),
('09102965-7549-4c72-a993-13b8de459bb1','仙釣臺','翁彥約','宋','宋诗','song-poetry','','[]','百粵堯時路未通，曲溪春水沒長松。',32,'全唐诗/poet.song.71000.json','["百粵堯時路未通，曲溪春水沒長松。", "老仙臺上無明月，不釣凡魚只釣龍。"]'),
('c46a2ee2-bf9c-49cb-bc45-cb7d147e2158','晞真館','翁彥約','宋','宋诗','song-poetry','','[]','濯濯清溪九曲流，一天風露萬山秋。',32,'全唐诗/poet.song.71000.json','["濯濯清溪九曲流，一天風露萬山秋。", "凄清不似人間世，月檻雲窗特地幽。"]'),
('397e34b4-90a9-4773-bc48-114781a2b455','張公洞','王繹','宋','宋诗','song-poetry','','[]','高士宸居隔紫烟，洞中金闕暗相連。',64,'全唐诗/poet.song.71000.json','["高士宸居隔紫烟，洞中金闕暗相連。", "輔光竈冷留香壤，太素淵清湧玉泉。", "後夜雲歸雪浪濕，未明人起月華鮮。", "秋光不老巖前麓，到此偷閒亦自賢。"]'),
('3352e82f-b80a-4369-8cdb-e2dcbc3b211f','方叔寓龍興仁王佛舍與公定道輔仲寶携酒肴納凉聯句十六韵','趙令畤','宋','宋诗','song-poetry','','[]','宿雨且初霽，微凉吹廣庭。',192,'全唐诗/poet.song.71000.json','["宿雨且初霽，微凉吹廣庭。", "嘉賓忽相遇，午夢驚扣扃。", "長松森翠影，修竹參青冥。", "飄雲度空急，殘日穿林明。", "幽牆隔江浦，遠嶼定風舲。", "城市厭煩暑，山樊念伶俜。", "角巾代公紱，草具踰侯鯖。", "園實摘的皪，厨醖斟晶熒。", "烹鮮縮頸大，海錯著器腥。", "笑談得真樂，採擷逢幽馨。", "雲陰剝初霽，夕嵐收遠青。", "窗卧憶元亮，詩成懷景升。", "日須河朔飲，當解高陽酲。", "煩襟頓忘釋，嘉詠不少停。", "闉闍發嚴鼓，穹碧垂繁星。", "一笑跨鞍去，奚論楚人醒。"]'),
('ea1a1496-265b-4c89-8fbd-3bd9c48d04d3','同官李仲益贈張思仲家歌人團茶因題其封','趙令畤','宋','宋诗','song-poetry','','[]','色映宮姝粉，香傳漢殿春。',24,'全唐诗/poet.song.71000.json','["色映宮姝粉，香傳漢殿春。", "團團明月魄，却贈月中人。"]'),
('86d637d2-a930-4382-92da-f02315f144a7','次韵陳履常汝陰久雪賑饑','趙令畤','宋','宋诗','song-poetry','','[]','坎壈中年坐廢人，老來貂鼎視埃塵。',64,'全唐诗/poet.song.71000.json','["坎壈中年坐廢人，老來貂鼎視埃塵。", "鐵霜带面惟憂國，機穽當前不爲身。", "發廩已康諸縣命，蠲逋一洗幾年貧。", "歸來又掃寬民奏，慚愧毫端爾許春。"]'),
('d05d94b8-0627-4878-9fdd-2db6bb40b654','初到長安','趙令畤','宋','宋诗','song-poetry','','[]','來往長安未定居，暫將僧舍當吾廬。',64,'全唐诗/poet.song.71000.json','["來往長安未定居，暫將僧舍當吾廬。", "空中說法憑鈴語，枕上朝饑聽木魚。", "因果分明休問佛，行藏自信罷占書。", "眼前一物真堪羨，百尺長楊水滿渠。"]'),
('21da81ae-c669-4eb1-9f57-1a54bc0faa49','次韵晁以道嘲陳叔易得官入京','趙令畤','宋','宋诗','song-poetry','','[]','聞道諸公置齒牙，買韉賣展趁年華。',32,'全唐诗/poet.song.71000.json','["聞道諸公置齒牙，買韉賣展趁年華。", "太平起隠無遺策，空盡嵩山處士家。"]'),
('757851f7-18d0-4738-bd3f-a14d11fcc152','跋太白醉草','趙令畤','宋','宋诗','song-poetry','','[]','雖自九天分派，不與萬李同林。',28,'全唐诗/poet.song.71000.json','["雖自九天分派，不與萬李同林。", "步處雷驚電繞，空餘翰墨窺尋。"]'),
('7f50938f-dc71-4283-86ba-e8f7d4f4b0bf','秋','趙令畤','宋','宋诗','song-poetry','','[]','白藕作花風已秋，不堪殘睡更回頭。',32,'全唐诗/poet.song.71000.json','["白藕作花風已秋，不堪殘睡更回頭。", "晚雲带雨歸飛急，去作西窗一夜愁。"]'),
('04d3e187-8aa3-438d-8a2e-59e2d35d4b0c','被責三十年蒙恩召還行在方駐蹕錢塘書呈子常侍郎','趙令畤','宋','宋诗','song-poetry','','[]','三十餘年一夢同，向來朝士盡沈空。',32,'全唐诗/poet.song.71000.json','["三十餘年一夢同，向來朝士盡沈空。", "如今白首趨行闕，不是當年長樂鐘。"]'),
('ad56f57d-8bfb-465c-891e-e5d4cc3dec26','贈陳處士','趙令畤','宋','宋诗','song-poetry','','[]','疏慵任過少年時，名利難交遠近知。',64,'全唐诗/poet.song.71000.json','["疏慵任過少年時，名利難交遠近知。", "一洞落花春病酒，滿樓明月夜吟詩。", "展編海曲菰蒲葉，杖剪嵩陽楖栗枝。", "却話東林擬重去，伴僧閑逸白蓮池。"]'),
('cd8b8b0d-81f5-4bfd-ba8e-ce0cc936b496','江樓閒望','趙令畤','宋','宋诗','song-poetry','','[]','紅塵無處不諠譁，獨上江樓四望賒。',64,'全唐诗/poet.song.71000.json','["紅塵無處不諠譁，獨上江樓四望賒。", "泥水僧歸林下寺，待船人立渡頭沙。", "雲藏島外啼猿樹，竹鎖橋邊賣酒家。", "吟罷憑欄心更逸，海風吹斷暮天霞。"]'),
('d5c37228-29b6-499a-98c2-b237d6f6d991','冬日居山','趙令畤','宋','宋诗','song-poetry','','[]','亂山深處過嚴凝，僻靜門鄰物外僧。',64,'全唐诗/poet.song.71000.json','["亂山深處過嚴凝，僻靜門鄰物外僧。", "送客踏穿松徑雪，煮茶敲破石池冰。", "朝垂簾幙寒慵卷，夜鎖樓臺靜懶登。", "只待春來歸上國，杖藜吟出白雲層。"]'),
