('594b3136-0898-4533-a18f-d6a62340def4','句  其五','趙令畤','宋','宋诗','song-poetry','','[]','羣峰競秀尖。',6,'全唐诗/poet.song.71000.json','["羣峰競秀尖。"]'),
('3e8a4501-f0e5-4cd9-98ce-3d1a3e770417','謁照師塔二首  其一','釋宗敏','宋','宋诗','song-poetry','','[]','苧麻刪補後，法律漸凌遲。',48,'全唐诗/poet.song.71000.json','["苧麻刪補後，法律漸凌遲。", "一字誰褒貶，三宗絕見知。", "奔馳事名相，逸蕩傲行持。", "獨有芝園老，提綱繼祖師。"]'),
('66410571-f5f5-4bac-8fa0-f91db1d36371','謁照師塔二首  其二','釋宗敏','宋','宋诗','song-poetry','','[]','兵火焚諸剎，樓臺化碧烟。',48,'全唐诗/poet.song.71000.json','["兵火焚諸剎，樓臺化碧烟。", "松龕橫野岸，塑像枕流泉。", "誌述都煨燼，功名獨不遷。", "高蹤杳然夢，不覺涕潸然。"]'),
('cb186419-aaf8-4b58-aede-018b3af2029f','句  其一','陸傅','宋','宋诗','song-poetry','','[]','枕上吹虀醒宿酒，窗間秉燭拾殘棋。',16,'全唐诗/poet.song.71000.json','["枕上吹虀醒宿酒，窗間秉燭拾殘棋。"]'),
('774b30bc-59a0-40d9-8306-a86dac76a544','句  其二','陸傅','宋','宋诗','song-poetry','','[]','寧知小兒輩，竟壞好家居。',12,'全唐诗/poet.song.71000.json','["寧知小兒輩，竟壞好家居。"]'),
('1bbaa763-1729-4099-9a47-b51e8f1fa6e8','哭魏夫人','張夫人','宋','宋诗','song-poetry','','[]','香散簾幃寂，塵生翰墨閑。',24,'全唐诗/poet.song.71000.json','["香散簾幃寂，塵生翰墨閑。", "空傳三壺譽，無復內朝班。"]'),
('d4d79bb0-2493-4e4e-8bc6-1607978ceee1','句','李湜','宋','宋诗','song-poetry','','[]','迸石如散珠，穿雲似流玉。',12,'全唐诗/poet.song.71000.json','["迸石如散珠，穿雲似流玉。"]'),
('843d52af-7018-4717-a984-bcb95af81474','題清芬閣','茹東濟','宋','宋诗','song-poetry','','[]','艤棹叩朱門，雄飛處士村。',48,'全唐诗/poet.song.71000.json','["艤棹叩朱門，雄飛處士村。", "詩名千古重，廟貌一方尊。", "綠水長溪闊，青山遠岫昏。", "辭華誰善繼，御史是曾孫。"]'),
('dac5882a-837b-4b1d-8e1f-f2f4d065df20','象鼻岩','張元仲','宋','宋诗','song-poetry','','[]','會入蒼舒萬斛舟，至今鼻準醮清流。',32,'全唐诗/poet.song.71000.json','["會入蒼舒萬斛舟，至今鼻準醮清流。", "君王玉輅催行駕，安得身閑伴白鷗。"]'),
('2a31f77d-40ef-449e-905c-5dfe1dc04e62','越王城','方叔震','宋','宋诗','song-poetry','','[]','聞道越王避漢兵，竄身巖谷覬偷生。',32,'全唐诗/poet.song.71000.json','["聞道越王避漢兵，竄身巖谷覬偷生。", "如雲甲馬今何在，只見良田萬頃平。"]'),
('aa7b03c2-644f-4444-8ddb-2baa3fcff110','贈王直方','秦覯','宋','宋诗','song-poetry','','[]','不到王家近十年，子猷風韵亦依然。',32,'全唐诗/poet.song.71000.json','["不到王家近十年，子猷風韵亦依然。", "舊時朋友今何在，別後新詩誰與傳。"]'),
