('014cbd84-23c7-4572-98de-c72bac549dd2','和王直方夜坐','秦覯','宋','宋诗','song-poetry','','[]','幃幔高深夜漏長，頗從詩酒傲冰霜。',32,'全唐诗/poet.song.71000.json','["幃幔高深夜漏長，頗從詩酒傲冰霜。", "燭花漸暗人初睡，金獸無烟却有香。"]'),
('cf4c9c0e-d54c-41ff-b970-3e6e238d0070','城東寄王越州','高茂華','宋','宋诗','song-poetry','','[]','五年不出青門道，邂逅尋春此一回。',32,'全唐诗/poet.song.71000.json','["五年不出青門道，邂逅尋春此一回。", "忽憶秦川貴公子，桃花落盡合歸來。"]'),
('07d68500-43eb-40fb-8af9-e06bc227ce49','句','高茂華','宋','宋诗','song-poetry','','[]','中途留眼占星聚，一宿披顔覺霧收。',16,'全唐诗/poet.song.71000.json','["中途留眼占星聚，一宿披顔覺霧收。"]'),
('1aa2c056-5ff4-4ff2-8834-fdf523c9beb4','句','張庭堅','宋','宋诗','song-poetry','','[]','儋耳百年經僻陋，眉山二老繼驅除。',16,'全唐诗/poet.song.71000.json','["儋耳百年經僻陋，眉山二老繼驅除。"]'),
('dd84fff0-671f-4d5b-85e9-ee8f9324a4ad','題北山松軒','石公弼','宋','宋诗','song-poetry','','[]','梢雲阻日引清風，抱石盤根造物工。',32,'全唐诗/poet.song.71000.json','["梢雲阻日引清風，抱石盤根造物工。", "凌厲四時同一色，不知何歲植巖中。"]'),
('5899af0b-42f9-44c5-8556-7f8d484f7860','遊嘉祐院登般若臺','石公弼','宋','宋诗','song-poetry','','[]','縈回巖岫擁高樓，飲海拏雲走翠虯。',32,'全唐诗/poet.song.71000.json','["縈回巖岫擁高樓，飲海拏雲走翠虯。", "欲問此臺名般若，一輪明月照中秋。"]'),
('af41a5d5-fc7c-47a2-b741-4b5c7f9c7b51','遊日山','石公弼','宋','宋诗','song-poetry','','[]','嵐光咫尺見山扃，候得潮來一葦輕。',64,'全唐诗/poet.song.71000.json','["嵐光咫尺見山扃，候得潮來一葦輕。", "慘慘晚堂看日色，森森古殿對江城。", "風敲寒玉驚僧睡，巖落澌冰認雨聲。", "不是平生曾到處，因緣今日此中行。"]'),
('05aaebfb-e5e7-4f52-8f2c-90df8e7b2852','題樗軒綫泉及聞琴','石公弼','宋','宋诗','song-poetry','','[]','竹引高山一綫泉，細如絲髮亦涓涓。',32,'全唐诗/poet.song.71000.json','["竹引高山一綫泉，細如絲髮亦涓涓。", "莫嫌此去滄溟遠，流水更聽琴上弦。"]'),
('71b8aa0e-12cb-4141-967f-7c444a1cf489','題無垢院  其一','石公弼','宋','宋诗','song-poetry','','[]','沿磴穿嵐造竹扉，一軒幽敞坐忘機。',32,'全唐诗/poet.song.71000.json','["沿磴穿嵐造竹扉，一軒幽敞坐忘機。", "池鑱瓊骨容清泚，凭檻時看翡翠飛。"]'),
('161a9631-7d11-4c7c-8f60-fab258474593','題無垢院  其二','石公弼','宋','宋诗','song-poetry','','[]','浄界曾無一點塵，風疏松竹響天真。',32,'全唐诗/poet.song.71000.json','["浄界曾無一點塵，風疏松竹響天真。", "從來此意少人會，只道林閒無至人。"]'),
('a2d3d8de-16ca-4598-9ad5-82b527cbbc40','游巾子山諸剎','石公弼','宋','宋诗','song-poetry','','[]','杖策遊山寺，終朝事討尋。',48,'全唐诗/poet.song.71000.json','["杖策遊山寺，終朝事討尋。", "地危敧石磴，殿古倚雲岑。", "曲徑行松杪，禪房過竹林。", "奈何幽興在，他日更登臨。"]'),
('a6f41783-f3b7-41a8-aa5c-0a4312c07458','絕句','趙占龜','宋','宋诗','song-poetry','','[]','四枚豚犬教知書，二頃良田儘有餘。',32,'全唐诗/poet.song.71000.json','["四枚豚犬教知書，二頃良田儘有餘。", "魯酒三杯棋一局，客來渾不問親疏。"]'),
('e93f9ccd-7405-42d0-89dc-995b4d101ee2','謝傳神蔡景直','鮑慎由','宋','宋诗','song-poetry','','[]','馳譽丹青有古風，筆端及我未宜蒙。',32,'全唐诗/poet.song.71000.json','["馳譽丹青有古風，筆端及我未宜蒙。", "雲臺麟閣遥相望，枉寫褒公與鄂公。"]'),
('58cccd02-89c8-498b-8700-1145a82398ef','王略帖贊','鮑慎由','宋','宋诗','song-poetry','','[]','昭回于天垂英光，跨頡歷籀化大荒。',64,'全唐诗/poet.song.71000.json','["昭回于天垂英光，跨頡歷籀化大荒。", "烟華濃淡賦低昂，一噫萬古稱天章。", "鸞跨虯引鵠序行，洞天九九歸遼陽。", "茫茫十二小劫長，璽完神訶命芾藏。"]'),
('86cbc64d-50d6-479f-ae56-cdbc8cf3bd70','雨餘','鮑慎由','宋','宋诗','song-poetry','','[]','礎潤雨欲作，好風每相先。',96,'全唐诗/poet.song.71000.json','["礎潤雨欲作，好風每相先。", "蕭蕭清入簾，令我心灑然。", "閉門倦永夏，枕書日昏眠。", "快此風雨餘，端如濯飛泉。", "盆山有佳趣，草木更幽妍。", "井華養文石，香篆橫雲烟。", "俯仰方丈間，勝事亦可憐。", "永懷觸熱子，我勞良獨賢。"]'),
('b644b55d-94d4-40cc-9be5-0a6bd5672753','讀漢書','鮑慎由','宋','宋诗','song-poetry','','[]','漢公事業比阿衡，純用詩書致太平。',32,'全唐诗/poet.song.71000.json','["漢公事業比阿衡，純用詩書致太平。", "它日何人頌功德，至今嘲笑亦諸生。"]'),
('144b93c7-8000-4b37-8a33-38ef91d7cdf5','夜坐','鮑慎由','宋','宋诗','song-poetry','','[]','萬卷堆中種眼花，睡魔亦厭夜深茶。',32,'全唐诗/poet.song.71000.json','["萬卷堆中種眼花，睡魔亦厭夜深茶。", "平生不草長門賦，豈有黄金送酒家。"]'),
('ad7bab3c-92ef-4754-886f-2a6046159dc9','寄曾子開','鮑慎由','宋','宋诗','song-poetry','','[]','白髮波波尚問津，可嗟志業在經綸。',64,'全唐诗/poet.song.71000.json','["白髮波波尚問津，可嗟志業在經綸。", "十年於此纔三見，四海如公復幾人。", "虎穴功名勞唾掌，醉鄉風月且藏身。", "平安欲問無來使，何處荒山野水濱。"]'),
('bed6afde-75c3-4c48-8fe5-6a7f344e4905','與鄭公華自朐山鄰舟行','鮑慎由','宋','宋诗','song-poetry','','[]','舟行有後先，相去能幾許。',60,'全唐诗/poet.song.71000.json','["舟行有後先，相去能幾許。", "鏗轟金鼓聲，見面不得語。", "水花來幽香，岸柳過疏雨。", "登艫各乘風，解帆會聯浦。", "閑携小龍團，睡起就君煮。"]'),
('8a8e0029-17a3-4935-821f-e426a401ecd7','句  其一','鮑慎由','宋','宋诗','song-poetry','','[]','三白歲可期，一飽分已定。',12,'全唐诗/poet.song.71000.json','["三白歲可期，一飽分已定。"]'),
('f4dde63b-0de5-4d37-ab2a-cc60e6548676','句  其二','鮑慎由','宋','宋诗','song-poetry','','[]','學詩比登仙，金膏換凡骨。',12,'全唐诗/poet.song.71000.json','["學詩比登仙，金膏換凡骨。"]'),
('e4c91358-9868-4e1c-816b-4b41bb3854b9','句  其三','鮑慎由','宋','宋诗','song-poetry','','[]','繞樹尋花得得來。',8,'全唐诗/poet.song.71000.json','["繞樹尋花得得來。"]'),
('125793cc-57c4-4948-9493-68f962ce8174','句  其四','鮑慎由','宋','宋诗','song-poetry','','[]','平池九曲在，春水縈碕{石彎}。',15,'全唐诗/poet.song.71000.json','["平池九曲在，春水縈碕{石彎}。"]'),
('ecd452a9-4e00-4932-a342-34dc4913c036','句','鮑輝','宋','宋诗','song-poetry','','[]','下瞰波瀾知海闊，仰觀霄漢得天多。',16,'全唐诗/poet.song.71000.json','["下瞰波瀾知海闊，仰觀霄漢得天多。"]'),
('8d8b700b-b339-4c0a-a782-0779ee4a1a02','黄蘗寺','李諭','宋','宋诗','song-poetry','','[]','但覺壺中長日月，焉知世上有風波。',32,'全唐诗/poet.song.71000.json','["但覺壺中長日月，焉知世上有風波。", "龍收雨雹歸巖穴，僧伴烟霞宿鳥窠。"]'),
('cd49c744-fd8c-442a-8b34-f72f532853bf','戲賀何端明得子','袁灼','宋','宋诗','song-poetry','','[]','慶門昨夜夢熊羆，曉得明珠照鳳池。',32,'全唐诗/poet.song.71000.json','["慶門昨夜夢熊羆，曉得明珠照鳳池。", "却憶劉郎詩句好，海中仙果子生遲。"]'),
('fff268c8-e8e6-47e4-94fc-d65eff83a9c0','句','董行之','宋','宋诗','song-poetry','','[]','頼有遺鞭在黄道，不教追騎及清塵。',16,'全唐诗/poet.song.71000.json','["頼有遺鞭在黄道，不教追騎及清塵。"]'),
('b8729117-490e-4fcb-af21-401906e3fd73','句','黄蕡','宋','宋诗','song-poetry','','[]','黄梔姑且饒他詠，丹桂行須見我攀。',16,'全唐诗/poet.song.71000.json','["黄梔姑且饒他詠，丹桂行須見我攀。"]'),
('3bbb29cb-a28d-4ef1-8fe4-f8fed51c619f','玉泉院荔枝軒','楊朏','宋','宋诗','song-poetry','','[]','曾觀荔枝圖，幾費丹青粧。',120,'全唐诗/poet.song.71000.json','["曾觀荔枝圖，幾費丹青粧。", "能紅能紫亦能綠，不能寫得天然香。", "曾讀荔枝譜，品品堪第一。", "較量滋味論高低，大抵聞名不聞實。", "我疑真宰推化工，安排百果分番紅。", "杏梅桃李不足數，先教碌碌隨春風。", "錦囊玉液相渾淪，百果讓作東南元。", "別有真香與味色，一時分付荔枝軒。"]'),
('8c6a6402-73b9-4cb8-ada6-2cf728f35243','句','胡璪','宋','宋诗','song-poetry','','[]','南安建邦庾嶺下，小小城池堅四壁。',16,'全唐诗/poet.song.71000.json','["南安建邦庾嶺下，小小城池堅四壁。"]'),
('3ce6f38b-645f-4649-95f0-78e436ca13c2','句','劉渭','宋','宋诗','song-poetry','','[]','庶子泉寒澄雅思，陽冰篆古足清心。',16,'全唐诗/poet.song.71000.json','["庶子泉寒澄雅思，陽冰篆古足清心。"]'),
('4b559ef6-89d5-4804-99a4-09c1a078e87b','句','劉況','宋','宋诗','song-poetry','','[]','夜觀月色如銀色，朝聽潮音雜梵音。',16,'全唐诗/poet.song.71000.json','["夜觀月色如銀色，朝聽潮音雜梵音。"]'),
('6da98469-4c1f-4fc9-872d-f17d65f50b98','憶歐段','周行己','宋','宋诗','song-poetry','','[]','歲暮何所思，道南咸與籍。',240,'全唐诗/poet.song.71000.json','["歲暮何所思，道南咸與籍。", "出門泥漫漫，跬步成乖隔。", "人情未免俗，節物復感迫。", "念我江海人，紓節慕古昔。", "少年弄柔翰，頗謂得所適。", "豈有軒冕心，况自便菽麥。", "人生不可意，變態忽如弈。", "狼藉太學生，俯就科舉責。", "居然五六載，頗不料損益。", "貧賤思富貴，富貴悲迫阨。", "所得九牛毛，置身豈良策。", "何如謝客兒，會稽卜佳宅。", "文章富貴心，山水樂幽僻。", "長安不可居，季冬猶絺綌。", "緬望悲故鄉，恨無晨風翮。", "寒窗九轉腸，紛亂不可繹。", "此意竟誰語，坐覺鄙吝積。", "不見二三子，詎可論肝膈。", "悠悠百世名，浩浩此生跡。", "離婁燭千里，盲不見咫尺。"]'),
('0810d7bf-20ad-440c-9e90-a383c1d13d01','營居有感','周行己','宋','宋诗','song-poetry','','[]','有鵲銜枯枝，往往營其巢。',84,'全唐诗/poet.song.71000.json','["有鵲銜枯枝，往往營其巢。", "巢成雌卵雛，雛出聲嗷嗷。", "雌飛雄啄食，絡繹日百遭。", "咄哉誰使汝，理也不可逃。", "曠曠宇宙內，顧奚獨汝曹。", "人生結棟宇，斬木與誅茅。", "經營壯有室，耆艾尚勤勞。"]'),
('b7992de8-8e01-4cae-864e-e2e187d73dcf','待李純如鄧子同','周行己','宋','宋诗','song-poetry','','[]','誰云相知好，相知亦吾累。',156,'全唐诗/poet.song.71000.json','["誰云相知好，相知亦吾累。", "一夕不在眼，青燈已無寐。", "晚定李鄧交，付託足心地。", "嶷然諸儒中，百馬逢一驥。", "對我懷抱豁，軒眉得深意。", "昨朝分手出，冠带修人事。", "淹留久未返，終夕念乖異。", "摇落庭樹秋，虛窗發清吹。", "坐起無一歡，出門屢瞻跂。", "歸鼓朱絲弦，復理黄卷字。", "弦誦雖曰樂，其如心不遂。", "欻欲往從君，念無晨風翅。", "掃地焚香坐，聊以待君至。"]'),
('4bbb3d47-f1f9-4436-82f8-dc431d2b41fa','題樂文仲憊軒','周行己','宋','宋诗','song-poetry','','[]','古有大隠人，不必在林藪。',156,'全唐诗/poet.song.71000.json','["古有大隠人，不必在林藪。", "屠釣得賢傑，能出漢庭右。", "用之即爲虎，信是經濟手。", "樂生淮海來，貧窶常露肘。", "乃翁病風痹，粥食不到口。", "下簾長安市，授經供卯酉。", "生涯一憊軒，貌作槁木朽。", "膽實大于身，豪氣貫牛斗。", "往往或下人，恐是黄石叟。", "屈身以伸道，此事古來有。", "貧賤交分薄，益見俗態醜。", "丈夫豈得知，事定蓋棺後。", "與爾同一笑，聊進杯中酒。"]'),
('1fb34810-efbc-480c-800a-ea250e17622b','寄題鳳翔長孫家集芳亭','周行己','宋','宋诗','song-poetry','','[]','種木須種松，松有四時芳。',84,'全唐诗/poet.song.71000.json','["種木須種松，松有四時芳。", "種草須種蘭，蘭有千里香。", "衆木豈不大，秋至即凋傷。", "百草豈不好，露下紛萎黄。", "人生事園圃，用意各有方。", "不貴草木多，只貴草木良。", "但種松與蘭，主人家道昌。"]'),
('1cac9362-e68e-47cb-b289-885b909d46e8','玩師求詩歸台州','周行己','宋','宋诗','song-poetry','','[]','越鳥棲南枝，胡馬依北風。',144,'全唐诗/poet.song.71000.json','["越鳥棲南枝，胡馬依北風。", "人生亦懷土，安能長西東。", "玩公白雲老，方丈憑高峰。", "忽爲萬里遊，應緣來晨鐘。", "君看伊與洛，二川日溶溶。", "逝者亦如此，流轉何時窮。", "我居謝公山，天台一水通。", "莽莽宇宙內，那知忽相逢。", "塵埃識眉宇，覺我耳目聰。", "暫來還復去，有如無根蓬。", "令我長歎息，不得久相從。", "側身雞鶩羣，仰羨高飛鴻。"]'),
('bc818b90-03cd-453e-a51f-18e49260919f','奉和佛月大師','周行己','宋','宋诗','song-poetry','','[]','朝出太學門，廣路長飆飛。',108,'全唐诗/poet.song.71000.json','["朝出太學門，廣路長飆飛。", "如可緇塵微，污我如雪衣。", "擬足投清浄，入寺扣禪扉。", "遇彼賞心人，發言破夕霏。", "既見彌明句，乃知侯喜微。", "琅琅發妙語，慰此渴與饑。", "小卷大字書，一一各有歸。", "更以金玉贈，萬丈生光輝。", "日落微雲收，明月滿書幃。"]'),
('2ee8bea0-598a-403b-9a3a-af0cc1b9fb87','贈沈彬老','周行己','宋','宋诗','song-poetry','','[]','永嘉人物衰，斯文久零替。',240,'全唐诗/poet.song.71000.json','["永嘉人物衰，斯文久零替。", "學徒寡道心，日與風俗敝。", "我生衰敝後，上思千載事。", "實欲閭里間，一一蹈仁義。", "敬重鄉人情，翻遭俗眼忌。", "晚得沈夫子，學問有根柢。", "矯矯流輩中，頗識作者意。", "歡然慰吾心，歸此同好嗜。", "吾子更我聽，士也貴尚志。", "古道自足師，不必今人貴。", "荼苦不異畝，薰蕕不同器。", "所憂義理愆，何恤流俗議。", "進道要勇决，取與慎爲計。", "去惡如去沙，沙盡自見底。", "積善如積土，土多乃成巋。", "讀書要知道，文章實小技。", "子試反覆思，鄙言有深味。", "自非心愛合，安能吐肝肺。", "行行慎取之，紓節思遠大。", "豈但勸鄉閭，永爲斯民頼。"]'),
('6b658887-1e13-4d62-bfff-465d2e8ba047','敬贈李方叔','周行己','宋','宋诗','song-poetry','','[]','蛟龍吐雲氣，霧豹出文采。',156,'全唐诗/poet.song.71000.json','["蛟龍吐雲氣，霧豹出文采。", "許潁有佳士，翰林風流在。", "吾道固多艱，明時屢危殆。", "嘉穀生螟蝗，稊稗勞取采。", "平生數萬言，未料寒與餒。", "天生濟世才，發揮必有待。", "伯樂一顧重，豈不價百倍。", "展足造青雲，會見絕四海。", "顧我茅葦姿，謬欲漸蘭茝。", "達人固多可，借譽飾駑猥。", "丈夫一相知，胸中何磊磊。", "願作南山松，青青期不改。", "此事雖一時，風流激千載。"]'),
('b9720e2c-3422-4b1a-8f5e-b07e6b37362f','肺病','周行己','宋','宋诗','song-poetry','','[]','吾生與靜侔，早無適俗器。',120,'全唐诗/poet.song.71000.json','["吾生與靜侔，早無適俗器。", "失身掛塵網，道心日已替。", "今茲得肺病，自可絕人事。", "默觀悟生理，是身同一蛻。", "代馬無南蹄，越鳥無北翅。", "物各歸其本，我何有于世。", "冠冕且罷休，養痾山水際。", "藉石看白雲，臨流鼓蘭枻。", "百種絕念慮，優游聊卒歲。", "誰云病疾苦，邂逅即良計。"]'),
('038714a9-147e-4a8c-89d8-0dddacdea916','次韵李十七僧宜見過兼簡杜思誠','周行己','宋','宋诗','song-poetry','','[]','坎壈客遊子，歲莫懷百憂。',216,'全唐诗/poet.song.71000.json','["坎壈客遊子，歲莫懷百憂。", "困若伏轅駒，未遇甘垂頭。", "志度藴剛潔，勁氣橫清秋。", "豈事稻粱唼，比翼黄鶴遊。", "人情憎遠客，言笑懷戈矛。", "有道死不泯，能易匈匈不。", "窮當志益堅，詎逐波上鷗。", "有杜莫逆交，有李山陽儔。", "日想文義會，夫我心則休。", "心休日月閒，忽忽時歲遒。", "俗子浪嗤詬，日夕競咆烋。", "圓鑿事方枘，固知不相謀。", "我徒方外士，汎若不繫舟。", "東西與南北，無入不優遊。", "至此願隨俗，俛眉愧前修。", "駕言歸去來，山寒不可留。", "薄俗利口實，斬斬非我侔。", "太息仰明月，忍作尋常流。"]'),
('8f8b5d3e-fa2a-4c43-bb3d-fbd2c3540d94','蚊','周行己','宋','宋诗','song-poetry','','[]','天地不愛人，生此人之苦。',204,'全唐诗/poet.song.71000.json','["天地不愛人，生此人之苦。", "吁嗟實微物，身不及毛羽。", "利嘴善噆膚，令人失眠睡。", "長夏五六月，執熱不通噫。", "此物于是時，翾翾夸得勢。", "一聚動億萬，翳空如坌壒。", "當晝即散伏，得夜乃紛會。", "每見燈火集，不容設幬蓋。", "初若蝟毛戢，次第緣罅隘。", "稍稍傍耳飛，嚶鳴欲相賣。", "揮拂不敢停，得便時一嘬。", "所欲未涓滴，已見盈腹背。", "捨命不畏死，忽遭一拍碎。", "顧我七尺軀，豈不容爾細。", "蜂有毒在尾，爾有毒在喙。", "畏爾衆口多，不比蜂一蠆。", "安得厲金商，掃蕩聊一快。"]'),
('fd5ea9c8-1ca2-4ed2-9ba6-62b7334e39a2','寄題江陵李潜道釣磯','周行己','宋','宋诗','song-poetry','','[]','嚴陵避世士，四海一釣磯。',108,'全唐诗/poet.song.71000.json','["嚴陵避世士，四海一釣磯。", "三聘非其心，獨采富春薇。", "蒙城有靜者，白首卧荆扉。", "築臺俯溪鳥，默玩道心微。", "箕踞謝官長，把竿忘是非。", "少年詞賦場，秉筆落珠璣。", "投老漫假板，長嘯却南歸。", "緬懷直鉤理，濯髮待日晞。", "貧賤得肆志，富貴多危機。"]'),
('5840dc35-874b-4420-9e66-31275c5b46d4','觀傅公濟胡志衡楚越唱和集因成短句奉贈','周行己','宋','宋诗','song-poetry','','[]','清露凝百草，四海黄葉秋。',192,'全唐诗/poet.song.71000.json','["清露凝百草，四海黄葉秋。", "遊子思故鄉，中夜攬衣裘。", "起坐不成寐，歎息銜百憂。", "久客豈其願，亦爲甘旨謀。", "平生少年日，睥睨氣食牛。", "秉志三皇前，展步狹九州。", "乃今已半百，尚有餓凍愁。", "生逢聖明代，不忍棄田疇。", "折節衆士底，足爲妻嫂羞。", "伯樂尚未遇，焉知非驊騮。", "觀其楚越集，迥覺出輩流。", "有如閱武庫，森然見戈矛。", "近者咸興作，無乃或暗投。", "五車空拄腹，一飽豈易求。", "不如臨洮子，匹馬萬戶侯。", "遇合各有時，莫笑東家丘。"]'),
('b0322704-f768-4f3f-a6a1-3c1f940bbcc3','復用前韵奉酬夢符學錄','周行己','宋','宋诗','song-poetry','','[]','子卿五言法，氣格厲勁秋。',192,'全唐诗/poet.song.71000.json','["子卿五言法，氣格厲勁秋。", "綿綿武功裔，尚不廢箕裘。", "洒然落妙語，一破萬古憂。", "文章本道德，作者通神謀。", "惜其命不達，白首猶飯牛。", "學者願識面，或比韓荆州。", "儒冠真誤身，未免妻子愁。", "長安游俠兒，生不辨田疇。", "儒有不黔突，此輩飫珍羞。", "左右夾燕趙，出入跨騏騮。", "富貴即稱賢，寧辨清濁流。", "乃知讀萬卷，不如持尺矛。", "斯言雖有激，亦爲智者投。", "古人願執鞭，如或不可求。", "君看授業生，已爲公與侯。", "颯然灌園翁，零落守舊丘。"]'),
('026fa481-bba3-49a7-82b0-82279e81909c','古意贈答段公度','周行己','宋','宋诗','song-poetry','','[]','野人比芹子，昔獻已負慚。',48,'全唐诗/poet.song.71000.json','["野人比芹子，昔獻已負慚。", "安得長者語，借譽苦爲甘。", "自愧敝帚姿，欲駕騧驪驂。", "寸進復尺退，虎穴詎得探。"]'),
('8860d5f9-78d2-42ea-80e3-946157f99fbe','寄題方氏賞心亭','周行己','宋','宋诗','song-poetry','','[]','日月欻不淹，萬物紛迴薄。',96,'全唐诗/poet.song.71000.json','["日月欻不淹，萬物紛迴薄。", "冬索復春敷，夏茂以秋落。", "彼來無窮期，詎可盡酬酢。", "人生聊爾耳，政應如解籜。", "可料百年身，胡爲自束縛。", "達人暢高情，物物各有樂。", "濁醪隨身置，心賞悟遠託。", "陶阮寓酒意，斯亭豈虛作。"]'),
('c488663f-3218-4fcd-8ce3-7ba3a9df5b41','送別','周行己','宋','宋诗','song-poetry','','[]','人生如斷蓬，萬里忽相值。',168,'全唐诗/poet.song.71000.json','["人生如斷蓬，萬里忽相值。", "會日常苦難，別日常苦易。", "十年聞子名，未識已心醉。", "我友豈不多，愛子好心地。", "身小胸膽大，面目無邪氣。", "磊磊棟梁姿，溫溫瑚璉器。", "人物衰落盡，百馬逢一驥。", "我懷未傾倒，離別已復至。", "天寒霜正繁，山險道不利。", "君行獨何爲，百里求自試。", "願持孝友資，發爲惻隠治。", "上馬且勿難，吾民竚嘉惠。", "他年廟堂上，舉此亦不異。", "强飯數寄書，待爾慰窮悴。"]'),
('44623cf3-abfd-4e93-836e-7e8ff9f59763','同舍劉子美將歸唐作詩見貽次韵以送其行','周行己','宋','宋诗','song-poetry','','[]','我學比棘猴，漫費三年刻。',108,'全唐诗/poet.song.71000.json','["我學比棘猴，漫費三年刻。", "技成無所用，奔走虛南北。", "儒生紛逐利，雅道日衰息。", "乃獨資章甫，取售裸人國。", "雖知自守重，豈若趨時得。", "念欲障狂瀾，亮非一簣力。", "吁嗟且置此，徒使氣填臆。", "與子共師友，焉得久默默。", "行行慎茲道，慰我日惻惻。"]'),
('bd54786e-6786-4c43-8634-6de406a65e6c','送友人東歸','周行己','宋','宋诗','song-poetry','','[]','是身如聚沫，如燭亦如風。',108,'全唐诗/poet.song.71000.json','["是身如聚沫，如燭亦如風。", "奔走天地內，苦爲萬慮攻。", "陳子得先覺，水鏡當胸中。", "異鄉各爲客，相看如秋鴻。", "扁舟忽歸去，宛然此道東。", "我亦議遠適，西入華與嵩。", "飲水有餘樂，避煩甘百窮。", "相逢不可欺，偶然如飄蓬。", "于道各努力，千里自同風。"]'),
('ab9cada6-9562-4a5e-b723-a44692254d8e','和郭守叔光絕境亭','周行己','宋','宋诗','song-poetry','','[]','雲橫絕塵境，峻堞若繩削。',60,'全唐诗/poet.song.71000.json','["雲橫絕塵境，峻堞若繩削。", "羣山列培塿，衆水分脈絡。", "下瞰萬瓦居，縹緲見樓閣。", "松風發天籟，泠然衆音作。", "皛皛天宇清，塵襟一澄廓。"]'),
('2af8e725-1d2f-4a4a-81a2-08a206f5b281','少年子','周行己','宋','宋诗','song-poetry','','[]','臨洮少年子，白馬黄金羈。',48,'全唐诗/poet.song.71000.json','["臨洮少年子，白馬黄金羈。", "醉向壚邊宿，小女倩縫衣。", "不惜千金贈，只惜少年時。", "當時不行樂，過時空自悲。"]'),
('f97c26e6-976f-41b2-a33a-9a2b7b6a4c2b','北山閣','周行己','宋','宋诗','song-poetry','','[]','北山有高閣，暇日聊登遊。',108,'全唐诗/poet.song.71000.json','["北山有高閣，暇日聊登遊。", "臨眺益慘愴，焉能寫我憂。", "軒軒皆嶄石，激激瞰溪流。", "野鳥時上下，白雲自沈浮。", "徙倚事窮覽，良時忽我遒。", "日匿西岡下，月出東嶺頭。", "寒烟沒樹杪，勁風夾山陬。", "十月客衣單，不可重遲留。", "緬望涇水濱，使我心悠悠。"]'),
('92b00344-0278-4783-87b6-07dd0de7ead5','九日登高有感','周行己','宋','宋诗','song-poetry','','[]','置酒臨重陽，舉觴忽不樂。',84,'全唐诗/poet.song.71000.json','["置酒臨重陽，舉觴忽不樂。", "憶昔登高日，親朋盛杯酌。", "人事經年異，物景但如昨。", "生別未會遇，死別已冥漠。", "吾生更飄蕩，四海無所著。", "黄花眼中見，翻令懷抱惡。", "莫覓四坐歡，節序正寥落。"]'),
('6f5d985c-401a-4263-b01a-12cf561c7406','征婦怨','周行己','宋','宋诗','song-poetry','','[]','嫁君苦太遲，別君苦太早。',284,'全唐诗/poet.song.71000.json','["嫁君苦太遲，別君苦太早。", "官行有程期，不得暫相保。", "妾有嫁時衣，金縷光葳蕤。", "送君即遠道，數日望君歸。", "君去竟何許，君歸竟何長。", "昔爲膠與漆，今爲參與商。", "朝看雲間雁，暮看水底魚。", "雁魚過幾許，何處寄君書。", "有食不下咽，有衣不被體。", "夜回九轉腸，日下千行淚。", "階前萱草長，奩內粉黛空。", "萱草不解憂，粉黛爲誰容。", "人生若朝露，顔色豈長好。", "况乃懷憂愁，憂愁復易老。", "及春不開花，結子待何時。", "君在須早歸，妾在長相思。", "妾不願君富貴，妾只願君賤貧。", "賤貧足相保，富貴多棄舊。", "妾不願君成功，妾只願君早歸。", "早歸及年少，功成妾已老。", "君去妾二八，容顔花莫如。", "肌白不著粉，色紅不施朱。", "即今君尚未酬勳，妾年二十已有餘。"]'),
('d0db0baa-4651-4036-9c3c-013eaf422d98','楊花','周行己','宋','宋诗','song-poetry','','[]','楊花初生時，出在楊樹枝。',128,'全唐诗/poet.song.71000.json','["楊花初生時，出在楊樹枝。", "春風一飄蕩，忽與枝柯離。", "去去辭本根，日月逝無期。", "欲南而反北，焉得定東西。", "忽然驚飆起，吹我雲間飛。", "春風無定度，却送下污泥。", "寄謝枝與葉，邂逅復何時。", "我願爲樹葉，復恐秋風吹我令黄萎。", "我願爲樹枝，復恐斧斤斫我爲椽榱。", "只願爲樹根，生死長相依。"]'),
('d4b88a12-6241-4e02-b68b-bfe4347abcfd','和子同觀音寺新居','周行己','宋','宋诗','song-poetry','','[]','太學士千數，濟濟多白袍。',216,'全唐诗/poet.song.71000.json','["太學士千數，濟濟多白袍。", "其中靡不有，令人愧遁逃。", "風俗且如此，焉能獨守高。", "詳擇乃其道，或得賢與豪。", "近復失段子，嗚呼命不遭。", "吾生得覬豁，誰能置圈牢。", "武或萬人敵，何用學六韜。", "文士亦齷齪，勞心徒忉忉。", "利害竟何許，相去九牛毛。", "脫略或吾事，青松隠藜蒿。", "麟鳳豈仰見，狐狸多叫號。", "如不卜清曠，樂此阮與陶。", "文思韓吏部，詩見杜工曹。", "揮麈談風月，中夜聲颾颾。", "往往移北山，不必反楚騷。", "吾道用無窮，所志各有操。", "或隠身幽討，或放迹遊遨。", "平生事已定，用心奚獨勞。"]'),
('93eade69-a28b-4cf5-930d-0ba6a3f06f54','送畢之進狀元二首  其一','周行己','宋','宋诗','song-poetry','','[]','春風不開花，吹雲翳白日。',132,'全唐诗/poet.song.71000.json','["春風不開花，吹雲翳白日。", "天寒食不足，江頭拾芋栗。", "我馬不敢驅，畏此霜霰密。", "君行當奈何，開帆轉飄忽。", "挽舟君且住，爲君一洗拂。", "今日此良會，他時未可必。", "我生鋤犁手，一飯願已畢。", "官曹雖强汝，今汝心若失。", "扁舟行亦歸，還我性曠逸。", "騎牛不騎馬，鼓腹吞溟渤。", "他年作霖雨，勿污我蓬蓽。"]'),
('6c9269a1-8500-4a20-a667-0ecce579d55b','送畢之進狀元二首  其二','周行己','宋','宋诗','song-poetry','','[]','畢髯奇男子，未識已心與。',156,'全唐诗/poet.song.71000.json','["畢髯奇男子，未識已心與。", "獻策進英殿，脫略獨豪舉。", "二年襄陽幕，歸舟峴山渚。", "同事三日留，時時作險語。", "隆準帝王孫，蕭然好風度。", "詩書百萬卷，胸中莽迴互。", "平生蘇惠州，氣概頗自許。", "人生艱難際，政可觀去處。", "二子經濟才，用之則爲虎。", "髯公且爲客，王孫且爲主。", "明朝各天涯，歌眉爲誰嫵。", "柁師挽舟去，回首空南浦。", "莫笑參軍强，參軍定强否。"]'),
('b2e6b4df-ce48-458d-a313-8abb86775d35','雨中有懷','周行己','宋','宋诗','song-poetry','','[]','世態紛戢戢，客愁亦不盡。',264,'全唐诗/poet.song.71000.json','["世態紛戢戢，客愁亦不盡。", "坐窗木榻穿，百慨逢一哂。", "觸眼敗人意，喜事日益泯。", "小暑三日熱，重我憂躁疢。", "崇朝一雨洗，意氣覺清緊。", "焚香强起坐，曲肱聽鳴蚓。", "出門復有觀，物色相蠢蝡。", "危芳墮簷牙，水螾上階楯。", "失勢蛛墜網，得時朽蒸菌。", "矜飛啄泥燕，戢翼翔雲隼。", "此理復誰論，中腸紛結縝。", "懷我平生好，意得如合吻。", "歐段屈薄宦，有如驥服靷。", "兖李困諸生，豪氣浮海蜃。", "華李本達識，磊落忘畦畛。", "忼慨任關西，開口見肝腎。", "高蹈潘逸士，未能趨縣尹。", "小王頗清修，對策如射埻。", "復有孫夫子，未許連車軫。", "聚散各異處，單車謝推引。", "言笑誰與歡，思逝如抽筍。", "作詩當晤言，爲我發大辴。"]'),
('3496427e-f6ce-4e3b-8da5-d5e41ca9aeec','奉酬天復古風','周行己','宋','宋诗','song-poetry','','[]','我生不愛言，欲言令人惡。',192,'全唐诗/poet.song.71000.json','["我生不愛言，欲言令人惡。", "總總乾坤內，抱此誰與託。", "昔者所親人，今或苦荼若。", "生交各分離，死交已冥漠。", "事非固必存，千載一轉脚。", "要知達士心，閱世等糟粕。", "不求萬法脫，不與萬法縛。", "索然天地中，去留如解籜。", "萬事豈足爲，而苦自結約。", "吾以此應世，方枘入圓鑿。", "何當得蔡侯，飄若雲中鶴。", "新詩近道要，如病飲良藥。", "上言古心人，次言時道薄。", "落落濟世志，拙者但駭愕。", "功名付吾子，我獨甘藜藿。", "誰知陋巷中，簞瓢有餘樂。"]'),
('90662222-4228-4b47-b727-7a33a0891ca2','五月二十五日晚自天壽還呈秦少章','周行己','宋','宋诗','song-poetry','','[]','客思日百種，無一適所願。',132,'全唐诗/poet.song.71000.json','["客思日百種，無一適所願。", "入夏對燈火，坐窗如坐圈。", "開口畏禍機，俛首學癡鈍。", "嘉友不在眼，相思劇方寸。", "晚凉策馬出，豁然對清論。", "盈月阻良覿，歡喜論繾綣。", "上言得三益，次言科舉困。", "新詩破煩想，覺人體中健。", "重我特特來，殷勤留一飯。", "促膝對夜樹，蕭爽無俗坌。", "歸來勞夢侵，令人欲高遯。"]'),
('f82475a4-15ed-4b75-bcfa-35d5d7b321aa','政和丁酉罷攝樂清寓柳市莊居和林惠叔見寄','周行己','宋','宋诗','song-poetry','','[]','懷祿非其心，事君要以道。',96,'全唐诗/poet.song.71000.json','["懷祿非其心，事君要以道。", "古來際遇間，每恨見不早。", "觀其風雲會，事業何草草。", "卓哉張子房，器博用殊少。", "恐量世主心，用此恰恰好。", "所以收其才，遠從赤松老。", "富貴非利達，貧賤非枯槁。", "超超聖賢心，吾欣願執掃。"]'),
('6ac59a34-6744-418c-916e-de93ff51ee6d','遷居有感示二三子','周行己','宋','宋诗','song-poetry','','[]','四時忽代序，靡靡無停息。',132,'全唐诗/poet.song.71000.json','["四時忽代序，靡靡無停息。", "白露應節降，凉颸變晨夕。", "閒居二十載，遷徙靡寧日。", "鳥鼠有巢穴，我居無定室。", "田園固所乏，婚嫁何當畢。", "貧賤難爲好，仁義寡所匹。", "總總百年內，萬事安可必。", "人生七十稀，我今五十一。", "齒髮已彫喪，肌肉乏腴實。", "固窮吾素分，苟得鮮終吉。", "餘年當幾何，任運非得失。"]'),
('36368e18-71d5-4aab-b754-ab1c94f39c3d','發東陽','周行己','宋','宋诗','song-poetry','','[]','客行無緩程，悲吟無緩聲。',48,'全唐诗/poet.song.71000.json','["客行無緩程，悲吟無緩聲。", "促促復促促，居家食不足。", "徘徊重徘徊，欲行還欲歸。", "近懷遠弗顧，强復驅車去。"]'),
('8976dba6-4f3c-4095-8c72-55e7508ce2ed','寄魯直學士','周行己','宋','宋诗','song-poetry','','[]','當今文伯眉陽蘇，新詞的皪垂明珠。',192,'全唐诗/poet.song.71000.json','["當今文伯眉陽蘇，新詞的皪垂明珠。", "我公江南獨繼步，名譽籍甚傳清都。", "達人嗜好與俗異，誰欲海邊逐臭夫。", "小生結髮讀書史，隠憫每願脫世儒。", "幾載俛首黌堂趨，爭唼粱藻從羣鳬。", "野人鼓瑟不解竽，悠悠舉目誰與娛。", "幸有達者黄與蘇，誰復跼蹐如轅駒。", "古來志士恥沈沒，參軍慷慨曳長裾。", "相知寧論貴賤敵，詩奏終使蘭艾殊。", "當時仲宣亦小弱，蔡公歎其才不如。", "乃知士子名未立，須藉顯達齒論餘。", "嬰兒失乳投母哺，當亦飲食瓊漿壺。"]'),
('2afe6d65-af43-4c0e-8d44-df31b8a7d5b8','次天峰居士韵奉寄','周行己','宋','宋诗','song-poetry','','[]','天峰靜者巢箕叟，著書不爲牛馬走。',240,'全唐诗/poet.song.71000.json','["天峰靜者巢箕叟，著書不爲牛馬走。", "夜雨題詩寄日邊，觀者辟易皆縮手。", "嗚呼大雅久不聞，吾道悠悠付林藪。", "伏龍鳳雛人未知，腴田猥大皆稂莠。", "將軍爲志窮益堅，魯儒雖死不更守。", "鷦鵬有翅須摶風，苦李當道誰開口。", "京師車馬十二門，一日萬億無不有。", "吞腥啄腐何卒卒，正坐誚言芷漸滫。", "可憐惠施多才卿，不悟據梧瞑低首。", "功名浩蕩悵何許，置身謀慮苦不久。", "盍似淵明歸去來，不作折腰求五斗。", "飽食大人如肉山，衮衮奔馳氣如吼。", "東山野人氣亦芒，郎將自昔今獨否。", "誰能脂韋化百鍊，世態欻如屈伸肘。", "何時尊酒話疇昔，擊節新詩意非苟。"]'),
('0a53463d-78de-4886-85df-90de3dc8bc93','泥雪憶志康公度元老','周行己','宋','宋诗','song-poetry','','[]','正月二日多雪寒，京師道路無日乾。',64,'全唐诗/poet.song.71000.json','["正月二日多雪寒，京師道路無日乾。", "巷南巷北一望隔，出門但見泥漫漫。", "歸來危坐官屋底，日飽太倉半升米。", "相思更覺行路難，蒙垢何當爲一洗。"]'),
('0cbab4d5-8271-4646-8f88-7b0c8395a92b','和任昌叔寄終南之什','周行己','宋','宋诗','song-poetry','','[]','少陵作者今卓爾，彭澤一觴意何已。',64,'全唐诗/poet.song.71000.json','["少陵作者今卓爾，彭澤一觴意何已。", "詩工酒逸覺有神，此理浪傳嗤俗子。", "却求舉選科目間，仰看有道當汗顔。", "聞君欲往更愁絕，歸心日夜急飛湍。"]'),
('1802f18f-f95a-4908-8235-10a488b9006f','送歐陽司理歸荆南','周行己','宋','宋诗','song-poetry','','[]','荆南秀氣有異才，我今見之歐陽子。',240,'全唐诗/poet.song.71000.json','["荆南秀氣有異才，我今見之歐陽子。", "長年讀書五車過，下筆神捷風雲起。", "一昨新書警末俗，儒衣喜好入骨髓。", "此君矯矯出輩流，一心本學妙達理。", "斯之自信謝黨與，萬口一律誰信爾。", "眼明却見法令新，四海文章盡蘇氏。", "馬羣一遇伯樂空，近拔其尤自君始。", "可憐平生萬艱苦，及壯一官歸故里。", "丈夫行道會有時，用心深處良獨知。", "眼中人才不易得，鳳翥龍驤非爾誰。", "野人一身日百謗，人笑阮癡端不癡。", "憶昔定交論心腹，示我青青千載期。", "茲事風流定不朽，謝爾紛紛輕薄兒。", "如此嘉會豈易得，端知聚散非人力。", "相期遠大莫相憶，要須身健且强食。"]'),
('4cd2503f-e335-4814-bb84-04a7ead97f66','次君陟見志韵','周行己','宋','宋诗','song-poetry','','[]','秋風颯颯吹寒雨，寒士畏寒不畏暑。',112,'全唐诗/poet.song.71000.json','["秋風颯颯吹寒雨，寒士畏寒不畏暑。", "杜陵四海無尺椽，頗思大屋連千礎。", "大庇天下寒士寒，小利猶能及雀鼠。", "平生志大不小用，未解從人問科舉。", "可憐時俗喜儇媚，此道悠悠付何所。", "不如歸來負寒日，食芹得味絕不去。", "人生何處無一飯，飽卧便便腹如鼓。"]'),
('fd91b428-d216-4b56-b4a9-9255a0ba3c3b','竹枝歌上姚毅夫  其一','周行己','宋','宋诗','song-poetry','','[]','秋月亭亭揚明輝，浮雲一點天上飛，欻忽回陰雨四垂。',40,'全唐诗/poet.song.71000.json','["秋月亭亭揚明輝，浮雲一點天上飛，欻忽回陰雨四垂。", "人生萬事亦爾爲，今不行樂待何時。"]'),
('d4e80524-2038-422d-8c27-68c6605b0a32','竹枝歌上姚毅夫  其二','周行己','宋','宋诗','song-poetry','','[]','翠幕留夜燈燭光，主人歡娛客滿堂，龍船盛酒蠡作觴。',40,'全唐诗/poet.song.71000.json','["翠幕留夜燈燭光，主人歡娛客滿堂，龍船盛酒蠡作觴。", "秦吹齊歌舞燕倡，夜如何其夜未央。"]'),
('09fd6e4e-a611-4d0b-90bf-dcc152c4510a','竹枝歌上姚毅夫  其三','周行己','宋','宋诗','song-poetry','','[]','佳人玉顔冰雪肌，寶髻繡裳光葳蕤，齊聲緩歌楊柳枝。',40,'全唐诗/poet.song.71000.json','["佳人玉顔冰雪肌，寶髻繡裳光葳蕤，齊聲緩歌楊柳枝。", "歌罷障面私自悲，坐客滿堂淚霑衣。"]'),
('f1ddca9f-b926-4fdc-b5b5-d6cf024efea7','竹枝歌上姚毅夫  其四','周行己','宋','宋诗','song-poetry','','[]','酒當毒藥色當斤，人生行樂如浮雲，一杯更盡客已醺。',40,'全唐诗/poet.song.71000.json','["酒當毒藥色當斤，人生行樂如浮雲，一杯更盡客已醺。", "美人不用歌文君，客有相如心不春。"]'),
('54e56321-6910-4eb0-a8d1-f135cd54c83f','竹枝歌上姚毅夫  其五','周行己','宋','宋诗','song-poetry','','[]','壺傾燭燼樂事衰，堂上歌聲有餘哀，主人謝客客已歸。',40,'全唐诗/poet.song.71000.json','["壺傾燭燼樂事衰，堂上歌聲有餘哀，主人謝客客已歸。", "風蕩重陰月還輝，皎皎千里光無虧。"]'),
('57be8d98-1e1e-4f91-b5d2-4aa3f6570a53','上元被差監酤妙覺書呈文叔二首  其一','周行己','宋','宋诗','song-poetry','','[]','密雪沾游幕，餘寒犯酒茵。',48,'全唐诗/poet.song.71000.json','["密雪沾游幕，餘寒犯酒茵。", "坐招羣客飲，愁是獨醒人。", "事業慚知己，衣冠媿此身。", "吾生自有分，休問紫姑神。"]'),
('62c261a5-85ea-488e-bfa4-e129c5dc1626','上元被差監酤妙覺書呈文叔二首  其二','周行己','宋','宋诗','song-poetry','','[]','竊祿知踰分，論才昧所長。',48,'全唐诗/poet.song.71000.json','["竊祿知踰分，論才昧所長。", "幸同操犢鼻，幾不試漁陽。", "醉客或遭詬，少年來索嘗。", "此吾稽古力，咄咄未須忙。"]'),
('36a0cd96-3f58-4e39-a7e0-c9eeb05b515b','走筆問訊晁四以道  其一','周行己','宋','宋诗','song-poetry','','[]','問訊晁夫子，成州去幾時。',48,'全唐诗/poet.song.71000.json','["問訊晁夫子，成州去幾時。", "衣冠空攘攘，鬢髮獨絲絲。", "器業終難合，行藏只自知。", "嵩山讀書處，還許寄晨炊。"]'),
('94ca1e4b-619b-4944-bf6d-125221ee09b0','走筆問訊晁四以道  其二','周行己','宋','宋诗','song-poetry','','[]','故鄉羣盜阻，不見一人來。',48,'全唐诗/poet.song.71000.json','["故鄉羣盜阻，不見一人來。", "免死依君祿，全生抵酒杯。", "衰年聊爾耳，吾道已焉哉。", "未遂鹿門去，相思日幾回。"]'),
('74235f9c-4675-4099-87ba-77673a25213e','寓居婁氏樓居','周行己','宋','宋诗','song-poetry','','[]','樓高雲隠戶，秋靜月侵幃。',48,'全唐诗/poet.song.71000.json','["樓高雲隠戶，秋靜月侵幃。", "曠宇涵天界，連山軸地機。", "宿鴉風葉亂，歸牧笛聲稀。", "身世浮雲外，人生何所依。"]'),
('c941b19e-e723-40fc-becb-574f71695730','遷居柳市有感  其一','周行己','宋','宋诗','song-poetry','','[]','緬懷彭澤令，從借剡溪居。',48,'全唐诗/poet.song.71000.json','["緬懷彭澤令，從借剡溪居。", "水漫衆流會，山連夜逕疏。", "閉關非避世，爲道久忘書。", "乍愜幽棲趣，永欣塵鞅除。"]'),
('cc8a46d8-3a12-447d-9675-22477d5c3fe5','遷居柳市有感  其二','周行己','宋','宋诗','song-poetry','','[]','羅含亦有宅，洲渚啟柴門。',48,'全唐诗/poet.song.71000.json','["羅含亦有宅，洲渚啟柴門。", "未足拒風色，猶堪隔世喧。", "卜居空著論，畢娶詎忘言。", "且折薛中券，相從籬下樽。"]'),
('2af25dfb-35d2-4404-bb72-f63849169732','卧病京師蒙少伊察院惠米因敘歸懷奉呈','周行己','宋','宋诗','song-poetry','','[]','卧病逾三伏，辭鄉已四年。',48,'全唐诗/poet.song.71000.json','["卧病逾三伏，辭鄉已四年。", "故人分祿米，鄰舍貸醫錢。", "志業其如命，行藏休問天。", "吾歸舟已具，老去合求田。"]'),
('e93b0d2c-376a-4392-98a2-35b8243084c0','再依前韵酬少伊','周行己','宋','宋诗','song-poetry','','[]','亦有南堤宅，棲遲可寄年。',48,'全唐诗/poet.song.71000.json','["亦有南堤宅，棲遲可寄年。", "免從依廡賃，賸得買鄰錢。", "爲道難逢世，知吾獨是天。", "小橋連里巷，行日話桑田。"]'),
('b81bd798-02ee-4ae1-ac7b-2747c65bea32','次少伊韵反招隠','周行己','宋','宋诗','song-poetry','','[]','我已逾衰齒，公猶小五年。',48,'全唐诗/poet.song.71000.json','["我已逾衰齒，公猶小五年。", "少時能作賦，平日不言錢。", "風采桓公雅，詩情白樂天。", "朝綱方有頼，未可話歸田。"]'),
('bba08a08-98f7-45b4-ad78-ae42c02ef3ba','少伊察院再用年字韵寵示二篇輒復酬和一章陳德一章敘情  其一','周行己','宋','宋诗','song-poetry','','[]','恂恂許御史，清譽自初年。',48,'全唐诗/poet.song.71000.json','["恂恂許御史，清譽自初年。", "門絕苞苴使，家惟薪菜錢。", "文章名蓋世，忠義力回天。", "不爲兒孫計，何須僻處田。"]'),
('0343ca19-cfa4-4545-a8de-21b8e1e0abe4','少伊察院再用年字韵寵示二篇輒復酬和一章陳德一章敘情  其二','周行己','宋','宋诗','song-poetry','','[]','咄咄休無頼，栖栖又一年。',48,'全唐诗/poet.song.71000.json','["咄咄休無頼，栖栖又一年。", "時從柱下史，獨貸薛中錢。", "多病惟須藥，長貧不怨天。", "歸期無遠道，猶滯稻粱田。"]'),
('77a37306-2cfb-448d-b0a7-d2beadf3ff2a','雨後晨出滎澤道中寄嘉仲明府','周行己','宋','宋诗','song-poetry','','[]','宿雨郊原潤，新晴禾黍香。',48,'全唐诗/poet.song.71000.json','["宿雨郊原潤，新晴禾黍香。", "天高晨氣靜，地闊野風凉。", "忽忽憂羣盜，悁悁懷故鄉。", "攝官聊免死，何敢論行藏。"]'),
('95ca0cc8-6127-4d14-8a4c-650343dba8f0','謝嘉仲相招寄居滎澤','周行己','宋','宋诗','song-poetry','','[]','已解陳蕃榻，仍留杜甫亭。',48,'全唐诗/poet.song.71000.json','["已解陳蕃榻，仍留杜甫亭。", "飽聞期月政，願受一廛氓。", "萬事尊中酒，餘年水上萍。", "依投知有地，流轉任浮生。"]'),
('1aadcaab-1ec2-4ca0-b659-3cf59276bb72','送李子興新第歸寧','周行己','宋','宋诗','song-poetry','','[]','新恩好驥子，門戶有輝光。',48,'全唐诗/poet.song.71000.json','["新恩好驥子，門戶有輝光。", "昏宦通三世，山川共一方。", "拜親今綠綬，傳業自青緗。", "買宅如來此，相從及早凉。"]'),
('d541d422-0888-44b0-b8b3-e3e167e842ad','寄題江南李氏四照亭','周行己','宋','宋诗','song-poetry','','[]','聞道新亭好，開軒四望虛。',48,'全唐诗/poet.song.71000.json','["聞道新亭好，開軒四望虛。", "葱葱佳氣合，衮衮衆山趣。", "野鳥來還去，浮雲卷却舒。", "登臨富幽興，應不羨陶朱。"]'),
('5e8e8f9e-361b-482a-8b0f-7765622e78e6','道中有感','周行己','宋','宋诗','song-poetry','','[]','皛皛平川靜，暉暉寒食曛。',48,'全唐诗/poet.song.71000.json','["皛皛平川靜，暉暉寒食曛。", "連山荒白草，屬地亂黄雲。", "歲晚關心事，天邊爲客身。", "扁舟終不惡，奔走失吾真。"]'),
('1ac20437-cdc5-4b4c-9544-52fca15c029e','次渠僅老韵四首  其一','周行己','宋','宋诗','song-poetry','','[]','癡拙時無用，歸來老罷休。',48,'全唐诗/poet.song.71000.json','["癡拙時無用，歸來老罷休。", "夜寒爲客夢，歲晚異鄉愁。", "鳥有南枝宿，川皆東海流。", "凭高望歸路，雲重失滄洲。"]'),
('32b752f0-fdaf-40d7-9817-a565c718bbde','次渠僅老韵四首  其二','周行己','宋','宋诗','song-poetry','','[]','世事人情了，年華鬢髮侵。',48,'全唐诗/poet.song.71000.json','["世事人情了，年華鬢髮侵。", "平生憂國淚，老去戀鄉心。", "四壁家千里，三秋書萬金。", "號寒小兒子，念汝故情深。"]'),
('077152eb-f37a-45cc-9eb8-e697ec18f364','次渠僅老韵四首  其三','周行己','宋','宋诗','song-poetry','','[]','鳥暮已歸宿，吾今行亦休。',48,'全唐诗/poet.song.71000.json','["鳥暮已歸宿，吾今行亦休。", "百年能幾許，萬事不勝愁。", "貧賤須行樂，功名可枕流。", "鱸魚秋興遠，風起白蘋洲。"]'),
('b6c3658e-f2a7-4986-b9c5-ba555c9c36c6','次渠僅老韵四首  其四','周行己','宋','宋诗','song-poetry','','[]','憂患功名晚，塵勞歲月侵。',48,'全唐诗/poet.song.71000.json','["憂患功名晚，塵勞歲月侵。", "愁來無與語，老去獨傷心。", "不復周公夢，寧須季子金。", "題詩憑遣興，情極恐言深。"]'),
('4b809ddb-3efa-4156-a358-9ff0191072c1','次李滎澤韵','周行己','宋','宋诗','song-poetry','','[]','已罷仍僑寓，雖貧强客羞。',48,'全唐诗/poet.song.71000.json','["已罷仍僑寓，雖貧强客羞。", "閒居非素隠，高卧得清秋。", "故國今何在，他鄉未免憂。", "爲儒生用拙，老去更宜休。"]'),
('b9a49d06-2ced-4072-b6c5-41bb78bbbdb0','宿大足寺','周行己','宋','宋诗','song-poetry','','[]','塵埃得古寺，突兀亂山中。',48,'全唐诗/poet.song.71000.json','["塵埃得古寺，突兀亂山中。", "疊徑僧居僻，懸崖鳥道通。", "塞雲常雨雪，山木自多風。", "萬事浮生外，心花發暮鐘。"]'),
('9e43cccd-6031-44a4-b255-2d0530ae5eb3','送左與言赴杭司錄','周行己','宋','宋诗','song-poetry','','[]','艱難惟義重，去住各愁深。',48,'全唐诗/poet.song.71000.json','["艱難惟義重，去住各愁深。", "喬木迷歸夢，孤帆伴客吟。", "相看憂國淚，獨立望鄉心。", "到日如無事，來書速寄音。"]');
